import React, { useState } from 'react';

interface ReportViewerModalProps {
    onClose: () => void;
    onPrint: () => void;
    onSubmit?: () => void;
    onSaveDraft?: () => void;
    isSubmitting?: boolean;
    children: React.ReactNode;
    title: string;
}

const ReportViewerModal: React.FC<ReportViewerModalProps> = ({ 
    onClose, 
    onPrint, 
    onSubmit, 
    onSaveDraft,
    isSubmitting, 
    children, 
    title 
}) => {
    const [isGenerating, setIsGenerating] = useState(false);
    const isPreviewMode = !!onSubmit; // If it has an onSubmit handler, it's a preview before submission

    const handleDownload = () => {
        if (isPreviewMode) return; // Guard clause

        setIsGenerating(true);
        const element = document.getElementById('printable-report-content');

        if (!element) {
            console.error("Report content not found");
            setIsGenerating(false);
            return;
        }

        const filename = `${title.replace(/[^a-zA-Z0-9]/g, '_')}_${new Date().toISOString().split('T')[0]}.pdf`;

        const opt = {
            margin: 0,
            filename: filename,
            image: { type: 'jpeg', quality: 0.98 },
            html2canvas: { scale: 2, useCORS: true, letterRendering: true, scrollY: 0 },
            jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
        };

        const html2pdf = (window as any).html2pdf;

        if (html2pdf) {
            html2pdf().set(opt).from(element).save().then(() => {
                setIsGenerating(false);
            }).catch((err: any) => {
                console.error("PDF Generation Error", err);
                setIsGenerating(false);
                alert("Failed to generate PDF. You can try the Print button.");
            });
        } else {
            onPrint();
            setIsGenerating(false);
        }
    };

    return (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-sm animate-fadeIn">
            <div className="bg-white w-full max-w-5xl h-[92vh] rounded-2xl shadow-2xl flex flex-col overflow-hidden">
                {/* Header Context Switcher */}
                <div className={`px-6 py-4 border-b flex justify-between items-center ${isPreviewMode ? 'bg-amber-50 border-amber-100' : 'bg-slate-50 border-slate-200'}`}>
                    <div className="flex items-center gap-3">
                        <div className={`p-2 rounded-lg ${isPreviewMode ? 'bg-amber-100 text-amber-700' : 'bg-slate-200 text-slate-700'}`}>
                            {isPreviewMode ? (
                                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z"></path></svg>
                            ) : (
                                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"></path></svg>
                            )}
                        </div>
                        <div>
                            <h3 className="text-sm font-bold text-slate-800 uppercase tracking-widest">{title}</h3>
                            <p className={`text-[10px] font-black uppercase tracking-widest ${isPreviewMode ? 'text-amber-600' : 'text-slate-400'}`}>
                                {isPreviewMode ? 'UNSUBMITTED PREVIEW' : 'OFFICIAL RECORD'}
                            </p>
                        </div>
                    </div>

                    <div className="flex items-center gap-2 sm:gap-3">
                        <button 
                            onClick={onClose}
                            className="px-4 py-2 text-xs font-bold text-slate-500 hover:text-slate-800 hover:bg-slate-100 rounded-lg transition-colors border border-transparent"
                        >
                            {isPreviewMode ? 'Cancel' : 'Close'}
                        </button>

                        {/* MODE: PREVIEW ACTIONS */}
                        {isPreviewMode ? (
                            <div className="flex gap-2">
                                {onSaveDraft && (
                                    <button 
                                        onClick={onSaveDraft}
                                        className="px-4 py-2 text-xs font-bold text-blue-700 bg-blue-50 border border-blue-200 rounded-lg hover:bg-blue-100 transition-all flex items-center gap-2"
                                    >
                                        <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 7H5a2 2 0 00-2 2v9a2 2 0 002 2h14a2 2 0 002-2V9a2 2 0 00-2-2h-3m-1 4l-3 3m0 0l-3-3m3 3V4"></path></svg>
                                        Draft
                                    </button>
                                )}
                                <button 
                                    onClick={onSubmit}
                                    disabled={isSubmitting}
                                    className={`px-5 py-2 text-xs font-black text-white rounded-lg shadow-lg flex items-center gap-2 transition-all active:scale-95 uppercase tracking-widest
                                        ${isSubmitting ? 'bg-indigo-400' : 'bg-indigo-600 hover:bg-indigo-700'}
                                    `}
                                >
                                    {isSubmitting ? (
                                        <svg className="animate-spin h-3.5 w-3.5 text-white" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                                    ) : (
                                        <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M5 13l4 4L19 7"></path></svg>
                                    )}
                                    Confirm & Submit
                                </button>
                            </div>
                        ) : (
                            /* MODE: HISTORICAL ACTIONS */
                            <div className="flex gap-2">
                                <button 
                                    onClick={onPrint}
                                    className="hidden sm:flex px-4 py-2 text-xs font-bold text-slate-700 bg-white border border-slate-300 rounded-lg hover:bg-slate-50 shadow-sm items-center gap-2"
                                >
                                     <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z"></path></svg>
                                     Print
                                </button>

                                <button 
                                    onClick={handleDownload}
                                    disabled={isGenerating}
                                    className={`px-4 py-2 text-xs font-bold text-white rounded-lg shadow-md flex items-center gap-2 transition-all active:scale-95
                                        ${isGenerating ? 'bg-slate-400' : 'bg-slate-800 hover:bg-black'}
                                    `}
                                >
                                    {isGenerating ? (
                                        <svg className="animate-spin w-3.5 h-3.5 text-white" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                                    ) : (
                                        <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"></path></svg>
                                    )}
                                    <span className="hidden md:inline">Download Report</span>
                                    <span className="md:hidden">PDF</span>
                                </button>
                            </div>
                        )}
                    </div>
                </div>

                {/* Content Area */}
                <div className="flex-1 overflow-auto bg-slate-100 p-4 sm:p-8 flex justify-center relative group/viewer">
                    {/* Watermark Overlay (Only in Preview) */}
                    {isPreviewMode && (
                        <div className="absolute inset-0 pointer-events-none flex items-center justify-center overflow-hidden z-20 opacity-[0.03]">
                            <div className="text-[20vw] font-black text-slate-900 border-y-[20px] border-slate-900 rotate-[-45deg] whitespace-nowrap select-none uppercase">
                                Preview • Draft • Preview • Draft
                            </div>
                        </div>
                    )}

                    <div className="origin-top transform scale-[0.85] md:scale-100 transition-transform duration-300">
                         <div 
                            id="printable-report-content" 
                            className="bg-white shadow-2xl min-h-[297mm] relative z-10"
                        >
                            {children}
                        </div>
                    </div>
                </div>

                {/* Mobile Guard Notice */}
                {isPreviewMode && (
                    <div className="bg-amber-100 text-amber-800 px-4 py-2 text-[10px] font-bold text-center uppercase tracking-widest border-t border-amber-200">
                        Record is temporary and not valid for compliance until submitted.
                    </div>
                )}
            </div>
        </div>
    );
};

export default ReportViewerModal;

import React, { useState, useEffect } from 'react';
import { INITIAL_DATA, InspectionData, User } from './types';
import { 
    SHEET_HEADERS, PETROLEUM_HEADERS, PETROLEUM_V2_HEADERS, ACID_HEADERS,
    INSPECTION_ITEMS, PETROLEUM_INSPECTION_ITEMS, PETROLEUM_V2_ITEMS, ACID_INSPECTION_ITEMS
} from './constants';

// Hooks
import { useAuth } from './hooks/useAuth';
import { useSettings } from './hooks/useSettings';
import { useNotifications } from './hooks/useNotifications';
import { useHistory } from './hooks/useHistory';
import { useOfflineSync } from './hooks/useOfflineSync';
import { useSubscription } from './hooks/useSubscription';

// UI Components
import Toast from './components/ui/Toast';
import ReportViewerModal from './components/ui/ReportViewerModal';
import SubmissionOverlay from './components/ui/SubmissionOverlay';
import ProfileModal from './components/ui/ProfileModal';
import NotificationCenter from './components/ui/NotificationCenter'; 
import UpgradeModal from './components/ui/UpgradeModal';
import InspectionStartModal from './components/ui/InspectionStartModal';
import SubscriptionAlert from './components/ui/SubscriptionAlert';
import MaintenanceOverlay from './components/ui/MaintenanceOverlay';
import RequestInspectionModal from './components/ui/RequestInspectionModal'; 
import OnboardingWizard from './components/ui/OnboardingWizard'; 
import SystemTour from './components/ui/SystemTour'; 
import InstallPwaPrompt from './components/ui/InstallPwaPrompt';

// Views
import LoginView from './views/LoginView';
import SettingsView from './views/SettingsView';
import GeneralDashboard from './views/GeneralDashboard';
import PetroleumDashboard from './views/PetroleumDashboard';
import PetroleumV2Dashboard from './views/PetroleumV2Dashboard';
import AcidDashboard from './views/AcidDashboard';
import UserManagementView from './views/UserManagementView';
import OverviewDashboard from './views/OverviewDashboard';
import InspectionFormView from './views/InspectionFormView';
import SupportView from './views/SupportView';
import MaintenanceView from './views/MaintenanceView';
import RequestTrackingView from './views/RequestTrackingView';

// Report Components
import PrintableGeneralReport from './components/reports/PrintableGeneralReport';
import PrintablePetroleumReport from './components/reports/PrintablePetroleumReport';
import PrintablePetroleumV2Report from './components/reports/PrintablePetroleumV2Report';
import PrintableAcidReport from './components/reports/PrintableAcidReport';

const App = () => {
  const { currentUser, setCurrentUser, handleLogin, handleLogout, sessionExpired, setSessionExpired } = useAuth();
  const { settings, setSettings, appScriptUrl, setAppScriptUrl, isSavingSettings, handleSaveSettings } = useSettings();
  const { subscription } = useSubscription(appScriptUrl, currentUser);

  const [activeModule, setActiveModule] = useState('overview'); 
  const [viewMode, setViewMode] = useState<'dashboard' | 'form'>('dashboard');
  const [isProfileModalOpen, setIsProfileModalOpen] = useState(false);
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error' | 'info' | 'warning'} | null>(null);
  const [isRequestModalOpen, setIsRequestModalOpen] = useState(false);
  const [showTour, setShowTour] = useState(false);

  const { historyList, isLoadingHistory, validationLists, stats, fetchHistory } = useHistory(appScriptUrl, activeModule, currentUser);

  const showToast = (message: string, type: 'success' | 'error' | 'info' | 'warning') => {
      setToast({ message, type });
      setTimeout(() => setToast(null), 4000);
  };

  useEffect(() => {
      if (sessionExpired === 'idle') showToast("Session expired due to inactivity.", 'warning');
      else if (sessionExpired === 'max_duration') showToast("Session limit reached. Log in again.", 'info');
      if (sessionExpired) setSessionExpired(null);
  }, [sessionExpired]);

  const { submissionStatus, setSubmissionStatus, isSyncing, addToQueue } = useOfflineSync(appScriptUrl, showToast, () => fetchHistory(true));
  const { notifications, handleMarkNotificationRead, handleDismissNotification, handleClearAllNotifications, handleGlobalAcknowledge } = useNotifications(appScriptUrl, currentUser, showToast);

  const [isReportModalOpen, setIsReportModalOpen] = useState(false);
  const [selectedReportData, setSelectedReportData] = useState<InspectionData | null>(null);
  const [formInitialData, setFormInitialData] = useState<InspectionData>(INITIAL_DATA);

  const isAdmin = currentUser?.role === 'Admin' || currentUser?.role === 'SuperAdmin';
  const isSuperAdmin = currentUser?.role === 'SuperAdmin';
  const showMaintenance = settings.maintenanceMode && currentUser && !isSuperAdmin;

  // CRITICAL: Handle auto-correction of unauthorized modules
  useEffect(() => {
    if (!currentUser) return;
    const restrictedModules = ['users', 'settings', 'maintenance'];
    if (restrictedModules.includes(activeModule) && !isAdmin) {
        setActiveModule('overview');
    }
  }, [activeModule, currentUser, isAdmin]);

  const startFreshInspection = (module: string, prefill?: Partial<InspectionData>) => {
      setFormInitialData({ ...INITIAL_DATA, timestamp: new Date().toISOString(), inspectedBy: currentUser?.name || '', ...prefill });
      setViewMode('form');
  };

  const handleExitForm = (savedData?: InspectionData) => setViewMode('dashboard');

  const handleGoogleSheetSubmit = async (formData: InspectionData) => {
    if (!appScriptUrl) {
        showToast("Server URL not configured", "error");
        return;
    }

    setSubmissionStatus('submitting');

    let sheetName = 'General';
    let headers = SHEET_HEADERS;
    let moduleTitle = "General Vehicle Inspection";
    let activeItems = INSPECTION_ITEMS;

    if (activeModule === 'petroleum') { 
        sheetName = 'Petroleum'; 
        headers = PETROLEUM_HEADERS; 
        moduleTitle = "Petroleum Tanker Inspection";
        activeItems = PETROLEUM_INSPECTION_ITEMS;
    }
    else if (activeModule === 'petroleum_v2') { 
        sheetName = 'Petroleum_V2'; 
        headers = PETROLEUM_V2_HEADERS; 
        moduleTitle = "Petroleum Tanker Inspection V2";
        activeItems = PETROLEUM_V2_ITEMS;
    }
    else if (activeModule === 'acid') { 
        sheetName = 'Acid'; 
        headers = ACID_HEADERS; 
        moduleTitle = "Acid Tanker Inspection";
        activeItems = ACID_INSPECTION_ITEMS;
    }

    const row = headers.map(h => formData[h] !== undefined ? formData[h] : "");

    const reportData = {
        title: moduleTitle,
        timestamp: formData.timestamp,
        truckNo: formData.truckNo,
        trailerNo: formData.trailerNo,
        jobCard: formData.jobCard,
        location: formData.location,
        odometer: formData.odometer,
        inspectedBy: formData.inspectedBy,
        driverName: formData.driverName,
        remarks: formData.remarks,
        rate: formData.rate,
        signatures: {
            inspector: formData.inspectorSignature,
            driver: formData.driverSignature
        },
        photos: {
            front: formData.photoFront,
            ls: formData.photoLS,
            rs: formData.photoRS,
            back: formData.photoBack,
            damage: formData.photoDamage
        },
        items: activeItems.map(item => ({
            label: item.label,
            category: item.category,
            status: formData[item.id] || 'N/A'
        })),
        companyName: settings.companyName,
        companyLogo: settings.companyLogo
    };

    const payload = {
        action: 'create',
        sheet: sheetName,
        headers: headers,
        row: row,
        requestId: formData.requestId || null,
        reportData: reportData 
    };

    if (!navigator.onLine) {
        addToQueue(payload);
        setSubmissionStatus('offline_saved');
        setTimeout(() => {
            setSubmissionStatus('idle');
            setViewMode('dashboard');
        }, 3500);
        return;
    }

    try {
        await fetch(appScriptUrl, {
            method: 'POST',
            body: JSON.stringify(payload),
            mode: 'no-cors' 
        });

        setSubmissionStatus('success');
        fetchHistory(true); 

        setTimeout(() => {
            setSubmissionStatus('idle');
            setViewMode('dashboard');
        }, 3000);

    } catch (error) {
        console.error("Submission error", error);
        addToQueue(payload);
        setSubmissionStatus('offline_saved');
        setTimeout(() => {
            setSubmissionStatus('idle');
            setViewMode('dashboard');
        }, 3500);
    }
  };

  const handleRequestSubmit = async (data: any) => {
      if (!appScriptUrl) return;
      try {
          await fetch(appScriptUrl, {
              method: 'POST',
              body: JSON.stringify({
                  action: 'request_inspection',
                  requester: currentUser?.name,
                  role: currentUser?.role,
                  ...data
              }),
              mode: 'no-cors'
          });
          showToast("Inspection Request submitted successfully", "success");
      } catch (e) {
          showToast("Failed to submit request", "error");
      }
  };

  const handleViewReport = (item: InspectionData | null) => {
    setSelectedReportData(item);
    setIsReportModalOpen(true);
  };

  const handleNavigate = (module: string) => {
    if (module === 'request_inspection') {
        setIsRequestModalOpen(true);
    } else {
        setActiveModule(module);
        setViewMode('dashboard');
    }
  };

  const handleOnboardingComplete = (updatedUser: User) => {
      const userWithSetup = { ...updatedUser, needsSetup: false };
      setCurrentUser(userWithSetup);
      localStorage.setItem('safetyCheck_user', JSON.stringify(userWithSetup));

      // CRITICAL FIX: Ensure user lands on dashboard, not restricted management screens
      setActiveModule('overview');
      setViewMode('dashboard');

      showToast("Profile identity synchronized.", "success");
      setShowTour(true);
  };

  const isAtRoot = activeModule === 'overview';

  if (!currentUser) {
      return (
          <>
            <InstallPwaPrompt />
            {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
            <LoginView 
                onLogin={handleLogin} 
                appScriptUrl={appScriptUrl}
                setAppScriptUrl={setAppScriptUrl}
                settings={settings}
            />
          </>
      );
  }

  if (currentUser && (currentUser as any).needsSetup) {
      return (
          <OnboardingWizard 
            user={currentUser} 
            appScriptUrl={appScriptUrl} 
            onComplete={handleOnboardingComplete} 
          />
      );
  }

  if (showMaintenance) {
      return (
        <>
           <MaintenanceOverlay isActive={true} message={settings.maintenanceMessage || ''} onLogout={() => handleLogout()} />
           {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
        </>
      );
  }

  // Determine if we are in "Preview Mode" (No ID yet means it's a draft/live-form view)
  const isDraftViewing = selectedReportData && !selectedReportData.id;

  return (
    <div className="min-h-screen bg-white font-sans text-gray-900 relative">
      <SubmissionOverlay status={submissionStatus} />
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      {showTour && <SystemTour onComplete={() => setShowTour(false)} />}

      {isProfileModalOpen && (
          <ProfileModal 
            user={currentUser} 
            settings={settings}
            appScriptUrl={appScriptUrl} 
            onClose={() => setIsProfileModalOpen(false)} 
            showToast={showToast} 
            onUpdateSuccess={(u) => setCurrentUser(u)} 
            onLogout={() => { setIsProfileModalOpen(false); handleLogout(); }}
          />
      )}

      <RequestInspectionModal
          isOpen={isRequestModalOpen}
          onClose={() => setIsRequestModalOpen(false)}
          onSubmit={handleRequestSubmit}
          validationLists={validationLists}
          currentUserRole={currentUser.role}
      />

      <div className="relative z-10 min-h-screen flex flex-col">
          <SubscriptionAlert subscription={subscription} user={currentUser} onManage={() => setActiveModule('settings')} />

          <header className="bg-white border-b border-gray-100 sticky top-0 z-40 px-4 py-2 flex items-center justify-between h-14">
              <div className="flex items-center gap-1 sm:gap-2">
                  {!isAtRoot ? (
                      <button 
                          onClick={() => { setActiveModule('overview'); setViewMode('dashboard'); }}
                          title="Back to Overview"
                          className="p-2 text-slate-900 hover:bg-slate-50 rounded-lg transition-all flex items-center group"
                      >
                          <svg className="w-5 h-5 transition-transform group-hover:-translate-x-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M15 19l-7-7 7-7"></path></svg>
                          <span className="text-[10px] font-semibold uppercase tracking-widest ml-1 hidden sm:inline">Back</span>
                      </button>
                  ) : (
                      <div className="w-10"></div>
                  )}
              </div>

              <button 
                  onClick={() => { setActiveModule('overview'); setViewMode('dashboard'); }}
                  className="flex flex-col items-center hover:opacity-70 transition-opacity"
              >
                  <h1 className="text-lg font-bold text-slate-900 tracking-tight leading-none uppercase">
                      {settings.companyName || 'Alistair Group'}
                  </h1>
                  <span className="text-[7px] font-medium text-slate-400 tracking-[0.3em] mt-1 uppercase">Fleet Portal</span>
              </button>

              <div className="flex items-center gap-1">
                  <NotificationCenter 
                      id="notification-bell"
                      notifications={notifications}
                      onMarkAsRead={(id) => handleMarkNotificationRead(id)}
                      onDismiss={handleDismissNotification}
                      onClearAll={handleClearAllNotifications}
                      onAcknowledge={handleGlobalAcknowledge}
                      canAcknowledge={isAdmin}
                  />
                  <button 
                      onClick={() => setIsProfileModalOpen(true)} 
                      className={`p-2 transition-colors ${isProfileModalOpen ? 'text-slate-900 bg-slate-50 rounded-full' : 'text-slate-400 hover:text-slate-600'}`}
                  >
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z"></path></svg>
                  </button>
              </div>
          </header>

          <main className="flex-1 p-4 md:p-8 w-full max-w-7xl mx-auto">
              {viewMode === 'form' ? (
                  <InspectionFormView 
                      initialData={formInitialData}
                      activeModule={activeModule}
                      validationLists={validationLists}
                      settings={settings}
                      onSaveDraft={handleExitForm} 
                      onExit={() => setViewMode('dashboard')} 
                      onSubmit={handleGoogleSheetSubmit}
                      submissionStatus={submissionStatus}
                      onViewReport={handleViewReport}
                  />
              ) : (
                  <div className="animate-fadeIn">
                      {activeModule === 'overview' && (
                          <OverviewDashboard 
                              appScriptUrl={appScriptUrl} 
                              onNavigate={handleNavigate} 
                              userRole={currentUser.role}
                              historyList={historyList}
                              isLoading={isLoadingHistory}
                              onViewReport={handleViewReport}
                              isMaintenanceActive={settings.maintenanceMode}
                              pendingAlertsCount={notifications.filter(n => !n.read && n.type === 'critical').length}
                          />
                      )}
                      {(activeModule === 'settings' && isAdmin) && <SettingsView settings={settings} setSettings={setSettings} appScriptUrl={appScriptUrl} setAppScriptUrl={setAppScriptUrl} handleSaveSettings={handleSaveSettings} isSavingSettings={isSavingSettings} showToast={showToast} user={currentUser} />}
                      {(activeModule === 'maintenance' && isSuperAdmin) && <MaintenanceView user={currentUser} appScriptUrl={appScriptUrl} settings={settings} onSettingsUpdate={(s) => setSettings(p => ({...p, ...s}))} showToast={showToast} />}
                      {activeModule === 'general' && <GeneralDashboard userRole={currentUser.role} stats={stats} startNewInspection={() => startFreshInspection('general')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} />}
                      {activeModule === 'petroleum' && <PetroleumDashboard userRole={currentUser.role} stats={stats} startNewInspection={() => startFreshInspection('petroleum')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} />}
                      {activeModule === 'petroleum_v2' && <PetroleumV2Dashboard userRole={currentUser.role} stats={stats} startNewInspection={() => startFreshInspection('petroleum_v2')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} />}
                      {activeModule === 'acid' && <AcidDashboard userRole={currentUser.role} stats={stats} startNewInspection={() => startFreshInspection('acid')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} />}
                      {(activeModule === 'users' && isAdmin) && <UserManagementView currentUser={currentUser} appScriptUrl={appScriptUrl} showToast={showToast} validationLists={validationLists} settings={settings} />}
                      {activeModule === 'support' && <SupportView appScriptUrl={appScriptUrl} currentUser={currentUser} showToast={showToast} settings={settings} validationLists={validationLists} />}
                      {activeModule === 'track_requests' && <RequestTrackingView appScriptUrl={appScriptUrl} currentUser={currentUser} showToast={showToast} onRequestNew={() => setIsRequestModalOpen(true)} />}
                  </div>
              )}
          </main>

          <footer className="mt-auto py-6 border-t border-slate-50 text-center">
              <span className="text-[9px] font-medium text-slate-300 uppercase tracking-[0.2em]">scbc@2026</span>
          </footer>
      </div>

      {isReportModalOpen && selectedReportData && (
          <ReportViewerModal 
            onClose={() => setIsReportModalOpen(false)} 
            onPrint={() => window.print()}
            onSubmit={isDraftViewing ? () => { setIsReportModalOpen(false); handleGoogleSheetSubmit(selectedReportData); } : undefined}
            onSaveDraft={isDraftViewing ? () => { setIsReportModalOpen(false); handleExitForm(selectedReportData); } : undefined}
            isSubmitting={submissionStatus === 'submitting'}
            title={`Report_${selectedReportData.id || 'Draft'}`}
          >
              {activeModule === 'petroleum' ? (
                  <PrintablePetroleumReport data={selectedReportData} settings={settings} />
              ) : activeModule === 'petroleum_v2' ? (
                  <PrintablePetroleumV2Report data={selectedReportData} settings={settings} />
              ) : activeModule === 'acid' ? (
                  <PrintableAcidReport data={selectedReportData} settings={settings} />
              ) : (
                  <PrintableGeneralReport data={selectedReportData} settings={settings} />
              )}
          </ReportViewerModal>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';

interface ReportViewerModalProps {
    onClose: () => void;
    onPrint: () => void;
    onSubmit?: () => void;
    onSaveDraft?: () => void;
    isSubmitting?: boolean;
    children: React.ReactNode;
    title: string;
}

const ReportViewerModal: React.FC<ReportViewerModalProps> = ({ 
    onClose, 
    onPrint, 
    onSubmit, 
    onSaveDraft,
    isSubmitting, 
    children, 
    title 
}) => {
    const [isGenerating, setIsGenerating] = useState(false);
    const isPreviewMode = !!onSubmit; // Determined by presence of submission handler

    const handleDownload = () => {
        if (isPreviewMode) return;

        setIsGenerating(true);
        const element = document.getElementById('printable-report-content');

        if (!element) {
            console.error("Report content not found");
            setIsGenerating(false);
            return;
        }

        const filename = `${title.replace(/[^a-zA-Z0-9]/g, '_')}_${new Date().toISOString().split('T')[0]}.pdf`;

        const opt = {
            margin: 0,
            filename: filename,
            image: { type: 'jpeg', quality: 0.98 },
            html2canvas: { scale: 2, useCORS: true, letterRendering: true, scrollY: 0 },
            jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
        };

        const html2pdf = (window as any).html2pdf;

        if (html2pdf) {
            html2pdf().set(opt).from(element).save().then(() => {
                setIsGenerating(false);
            }).catch((err: any) => {
                console.error("PDF Generation Error", err);
                setIsGenerating(false);
                alert("Failed to generate PDF. You can use the Print button as a fallback.");
            });
        } else {
            onPrint();
            setIsGenerating(false);
        }
    };

    return (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/90 backdrop-blur-md animate-fadeIn no-print">
            <div className="bg-white w-full max-w-5xl h-[94vh] rounded-3xl shadow-2xl flex flex-col overflow-hidden border border-white/20">
                {/* Modal Header */}
                <div className={`px-6 py-4 border-b flex justify-between items-center ${isPreviewMode ? 'bg-amber-50 border-amber-100' : 'bg-slate-50 border-slate-200'}`}>
                    <div className="flex items-center gap-4">
                        <div className={`p-2.5 rounded-xl ${isPreviewMode ? 'bg-amber-100 text-amber-600' : 'bg-slate-200 text-slate-600'}`}>
                            {isPreviewMode ? (
                                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /><path d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" /></svg>
                            ) : (
                                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                            )}
                        </div>
                        <div>
                            <h3 className="text-sm font-bold text-slate-800 uppercase tracking-widest leading-none">{title}</h3>
                            <p className={`text-[10px] font-bold uppercase tracking-[0.2em] mt-1.5 ${isPreviewMode ? 'text-amber-600' : 'text-slate-400'}`}>
                                {isPreviewMode ? 'Pre-Submission Review' : 'Verified Database Record'}
                            </p>
                        </div>
                    </div>

                    <div className="flex items-center gap-2">
                        <button 
                            onClick={onClose}
                            className="px-4 py-2 text-xs font-bold text-slate-500 hover:text-slate-800 hover:bg-slate-100 rounded-lg transition-colors mr-2"
                        >
                            {isPreviewMode ? 'Cancel' : 'Close'}
                        </button>

                        {/* MODE SPECIFIC ACTIONS */}
                        {isPreviewMode ? (
                            <div className="flex gap-2">
                                {onSaveDraft && (
                                    <button 
                                        onClick={onSaveDraft}
                                        className="px-4 py-2 text-xs font-bold text-blue-700 bg-blue-50 border border-blue-100 rounded-xl hover:bg-blue-100 transition-all flex items-center gap-2"
                                    >
                                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path d="M8 7H5a2 2 0 00-2 2v9a2 2 0 002 2h14a2 2 0 002-2V9a2 2 0 00-2-2h-3m-1 4l-3 3m0 0l-3-3m3 3V4" /></svg>
                                        Draft
                                    </button>
                                )}
                                <button 
                                    onClick={onSubmit}
                                    disabled={isSubmitting}
                                    className={`px-6 py-2 text-xs font-bold text-white rounded-xl shadow-lg flex items-center gap-2 transition-all active:scale-95 uppercase tracking-widest
                                        ${isSubmitting ? 'bg-indigo-400 cursor-wait' : 'bg-indigo-600 hover:bg-indigo-700'}
                                    `}
                                >
                                    {isSubmitting ? (
                                        <svg className="animate-spin h-4 w-4 text-white" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                                    ) : (
                                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M5 13l4 4L19 7" /></svg>
                                    )}
                                    Submit Final
                                </button>
                            </div>
                        ) : (
                            <div className="flex gap-2">
                                <button 
                                    onClick={onPrint}
                                    className="hidden sm:flex px-4 py-2 text-xs font-bold text-slate-700 bg-white border border-slate-200 rounded-xl hover:bg-slate-50 transition-all items-center gap-2"
                                >
                                     <svg className="w-4 h-4 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z" /></svg>
                                     Print
                                </button>

                                <button 
                                    onClick={handleDownload}
                                    disabled={isGenerating}
                                    className={`px-5 py-2 text-xs font-bold text-white rounded-xl shadow-lg flex items-center gap-2 transition-all active:scale-95
                                        ${isGenerating ? 'bg-slate-400' : 'bg-slate-900 hover:bg-black'}
                                    `}
                                >
                                    {isGenerating ? (
                                        <svg className="animate-spin w-4 h-4 text-white" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                                    ) : (
                                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                                    )}
                                    <span className="hidden md:inline">Download PDF</span>
                                    <span className="md:hidden">PDF</span>
                                </button>
                            </div>
                        )}
                    </div>
                </div>

                {/* Content Viewer Area */}
                <div className="flex-1 overflow-auto bg-slate-100 p-4 sm:p-10 flex justify-center relative">
                    {/* Visual Disclaimer (Only in Preview) */}
                    {isPreviewMode && (
                        <div className="absolute inset-0 pointer-events-none flex items-center justify-center overflow-hidden z-20 opacity-[0.04] select-none">
                            <div className="text-[18vw] font-black text-slate-900 border-y-[15px] border-slate-900 rotate-[-35deg] whitespace-nowrap uppercase tracking-tighter">
                                Preview Mode Only • Unsubmitted
                            </div>
                        </div>
                    )}

                    <div className="origin-top transform scale-[0.9] lg:scale-100 transition-transform duration-500">
                         <div 
                            id="printable-report-content" 
                            className="bg-white shadow-2xl min-h-[297mm] relative z-10 w-[210mm] print:shadow-none"
                        >
                            {children}
                        </div>
                    </div>
                </div>

                {/* Footer Disclaimer (Only in Preview) */}
                {isPreviewMode && (
                    <div className="bg-amber-100/80 backdrop-blur-sm text-amber-900 px-6 py-2.5 text-[9px] font-bold text-center uppercase tracking-[0.25em] border-t border-amber-200">
                        Notice: This document is a temporary preview and carries no legal or operational validity until submitted.
                    </div>
                )}
            </div>
        </div>
    );
};

export default ReportViewerModal;

import React, { useState, useEffect } from 'react';
import { INITIAL_DATA, InspectionData, User } from './types';
import { 
    SHEET_HEADERS, PETROLEUM_HEADERS, PETROLEUM_V2_HEADERS, ACID_HEADERS,
    INSPECTION_ITEMS, PETROLEUM_INSPECTION_ITEMS, PETROLEUM_V2_ITEMS, ACID_INSPECTION_ITEMS
} from './constants';

// Hooks
import { useAuth } from './hooks/useAuth';
import { useSettings } from './hooks/useSettings';
import { useNotifications } from './hooks/useNotifications';
import { useHistory } from './hooks/useHistory';
import { useOfflineSync } from './hooks/useOfflineSync';
import { useSubscription } from './hooks/useSubscription';

// UI Components
import Toast from './components/ui/Toast';
import ReportViewerModal from './components/ui/ReportViewerModal';
import SubmissionOverlay from './components/ui/SubmissionOverlay';
import ProfileModal from './components/ui/ProfileModal';
import NotificationCenter from './components/ui/NotificationCenter'; 
import UpgradeModal from './components/ui/UpgradeModal';
import InspectionStartModal from './components/ui/InspectionStartModal';
import SubscriptionAlert from './components/ui/SubscriptionAlert';
import MaintenanceOverlay from './components/ui/MaintenanceOverlay';
import RequestInspectionModal from './components/ui/RequestInspectionModal'; 
import OnboardingWizard from './components/ui/OnboardingWizard'; 
import SystemTour from './components/ui/SystemTour'; 
import InstallPwaPrompt from './components/ui/InstallPwaPrompt';

// Views
import LoginView from './views/LoginView';
import SettingsView from './views/SettingsView';
import GeneralDashboard from './views/GeneralDashboard';
import PetroleumDashboard from './views/PetroleumDashboard';
import PetroleumV2Dashboard from './views/PetroleumV2Dashboard';
import AcidDashboard from './views/AcidDashboard';
import UserManagementView from './views/UserManagementView';
import OverviewDashboard from './views/OverviewDashboard';
import InspectionFormView from './views/InspectionFormView';
import SupportView from './views/SupportView';
import MaintenanceView from './views/MaintenanceView';
import RequestTrackingView from './views/RequestTrackingView';

// Report Components
import PrintableGeneralReport from './components/reports/PrintableGeneralReport';
import PrintablePetroleumReport from './components/reports/PrintablePetroleumReport';
import PrintablePetroleumV2Report from './components/reports/PrintablePetroleumV2Report';
import PrintableAcidReport from './components/reports/PrintableAcidReport';

const App = () => {
  const { currentUser, setCurrentUser, handleLogin, handleLogout, sessionExpired, setSessionExpired } = useAuth();
  const { settings, setSettings, appScriptUrl, setAppScriptUrl, isSavingSettings, handleSaveSettings } = useSettings();
  const { subscription } = useSubscription(appScriptUrl, currentUser);

  const [activeModule, setActiveModule] = useState('overview'); 
  const [viewMode, setViewMode] = useState<'dashboard' | 'form'>('dashboard');
  const [isProfileModalOpen, setIsProfileModalOpen] = useState(false);
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error' | 'info' | 'warning'} | null>(null);
  const [isRequestModalOpen, setIsRequestModalOpen] = useState(false);
  const [showTour, setShowTour] = useState(false);

  const { historyList, isLoadingHistory, validationLists, stats, fetchHistory } = useHistory(appScriptUrl, activeModule, currentUser);

  const showToast = (message: string, type: 'success' | 'error' | 'info' | 'warning') => {
      setToast({ message, type });
      setTimeout(() => setToast(null), 4000);
  };

  useEffect(() => {
      if (sessionExpired === 'idle') showToast("Session expired due to inactivity.", 'warning');
      else if (sessionExpired === 'max_duration') showToast("Session limit reached. Log in again.", 'info');
      if (sessionExpired) setSessionExpired(null);
  }, [sessionExpired]);

  const { submissionStatus, setSubmissionStatus, isSyncing, addToQueue } = useOfflineSync(appScriptUrl, showToast, () => fetchHistory(true));
  const { notifications, handleMarkNotificationRead, handleDismissNotification, handleClearAllNotifications, handleGlobalAcknowledge } = useNotifications(appScriptUrl, currentUser, showToast);

  const [isReportModalOpen, setIsReportModalOpen] = useState(false);
  const [selectedReportData, setSelectedReportData] = useState<InspectionData | null>(null);
  const [formInitialData, setFormInitialData] = useState<InspectionData>(INITIAL_DATA);

  const isAdmin = currentUser?.role === 'Admin' || currentUser?.role === 'SuperAdmin';
  const isSuperAdmin = currentUser?.role === 'SuperAdmin';
  const showMaintenance = settings.maintenanceMode && currentUser && !isSuperAdmin;

  // Security guard for admin routes
  useEffect(() => {
    if (!currentUser) return;
    const restrictedModules = ['users', 'settings', 'maintenance'];
    if (restrictedModules.includes(activeModule) && !isAdmin) {
        setActiveModule('overview');
    }
  }, [activeModule, currentUser, isAdmin]);

  const startFreshInspection = (module: string, prefill?: Partial<InspectionData>) => {
      setFormInitialData({ ...INITIAL_DATA, timestamp: new Date().toISOString(), inspectedBy: currentUser?.name || '', ...prefill });
      setViewMode('form');
  };

  const handleExitForm = (savedData?: InspectionData) => setViewMode('dashboard');

  const handleGoogleSheetSubmit = async (formData: InspectionData) => {
    if (!appScriptUrl) {
        showToast("Server URL not configured", "error");
        return;
    }

    setSubmissionStatus('submitting');

    let sheetName = 'General';
    let headers = SHEET_HEADERS;
    let moduleTitle = "General Vehicle Inspection";
    let activeItems = INSPECTION_ITEMS;

    if (activeModule === 'petroleum') { 
        sheetName = 'Petroleum'; 
        headers = PETROLEUM_HEADERS; 
        moduleTitle = "Petroleum Tanker Inspection";
        activeItems = PETROLEUM_INSPECTION_ITEMS;
    }
    else if (activeModule === 'petroleum_v2') { 
        sheetName = 'Petroleum_V2'; 
        headers = PETROLEUM_V2_HEADERS; 
        moduleTitle = "Petroleum Tanker Inspection V2";
        activeItems = PETROLEUM_V2_ITEMS;
    }
    else if (activeModule === 'acid') { 
        sheetName = 'Acid'; 
        headers = ACID_HEADERS; 
        moduleTitle = "Acid Tanker Inspection";
        activeItems = ACID_INSPECTION_ITEMS;
    }

    const row = headers.map(h => formData[h] !== undefined ? formData[h] : "");

    const reportData = {
        title: moduleTitle,
        timestamp: formData.timestamp,
        truckNo: formData.truckNo,
        trailerNo: formData.trailerNo,
        jobCard: formData.jobCard,
        location: formData.location,
        odometer: formData.odometer,
        inspectedBy: formData.inspectedBy,
        driverName: formData.driverName,
        remarks: formData.remarks,
        rate: formData.rate,
        signatures: {
            inspector: formData.inspectorSignature,
            driver: formData.driverSignature
        },
        photos: {
            front: formData.photoFront,
            ls: formData.photoLS,
            rs: formData.photoRS,
            back: formData.photoBack,
            damage: formData.photoDamage
        },
        items: activeItems.map(item => ({
            label: item.label,
            category: item.category,
            status: formData[item.id] || 'N/A'
        })),
        companyName: settings.companyName,
        companyLogo: settings.companyLogo
    };

    const payload = {
        action: 'create',
        sheet: sheetName,
        headers: headers,
        row: row,
        requestId: formData.requestId || null,
        reportData: reportData 
    };

    if (!navigator.onLine) {
        addToQueue(payload);
        setSubmissionStatus('offline_saved');
        setTimeout(() => {
            setSubmissionStatus('idle');
            setViewMode('dashboard');
        }, 3500);
        return;
    }

    try {
        await fetch(appScriptUrl, {
            method: 'POST',
            body: JSON.stringify(payload),
            mode: 'no-cors' 
        });

        setSubmissionStatus('success');
        fetchHistory(true); 

        setTimeout(() => {
            setSubmissionStatus('idle');
            setViewMode('dashboard');
        }, 3000);

    } catch (error) {
        console.error("Submission error", error);
        addToQueue(payload);
        setSubmissionStatus('offline_saved');
        setTimeout(() => {
            setSubmissionStatus('idle');
            setViewMode('dashboard');
        }, 3500);
    }
  };

  const handleRequestSubmit = async (data: any) => {
      if (!appScriptUrl) return;
      try {
          await fetch(appScriptUrl, {
              method: 'POST',
              body: JSON.stringify({
                  action: 'request_inspection',
                  requester: currentUser?.name,
                  role: currentUser?.role,
                  ...data
              }),
              mode: 'no-cors'
          });
          showToast("Inspection Request submitted successfully", "success");
      } catch (e) {
          showToast("Failed to submit request", "error");
      }
  };

  const handleViewReport = (item: InspectionData | null) => {
    setSelectedReportData(item);
    setIsReportModalOpen(true);
  };

  const handleNavigate = (module: string) => {
    if (module === 'request_inspection') {
        setIsRequestModalOpen(true);
    } else {
        setActiveModule(module);
        setViewMode('dashboard');
    }
  };

  const handleOnboardingComplete = (updatedUser: User) => {
      const userWithSetup = { ...updatedUser, needsSetup: false };
      setCurrentUser(userWithSetup);
      localStorage.setItem('safetyCheck_user', JSON.stringify(userWithSetup));
      setActiveModule('overview');
      setViewMode('dashboard');
      showToast("Profile updated successfully.", "success");
      setShowTour(true);
  };

  const isAtRoot = activeModule === 'overview';

  if (!currentUser) {
      return (
          <>
            <InstallPwaPrompt />
            {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
            <LoginView 
                onLogin={handleLogin} 
                appScriptUrl={appScriptUrl}
                setAppScriptUrl={setAppScriptUrl}
                settings={settings}
            />
          </>
      );
  }

  if (currentUser && (currentUser as any).needsSetup) {
      return (
          <OnboardingWizard 
            user={currentUser} 
            appScriptUrl={appScriptUrl} 
            onComplete={handleOnboardingComplete} 
          />
      );
  }

  if (showMaintenance) {
      return (
        <>
           <MaintenanceOverlay isActive={true} message={settings.maintenanceMessage || ''} onLogout={() => handleLogout()} />
           {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
        </>
      );
  }

  // Determine if it's a live preview or historical record
  const isDraftViewing = selectedReportData && !selectedReportData.id;

  return (
    <div className="min-h-screen bg-white font-sans text-gray-900 relative">
      <SubmissionOverlay status={submissionStatus} />
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      {showTour && <SystemTour onComplete={() => setShowTour(false)} />}

      {isProfileModalOpen && (
          <ProfileModal 
            user={currentUser} 
            settings={settings}
            appScriptUrl={appScriptUrl} 
            onClose={() => setIsProfileModalOpen(false)} 
            showToast={showToast} 
            onUpdateSuccess={(u) => setCurrentUser(u)} 
            onLogout={() => { setIsProfileModalOpen(false); handleLogout(); }}
          />
      )}

      <RequestInspectionModal
          isOpen={isRequestModalOpen}
          onClose={() => setIsRequestModalOpen(false)}
          onSubmit={handleRequestSubmit}
          validationLists={validationLists}
          currentUserRole={currentUser.role}
      />

      <div className="relative z-10 min-h-screen flex flex-col">
          <div className="no-print">
            <SubscriptionAlert subscription={subscription} user={currentUser} onManage={() => setActiveModule('settings')} />
          </div>

          <header className="bg-white border-b border-gray-100 sticky top-0 z-40 px-4 py-2 flex items-center justify-between h-14 no-print">
              <div className="flex items-center gap-1 sm:gap-2">
                  {!isAtRoot ? (
                      <button 
                          onClick={() => { setActiveModule('overview'); setViewMode('dashboard'); }}
                          title="Back to Overview"
                          className="p-2 text-slate-900 hover:bg-slate-50 rounded-lg transition-all flex items-center group"
                      >
                          <svg className="w-5 h-5 transition-transform group-hover:-translate-x-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M15 19l-7-7 7-7"></path></svg>
                          <span className="text-[10px] font-bold uppercase tracking-widest ml-1 hidden sm:inline">Back</span>
                      </button>
                  ) : (
                      <div className="w-10"></div>
                  )}
              </div>

              <button 
                  onClick={() => { setActiveModule('overview'); setViewMode('dashboard'); }}
                  className="flex flex-col items-center hover:opacity-70 transition-opacity"
              >
                  <h1 className="text-lg font-bold text-slate-900 tracking-tight leading-none uppercase">
                      {settings.companyName || 'Alistair Group'}
                  </h1>
                  <span className="text-[7px] font-bold text-slate-400 tracking-[0.3em] mt-1 uppercase">Fleet Portal</span>
              </button>

              <div className="flex items-center gap-1">
                  <NotificationCenter 
                      id="notification-bell"
                      notifications={notifications}
                      onMarkAsRead={(id) => handleMarkNotificationRead(id)}
                      onDismiss={handleDismissNotification}
                      onClearAll={handleClearAllNotifications}
                      onAcknowledge={handleGlobalAcknowledge}
                      canAcknowledge={isAdmin}
                  />
                  <button 
                      onClick={() => setIsProfileModalOpen(true)} 
                      className={`p-2 transition-colors ${isProfileModalOpen ? 'text-slate-900 bg-slate-50 rounded-full' : 'text-slate-400 hover:text-slate-600'}`}
                  >
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z"></path></svg>
                  </button>
              </div>
          </header>

          <main className="flex-1 p-4 md:p-8 w-full max-w-7xl mx-auto no-print">
              {viewMode === 'form' ? (
                  <InspectionFormView 
                      initialData={formInitialData}
                      activeModule={activeModule}
                      validationLists={validationLists}
                      settings={settings}
                      onSaveDraft={handleExitForm} 
                      onExit={() => setViewMode('dashboard')} 
                      onSubmit={handleGoogleSheetSubmit}
                      submissionStatus={submissionStatus}
                      onViewReport={handleViewReport}
                  />
              ) : (
                  <div className="animate-fadeIn">
                      {activeModule === 'overview' && (
                          <OverviewDashboard 
                              appScriptUrl={appScriptUrl} 
                              onNavigate={handleNavigate} 
                              userRole={currentUser.role}
                              historyList={historyList}
                              isLoading={isLoadingHistory}
                              onViewReport={handleViewReport}
                              isMaintenanceActive={settings.maintenanceMode}
                              pendingAlertsCount={notifications.filter(n => !n.read && n.type === 'critical').length}
                          />
                      )}
                      {(activeModule === 'settings' && isAdmin) && <SettingsView settings={settings} setSettings={setSettings} appScriptUrl={appScriptUrl} setAppScriptUrl={setAppScriptUrl} handleSaveSettings={handleSaveSettings} isSavingSettings={isSavingSettings} showToast={showToast} user={currentUser} />}
                      {(activeModule === 'maintenance' && isSuperAdmin) && <MaintenanceView user={currentUser} appScriptUrl={appScriptUrl} settings={settings} onSettingsUpdate={(s) => setSettings(p => ({...p, ...s}))} showToast={showToast} />}
                      {activeModule === 'general' && <GeneralDashboard userRole={currentUser.role} stats={stats} startNewInspection={() => startFreshInspection('general')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} />}
                      {activeModule === 'petroleum' && <PetroleumDashboard userRole={currentUser.role} stats={stats} startNewInspection={() => startFreshInspection('petroleum')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} />}
                      {activeModule === 'petroleum_v2' && <PetroleumV2Dashboard userRole={currentUser.role} stats={stats} startNewInspection={() => startFreshInspection('petroleum_v2')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} />}
                      {activeModule === 'acid' && <AcidDashboard userRole={currentUser.role} stats={stats} startNewInspection={() => startFreshInspection('acid')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} />}
                      {(activeModule === 'users' && isAdmin) && <UserManagementView currentUser={currentUser} appScriptUrl={appScriptUrl} showToast={showToast} validationLists={validationLists} settings={settings} />}
                      {activeModule === 'support' && <SupportView appScriptUrl={appScriptUrl} currentUser={currentUser} showToast={showToast} settings={settings} validationLists={validationLists} />}
                      {activeModule === 'track_requests' && <RequestTrackingView appScriptUrl={appScriptUrl} currentUser={currentUser} showToast={showToast} onRequestNew={() => setIsRequestModalOpen(true)} />}
                  </div>
              )}
          </main>

          <footer className="mt-auto py-6 border-t border-slate-50 text-center no-print">
              <span className="text-[9px] font-bold text-slate-300 uppercase tracking-[0.2em]">scbc@2026</span>
          </footer>
      </div>

      {isReportModalOpen && selectedReportData && (
          <ReportViewerModal 
            onClose={() => setIsReportModalOpen(false)} 
            onPrint={() => window.print()}
            onSubmit={isDraftViewing ? () => { setIsReportModalOpen(false); handleGoogleSheetSubmit(selectedReportData); } : undefined}
            onSaveDraft={isDraftViewing ? () => { setIsReportModalOpen(false); handleExitForm(selectedReportData); } : undefined}
            isSubmitting={submissionStatus === 'submitting'}
            title={`Report_${selectedReportData.id || 'Draft'}`}
          >
              {activeModule === 'petroleum' ? (
                  <PrintablePetroleumReport data={selectedReportData} settings={settings} />
              ) : activeModule === 'petroleum_v2' ? (
                  <PrintablePetroleumV2Report data={selectedReportData} settings={settings} />
              ) : activeModule === 'acid' ? (
                  <PrintableAcidReport data={selectedReportData} settings={settings} />
              ) : (
                  <PrintableGeneralReport data={selectedReportData} settings={settings} />
              )}
          </ReportViewerModal>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { User, ValidationLists, SystemSettings } from '../types';
import AutocompleteInput from '../components/ui/AutocompleteInput';

interface UserManagementViewProps {
    currentUser: User;
    appScriptUrl: string;
    showToast: (msg: string, type: 'success' | 'error' | 'info' | 'warning') => void;
    validationLists: ValidationLists;
    settings?: SystemSettings;
}

const UserManagementView: React.FC<UserManagementViewProps> = ({ currentUser, appScriptUrl, showToast, validationLists, settings }) => {
    const [users, setUsers] = useState<(User & {password?: string})[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [viewMode, setViewMode] = useState<'list' | 'form'>('list');
    const [isEditing, setIsEditing] = useState(false);
    const [originalUsername, setOriginalUsername] = useState('');

    const [formData, setFormData] = useState({
        name: '', username: '', password: '', role: 'Inspector' as any, position: ''
    });
    const [isSubmitting, setIsSubmitting] = useState(false);

    const isSuperAdmin = currentUser.role === 'SuperAdmin';
    const isAdmin = currentUser.role === 'Admin' || isSuperAdmin;

    useEffect(() => { 
        if (isAdmin) fetchUsers(); 
    }, [isAdmin]);

    // SECURITY GUARD: If user is not authorized, don't show the view content
    if (!isAdmin) {
        return (
