                                        <div className="min-w-0">
                                            <div className="font-medium text-slate-800 text-base leading-tight truncate">{u.name || 'Setup Pending'}</div>
                                            <div className="text-[11px] text-slate-400 font-normal tracking-tight truncate">{u.username}</div>
