              </div>

              {isLoadingHistory ? (
                  <div className="py-16 text-center">
                      <div className="w-8 h-8 border-4 border-slate-200 border-t-indigo-500 rounded-full animate-spin mx-auto mb-4"></div>
                      <p className="text-[10px] font-medium text-slate-400 uppercase tracking-widest">Updating Records</p>
                  </div>
              ) : displayList.length === 0 ? (
                  <div className="py-16 text-center text-[11px] font-medium text-slate-300 uppercase tracking-widest">No active records found</div>
              ) : (
                  <div className="w-full">
                      {/* Desktop Table Headers */}
                      <div className="hidden md:grid grid-cols-12 px-6 py-4 border-b border-slate-100 bg-slate-50/30 text-[10px] font-medium text-slate-400 uppercase tracking-[0.2em]">
                          <div className="col-span-1">Status</div>
                          <div className="col-span-3">Vehicle Asset</div>
                          <div className="col-span-3">Audit Date</div>
                          <div className="col-span-3">Assigned Inspector</div>
                          <div className="col-span-2 text-right">Documents</div>
                      </div>

                      <div className="divide-y divide-slate-100">
                          {displayList.map((item, i) => (
                              <div key={i} className="md:grid md:grid-cols-12 flex flex-col md:items-center px-6 py-4 hover:bg-slate-50/50 transition-colors gap-3 md:gap-0 relative group">
                                  {/* Status Column */}
                                  <div className="col-span-1">
                                      <span className={`inline-flex items-center justify-center w-7 h-7 rounded-lg text-[11px] font-medium text-white shadow-sm
                                          ${Number(item.rate) >= 4 ? 'bg-emerald-500' : Number(item.rate) === 3 ? 'bg-amber-500' : 'bg-rose-500'}
                                      `}>
                                          {item.rate}
                                      </span>
                                  </div>

                                  {/* Vehicle Asset */}
                                  <div className="col-span-3 min-w-0">
                                      <div className="md:hidden text-[9px] font-medium text-slate-300 uppercase tracking-widest mb-1">Vehicle Asset</div>
                                      <div className="font-medium text-slate-800 text-base leading-tight truncate uppercase tracking-tight">{item.truckNo}</div>
                                      {item.trailerNo && <div className="text-[10px] text-slate-400 font-normal uppercase tracking-wide">{item.trailerNo}</div>}
                                  </div>

                                  {/* Audit Date */}
                                  <div className="col-span-3">
                                      <div className="md:hidden text-[9px] font-medium text-slate-300 uppercase tracking-widest mb-1">Audit Date</div>
                                      <div className="text-xs font-normal text-slate-700">{new Date(item.timestamp).toLocaleDateString()}</div>
                                      <div className="text-[9px] text-slate-400 font-normal uppercase">{new Date(item.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</div>
                                  </div>

                                  {/* Inspector */}
                                  <div className="col-span-3">
                                      <div className="md:hidden text-[9px] font-medium text-slate-300 uppercase tracking-widest mb-1">Personnel</div>
                                      <div className="flex items-center gap-2">
                                          <div className="hidden md:flex w-7 h-7 rounded-lg bg-slate-100 items-center justify-center text-[10px] font-medium text-slate-400 border border-slate-200 uppercase">
                                              {String(item.inspectedBy || '?').charAt(0)}
                                          </div>
                                          <span className="text-slate-600 font-normal text-xs truncate">{item.inspectedBy}</span>
                                      </div>
                                  </div>

                                  {/* Action Button */}
                                  <div className="col-span-2 text-right border-t md:border-none pt-3 md:pt-0">
                                      <button 
                                        onClick={() => onViewReport(item)}
                                        className="w-full md:w-auto inline-flex items-center justify-center gap-2 px-4 py-2 text-[10px] font-medium text-indigo-600 bg-indigo-50 hover:bg-indigo-600 hover:text-white rounded-xl transition-all uppercase tracking-widest border border-indigo-100 shadow-sm active:scale-95 group/btn"
                                      >
                                          <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path><path d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z"></path></svg>
                                          Report
                                      </button>
                                  </div>
                              </div>
                          ))}
                      </div>
                  </div>
              )}
          </div>
      </div>
      </SubscriptionLock>
    );
};

export default DashboardTemplate;

import React, { useState, useEffect } from 'react';
import { INITIAL_DATA, InspectionData, User } from './types';
import { 
    SHEET_HEADERS, PETROLEUM_HEADERS, PETROLEUM_V2_HEADERS, ACID_HEADERS,
    INSPECTION_ITEMS, PETROLEUM_INSPECTION_ITEMS, PETROLEUM_V2_ITEMS, ACID_INSPECTION_ITEMS
} from './constants';

// Hooks
import { useAuth } from './hooks/useAuth';
import { useSettings } from './hooks/useSettings';
import { useNotifications } from './hooks/useNotifications';
import { useHistory } from './hooks/useHistory';
import { useOfflineSync } from './hooks/useOfflineSync';
import { useSubscription } from './hooks/useSubscription';

// UI Components
import Toast from './components/ui/Toast';
import ReportViewerModal from './components/ui/ReportViewerModal';
import SubmissionOverlay from './components/ui/SubmissionOverlay';
import ProfileModal from './components/ui/ProfileModal';
import NotificationCenter from './components/ui/NotificationCenter'; 
import UpgradeModal from './components/ui/UpgradeModal';
import InspectionStartModal from './components/ui/InspectionStartModal';
import SubscriptionAlert from './components/ui/SubscriptionAlert';
import MaintenanceOverlay from './components/ui/MaintenanceOverlay';
import RequestInspectionModal from './components/ui/RequestInspectionModal'; 
import OnboardingWizard from './components/ui/OnboardingWizard'; 
import SystemTour from './components/ui/SystemTour'; 
import InstallPwaPrompt from './components/ui/InstallPwaPrompt';

// Views
import LoginView from './views/LoginView';
import SettingsView from './views/SettingsView';
import GeneralDashboard from './views/GeneralDashboard';
import PetroleumDashboard from './views/PetroleumDashboard';
import PetroleumV2Dashboard from './views/PetroleumV2Dashboard';
import AcidDashboard from './views/AcidDashboard';
import UserManagementView from './views/UserManagementView';
import OverviewDashboard from './views/OverviewDashboard';
import InspectionFormView from './views/InspectionFormView';
import SupportView from './views/SupportView';
import MaintenanceView from './views/MaintenanceView';
import RequestTrackingView from './views/RequestTrackingView';

// Report Components
import PrintableGeneralReport from './components/reports/PrintableGeneralReport';
import PrintablePetroleumReport from './components/reports/PrintablePetroleumReport';
import PrintablePetroleumV2Report from './components/reports/PrintablePetroleumV2Report';
import PrintableAcidReport from './components/reports/PrintableAcidReport';

const App = () => {
  const { currentUser, setCurrentUser, handleLogin, handleLogout, sessionExpired, setSessionExpired } = useAuth();
  const { settings, setSettings, appScriptUrl, setAppScriptUrl, isSavingSettings, handleSaveSettings } = useSettings();
  const { subscription } = useSubscription(appScriptUrl, currentUser);

  const [activeModule, setActiveModule] = useState('overview'); 
  const [viewMode, setViewMode] = useState<'dashboard' | 'form'>('dashboard');
  const [isProfileModalOpen, setIsProfileModalOpen] = useState(false);
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error' | 'info' | 'warning'} | null>(null);
  const [isRequestModalOpen, setIsRequestModalOpen] = useState(false);
  const [showTour, setShowTour] = useState(false);

  const { historyList, isLoadingHistory, validationLists, stats, fetchHistory } = useHistory(appScriptUrl, activeModule, currentUser);

  const showToast = (message: string, type: 'success' | 'error' | 'info' | 'warning') => {
      setToast({ message, type });
      setTimeout(() => setToast(null), 4000);
  };

  useEffect(() => {
      if (sessionExpired === 'idle') showToast("Session expired due to inactivity.", 'warning');
      else if (sessionExpired === 'max_duration') showToast("Session limit reached. Log in again.", 'info');
      if (sessionExpired) setSessionExpired(null);
  }, [sessionExpired]);

  const { submissionStatus, setSubmissionStatus, isSyncing, addToQueue } = useOfflineSync(appScriptUrl, showToast, () => fetchHistory(true));
  const { notifications, handleMarkNotificationRead, handleDismissNotification, handleClearAllNotifications, handleGlobalAcknowledge } = useNotifications(appScriptUrl, currentUser, showToast);

  const [isReportModalOpen, setIsReportModalOpen] = useState(false);
  const [selectedReportData, setSelectedReportData] = useState<InspectionData | null>(null);
  const [formInitialData, setFormInitialData] = useState<InspectionData>(INITIAL_DATA);

  const isAdmin = currentUser?.role === 'Admin' || currentUser?.role === 'SuperAdmin';
  const isSuperAdmin = currentUser?.role === 'SuperAdmin';
  const showMaintenance = settings.maintenanceMode && currentUser && !isSuperAdmin;

  // Security guard for admin routes
  useEffect(() => {
    if (!currentUser) return;
    const restrictedModules = ['users', 'settings', 'maintenance'];
    if (restrictedModules.includes(activeModule) && !isAdmin) {
        setActiveModule('overview');
    }
  }, [activeModule, currentUser, isAdmin]);

  const startFreshInspection = (module: string, prefill?: Partial<InspectionData>) => {
      setFormInitialData({ ...INITIAL_DATA, timestamp: new Date().toISOString(), inspectedBy: currentUser?.name || '', ...prefill });
      setViewMode('form');
  };

  const handleExitForm = (savedData?: InspectionData) => setViewMode('dashboard');

  const handleGoogleSheetSubmit = async (formData: InspectionData) => {
    if (!appScriptUrl) {
        showToast("Server URL not configured", "error");
        return;
    }

    setSubmissionStatus('submitting');

    let sheetName = 'General';
    let headers = SHEET_HEADERS;
    let moduleTitle = "General Vehicle Inspection";
    let activeItems = INSPECTION_ITEMS;

    if (activeModule === 'petroleum') { 
        sheetName = 'Petroleum'; 
        headers = PETROLEUM_HEADERS; 
        moduleTitle = "Petroleum Tanker Inspection";
        activeItems = PETROLEUM_INSPECTION_ITEMS;
    }
    else if (activeModule === 'petroleum_v2') { 
        sheetName = 'Petroleum_V2'; 
        headers = PETROLEUM_V2_HEADERS; 
        moduleTitle = "Petroleum Tanker Inspection V2";
        activeItems = PETROLEUM_V2_ITEMS;
    }
    else if (activeModule === 'acid') { 
        sheetName = 'Acid'; 
        headers = ACID_HEADERS; 
        moduleTitle = "Acid Tanker Inspection";
        activeItems = ACID_INSPECTION_ITEMS;
    }

    const row = headers.map(h => formData[h] !== undefined ? formData[h] : "");

    const reportData = {
        title: moduleTitle,
        timestamp: formData.timestamp,
        truckNo: formData.truckNo,
        trailerNo: formData.trailerNo,
        jobCard: formData.jobCard,
        location: formData.location,
        odometer: formData.odometer,
        inspectedBy: formData.inspectedBy,
        driverName: formData.driverName,
        remarks: formData.remarks,
        rate: formData.rate,
        signatures: {
            inspector: formData.inspectorSignature,
            driver: formData.driverSignature
        },
        photos: {
            front: formData.photoFront,
            ls: formData.photoLS,
            rs: formData.photoRS,
            back: formData.photoBack,
            damage: formData.photoDamage
        },
        items: activeItems.map(item => ({
            label: item.label,
            category: item.category,
            status: formData[item.id] || 'N/A'
        })),
        companyName: settings.companyName,
        companyLogo: settings.companyLogo
    };

    const payload = {
        action: 'create',
        sheet: sheetName,
        headers: headers,
        row: row,
        requestId: formData.requestId || null,
        reportData: reportData 
    };

    if (!navigator.onLine) {
        addToQueue(payload);
        setSubmissionStatus('offline_saved');
        setTimeout(() => {
            setSubmissionStatus('idle');
            setViewMode('dashboard');
        }, 3500);
        return;
    }

    try {
        await fetch(appScriptUrl, {
            method: 'POST',
            body: JSON.stringify(payload),
            mode: 'no-cors' 
        });

        setSubmissionStatus('success');
        fetchHistory(true); 

        setTimeout(() => {
            setSubmissionStatus('idle');
            setViewMode('dashboard');
        }, 3000);

    } catch (error) {
        console.error("Submission error", error);
        addToQueue(payload);
        setSubmissionStatus('offline_saved');
        setTimeout(() => {
            setSubmissionStatus('idle');
            setViewMode('dashboard');
        }, 3500);
    }
  };

  const handleRequestSubmit = async (data: any) => {
      if (!appScriptUrl) return;
      try {
          await fetch(appScriptUrl, {
              method: 'POST',
              body: JSON.stringify({
                  action: 'request_inspection',
                  requester: currentUser?.name,
                  role: currentUser?.role,
                  ...data
              }),
              mode: 'no-cors'
          });
          showToast("Inspection Request submitted successfully", "success");
      } catch (e) {
          showToast("Failed to submit request", "error");
      }
  };

  const handleViewReport = (item: InspectionData | null) => {
    setSelectedReportData(item);
    setIsReportModalOpen(true);
  };

  const handleNavigate = (module: string) => {
    setActiveModule(module);
    setViewMode('dashboard');
  };

  const handleOnboardingComplete = (updatedUser: User) => {
      const userWithSetup = { ...updatedUser, needsSetup: false };
      setCurrentUser(userWithSetup);
      localStorage.setItem('safetyCheck_user', JSON.stringify(userWithSetup));
      setActiveModule('overview');
      setViewMode('dashboard');
      showToast("Profile updated successfully.", "success");
      setShowTour(true);
  };

  const isAtRoot = activeModule === 'overview';

  if (!currentUser) {
      return (
          <>
            <InstallPwaPrompt />
            {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
            <LoginView 
                onLogin={handleLogin} 
                appScriptUrl={appScriptUrl}
                setAppScriptUrl={setAppScriptUrl}
                settings={settings}
            />
          </>
      );
  }

  if (currentUser && (currentUser as any).needsSetup) {
      return (
          <OnboardingWizard 
            user={currentUser} 
            appScriptUrl={appScriptUrl} 
            onComplete={handleOnboardingComplete} 
          />
      );
  }

  if (showMaintenance) {
      return (
        <>
           <MaintenanceOverlay isActive={true} message={settings.maintenanceMessage || ''} onLogout={() => handleLogout()} />
           {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
        </>
      );
  }

  // Determine if it's a live preview or historical record
  // Explicitly check for ID to ensure historical reports don't show "Submit" buttons
  const isDraftViewing = !!(selectedReportData && (!selectedReportData.id || selectedReportData.id === "" || selectedReportData.id === null));

  return (
    <div className="min-h-screen bg-white font-sans text-gray-900 relative">
      <SubmissionOverlay status={submissionStatus} />
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      {showTour && <SystemTour onComplete={() => setShowTour(false)} />}

      {isProfileModalOpen && (
          <ProfileModal 
            user={currentUser} 
            settings={settings}
            appScriptUrl={appScriptUrl} 
            onClose={() => setIsProfileModalOpen(false)} 
            showToast={showToast} 
            onUpdateSuccess={(u) => setCurrentUser(u)} 
            onLogout={() => { setIsProfileModalOpen(false); handleLogout(); }}
          />
      )}

      <RequestInspectionModal
          isOpen={isRequestModalOpen}
          onClose={() => setIsRequestModalOpen(false)}
          onSubmit={handleRequestSubmit}
          validationLists={validationLists}
          currentUserRole={currentUser.role}
      />

      <div className="relative z-10 min-h-screen flex flex-col">
          <div className="no-print">
            <SubscriptionAlert subscription={subscription} user={currentUser} onManage={() => setActiveModule('settings')} />
          </div>

          <header className="bg-white border-b border-gray-100 sticky top-0 z-40 px-4 py-2 flex items-center justify-between h-14 no-print">
              <div className="flex items-center gap-1 sm:gap-2">
                  {!isAtRoot ? (
                      <button 
                          onClick={() => { setActiveModule('overview'); setViewMode('dashboard'); }}
                          title="Back to Overview"
                          className="p-2 text-slate-900 hover:bg-slate-50 rounded-lg transition-all flex items-center group"
                      >
                          <svg className="w-5 h-5 transition-transform group-hover:-translate-x-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M15 19l-7-7 7-7"></path></svg>
                          <span className="text-[10px] font-bold uppercase tracking-widest ml-1 hidden sm:inline">Back</span>
                      </button>
                  ) : (
                      <div className="w-10"></div>
                  )}
              </div>

              <button 
                  onClick={() => { setActiveModule('overview'); setViewMode('dashboard'); }}
                  className="flex flex-col items-center hover:opacity-70 transition-opacity"
              >
                  <h1 className="text-lg font-bold text-slate-900 tracking-tight leading-none uppercase">
                      {settings.companyName || 'Alistair Group'}
                  </h1>
                  <span className="text-[7px] font-bold text-slate-400 tracking-[0.3em] mt-1 uppercase">Fleet Portal</span>
              </button>

              <div className="flex items-center gap-1">
                  <NotificationCenter 
                      id="notification-bell"
                      notifications={notifications}
                      onMarkAsRead={(id) => handleMarkNotificationRead(id)}
                      onDismiss={handleDismissNotification}
                      onClearAll={handleClearAllNotifications}
                      onAcknowledge={handleGlobalAcknowledge}
                      canAcknowledge={isAdmin}
                  />
                  <button 
                      onClick={() => setIsProfileModalOpen(true)} 
                      className={`p-2 transition-colors ${isProfileModalOpen ? 'text-slate-900 bg-slate-50 rounded-full' : 'text-slate-400 hover:text-slate-600'}`}
                  >
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z"></path></svg>
                  </button>
              </div>
          </header>

          <main className="flex-1 p-4 md:p-8 w-full max-w-7xl mx-auto no-print">
              {viewMode === 'form' ? (
                  <InspectionFormView 
                      initialData={formInitialData}
                      activeModule={activeModule}
                      validationLists={validationLists}
                      settings={settings}
                      onSaveDraft={handleExitForm} 
                      onExit={() => setViewMode('dashboard')} 
                      onSubmit={handleGoogleSheetSubmit}
                      submissionStatus={submissionStatus}
                      onViewReport={handleViewReport}
                  />
              ) : (
                  <div className="animate-fadeIn">
                      {activeModule === 'overview' && (
                          <OverviewDashboard 
                              appScriptUrl={appScriptUrl} 
                              onNavigate={handleNavigate} 
                              userRole={currentUser.role}
                              historyList={historyList}
                              isLoading={isLoadingHistory}
                              onViewReport={handleViewReport}
                              isMaintenanceActive={settings.maintenanceMode}
                              pendingAlertsCount={notifications.filter(n => !n.read && n.type === 'critical').length}
                          />
                      )}
                      {(activeModule === 'settings' && isAdmin) && <SettingsView settings={settings} setSettings={setSettings} appScriptUrl={appScriptUrl} setAppScriptUrl={setAppScriptUrl} handleSaveSettings={handleSaveSettings} isSavingSettings={isSavingSettings} showToast={showToast} user={currentUser} />}
                      {(activeModule === 'maintenance' && isSuperAdmin) && <MaintenanceView user={currentUser} appScriptUrl={appScriptUrl} settings={settings} onSettingsUpdate={(s) => setSettings(p => ({...p, ...s}))} showToast={showToast} />}
                      {activeModule === 'general' && <GeneralDashboard userRole={currentUser.role} stats={stats} startNewInspection={() => startFreshInspection('general')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} />}
                      {activeModule === 'petroleum' && <PetroleumDashboard userRole={currentUser.role} stats={stats} startNewInspection={() => startFreshInspection('petroleum')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} />}
                      {activeModule === 'petroleum_v2' && <PetroleumV2Dashboard userRole={currentUser.role} stats={stats} startNewInspection={() => startFreshInspection('petroleum_v2')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} />}
                      {activeModule === 'acid' && <AcidDashboard userRole={currentUser.role} stats={stats} startNewInspection={() => startFreshInspection('acid')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} />}
                      {(activeModule === 'users' && isAdmin) && <UserManagementView currentUser={currentUser} appScriptUrl={appScriptUrl} showToast={showToast} validationLists={validationLists} settings={settings} />}
                      {activeModule === 'support' && <SupportView appScriptUrl={appScriptUrl} currentUser={currentUser} showToast={showToast} settings={settings} validationLists={validationLists} />}
                      {activeModule === 'track_requests' && <RequestTrackingView appScriptUrl={appScriptUrl} currentUser={currentUser} showToast={showToast} onRequestNew={() => setIsRequestModalOpen(true)} />}
                  </div>
              )}
          </main>

          <footer className="mt-auto py-6 border-t border-slate-50 text-center no-print">
              <span className="text-[9px] font-bold text-slate-300 uppercase tracking-[0.2em]">scbc@2026</span>
          </footer>
      </div>

      {isReportModalOpen && selectedReportData && (
          <ReportViewerModal 
            onClose={() => setIsReportModalOpen(false)} 
            onPrint={() => window.print()}
            onSubmit={isDraftViewing ? () => { setIsReportModalOpen(false); handleGoogleSheetSubmit(selectedReportData); } : undefined}
            onSaveDraft={isDraftViewing ? () => { setIsReportModalOpen(false); handleExitForm(selectedReportData); } : undefined}
            isSubmitting={submissionStatus === 'submitting'}
            title={`Report_${selectedReportData.id || 'Draft'}`}
          >
              {activeModule === 'petroleum' ? (
                  <PrintablePetroleumReport data={selectedReportData} settings={settings} />
              ) : activeModule === 'petroleum_v2' ? (
                  <PrintablePetroleumV2Report data={selectedReportData} settings={settings} />
              ) : activeModule === 'acid' ? (
                  <PrintableAcidReport data={selectedReportData} settings={settings} />
              ) : (
                  <PrintableGeneralReport data={selectedReportData} settings={settings} />
              )}
          </ReportViewerModal>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { InspectionData, InspectionStatus, InspectionItemConfig, ValidationLists, SystemSettings } from '../types';
import { INSPECTION_ITEMS, INSPECTION_CATEGORIES, PETROLEUM_INSPECTION_ITEMS, PETROLEUM_CATEGORIES, ACID_INSPECTION_ITEMS, ACID_CATEGORIES, PETROLEUM_V2_ITEMS, PETROLEUM_V2_CATEGORIES, SECTIONS } from '../constants';
import CameraCapture from '../components/CameraCapture';
import SignaturePad from '../components/SignaturePad';
import StatusButton from '../components/ui/StatusButton';
import Input from '../components/ui/Input';
import AutocompleteInput from '../components/ui/AutocompleteInput';
import PrintableGeneralReport from '../components/reports/PrintableGeneralReport';
import PrintablePetroleumReport from '../components/reports/PrintablePetroleumReport';
import PrintablePetroleumV2Report from '../components/reports/PrintablePetroleumV2Report';
import PrintableAcidReport from '../components/reports/PrintableAcidReport';

interface InspectionFormViewProps {
    initialData: InspectionData;
    activeModule: string;
    validationLists: ValidationLists;
    settings: SystemSettings;
    onSaveDraft: (data: InspectionData) => void;
    onSubmit: (data: InspectionData) => void;
    onExit: () => void;
    submissionStatus: 'idle' | 'submitting' | 'success' | 'offline_saved';
    onViewReport: (data: InspectionData) => void;
}

const InspectionFormView: React.FC<InspectionFormViewProps> = ({ 
    initialData, activeModule, validationLists, settings, onSaveDraft, onSubmit, onExit, submissionStatus, onViewReport 
}) => {
    const [formData, setFormData] = useState<InspectionData & any>(initialData);
    const [currentSection, setCurrentSection] = useState(0);
    const [errors, setErrors] = useState<Record<string, boolean>>({});

    const updateField = (field: string, value: any) => {
        setFormData((prev: any) => ({ ...prev, [field]: value }));
        if (errors[field]) {
            setErrors(prev => {
                const next = {...prev};
                delete next[field];
                return next;
            });
        }
    };

    const getItemsForStep = (stepIndex: number): InspectionItemConfig[] => {
        let categories: string[] = [];
        let sourceItems: InspectionItemConfig[] = [];

        if (activeModule === 'general') sourceItems = INSPECTION_ITEMS;
        else if (activeModule === 'petroleum') sourceItems = PETROLEUM_INSPECTION_ITEMS;
        else if (activeModule === 'petroleum_v2') sourceItems = PETROLEUM_V2_ITEMS;
        else if (activeModule === 'acid') sourceItems = ACID_INSPECTION_ITEMS;

        if (activeModule === 'general') {
            if (stepIndex === 2) categories = [INSPECTION_CATEGORIES.PPE, INSPECTION_CATEGORIES.DOCUMENTATION];
            if (stepIndex === 3) categories = [INSPECTION_CATEGORIES.VEHICLE_EXTERIOR, INSPECTION_CATEGORIES.LIGHTS_ELECTRICAL];
            if (stepIndex === 4) categories = [INSPECTION_CATEGORIES.MECHANICAL, INSPECTION_CATEGORIES.TRAILER];
        } else if (activeModule === 'petroleum') {
            if (stepIndex === 2) categories = [PETROLEUM_CATEGORIES.TRUCK_EQUIPMENT];
            if (stepIndex === 3) categories = [PETROLEUM_CATEGORIES.TYRES, PETROLEUM_CATEGORIES.PPE_ID];
            if (stepIndex === 4) categories = [PETROLEUM_CATEGORIES.DOCUMENTS, PETROLEUM_CATEGORIES.ONBOARD];
        } else if (activeModule === 'petroleum_v2') {
            if (stepIndex === 2) categories = [PETROLEUM_V2_CATEGORIES.PRIME_MOVER];
            if (stepIndex === 3) categories = [PETROLEUM_V2_CATEGORIES.TRAILER_TANKS];
            if (stepIndex === 4) categories = [PETROLEUM_V2_CATEGORIES.DRIVER, PETROLEUM_V2_CATEGORIES.SAFETY_SIGNS, PETROLEUM_V2_CATEGORIES.DOCUMENTS];
        } else if (activeModule === 'acid') {
            if (stepIndex === 2) categories = [ACID_CATEGORIES.PPE];
            if (stepIndex === 3) categories = [ACID_CATEGORIES.VEHICLE];
            if (stepIndex === 4) categories = [ACID_CATEGORIES.SPILL_KIT, ACID_CATEGORIES.DOCUMENTATION];
        }

        return sourceItems.filter(item => categories.includes(item.category));
    };

    const validateSection = (sectionIndex: number): boolean => {
        const newErrors: Record<string, boolean> = {};

        if (sectionIndex === 0) {
            if (!formData.truckNo) newErrors.truckNo = true;
            if (!formData.trailerNo) newErrors.trailerNo = true;
            if (!formData.driverName) newErrors.driverName = true;
            if (!formData.location) newErrors.location = true;
            if (!formData.odometer) newErrors.odometer = true;
            if (activeModule !== 'general' && !formData.jobCard) newErrors.jobCard = true;
        }

        if (sectionIndex >= 2 && sectionIndex <= 4) {
            const requiredItems = getItemsForStep(sectionIndex);

            requiredItems.forEach(item => {
                const val = formData[item.id];
                if (!val) {
                    newErrors[item.id] = true;
                }
            });
        }

        if (sectionIndex === 5) {
             if (!formData.remarks || formData.remarks.trim() === '') newErrors.remarks = true;
             if (!formData.rate || formData.rate === 0) newErrors.rate = true;
             if (!formData.inspectorSignature) newErrors.inspectorSignature = true;
             if (!formData.driverSignature) newErrors.driverSignature = true;
        }

        if (Object.keys(newErrors).length > 0) {
            setErrors(newErrors);
            window.scrollTo({ top: 0, behavior: 'smooth' }); 
            return false;
        }

        setErrors({});
        return true;
    };

    const validateFullForm = (): boolean => {
        for (let i = 0; i <= 5; i++) {
            if (!validateSection(i)) {
                setCurrentSection(i); 
                return false;
            }
        }
        return true;
    };

    const handleNext = () => {
        if (!validateSection(currentSection)) return;
        window.scrollTo({ top: 0, behavior: 'smooth' });
        setCurrentSection(prev => Math.min(prev + 1, SECTIONS.length - 1));
    };

    const handleBack = () => {
        if (currentSection === 0) {
            onExit();
        } else {
            window.scrollTo({ top: 0, behavior: 'smooth' });
            setCurrentSection(prev => Math.max(prev - 1, 0));
        }
    };

    const handleSubmitInspection = () => {
        if (validateFullForm()) {
            onSubmit(formData);
        }
    };

    const renderDetailsSection = () => (
      <div className="space-y-6 animate-fadeIn">
        {formData.requestId && (
            <div className="bg-gradient-to-r from-indigo-500 to-blue-600 p-4 rounded-xl shadow-lg flex items-center justify-between text-white border border-indigo-400">
                <div className="flex items-center gap-3">
                    <div className="p-2 bg-white/20 rounded-lg backdrop-blur-sm">
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-3 7h3m-3 4h3m-6-4h.01M9 16h.01"></path></svg>
                    </div>
                    <div>
                        <p className="text-xs font-bold uppercase tracking-widest text-indigo-100">Assignment</p>
                        <p className="text-sm font-bold">Request #{formData.requestId}</p>
                    </div>
                </div>
            </div>
        )}

        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
          <h2 className="text-xl font-bold text-gray-800 mb-6 flex items-center gap-2">
            Vehicle Context
          </h2>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-x-8 gap-y-6">
            <AutocompleteInput 
              label="Truck Reg No *" 
              value={formData.truckNo} 
              onChange={v => updateField('truckNo', v)} 
              options={validationLists.trucks}
              placeholder="e.g. AHB 1502"
              isRegNo={true}
              error={errors.truckNo}
            />
            <AutocompleteInput 
              label="Trailer No *" 
              value={formData.trailerNo} 
              onChange={v => updateField('trailerNo', v)} 
              options={validationLists.trailers}
              placeholder="e.g. T-900"
              isRegNo={true}
              error={errors.trailerNo}
            />
            <Input label="Job Card Reference" value={formData.jobCard || ''} onChange={v => updateField('jobCard', v)} error={errors.jobCard} />
            <AutocompleteInput label="Lead Inspector" value={formData.inspectedBy} onChange={v => updateField('inspectedBy', v)} options={validationLists.inspectors} placeholder="Auto-filled" isTitleCase={true} readOnly={true} />
            <AutocompleteInput label="Driver Name *" value={formData.driverName} onChange={v => updateField('driverName', v)} options={validationLists.drivers} placeholder="Full Name" isTitleCase={true} error={errors.driverName} />
            <AutocompleteInput label="Location *" value={formData.location} onChange={v => updateField('location', v)} options={validationLists.locations} placeholder="Hub" isTitleCase={true} error={errors.location} />
            <Input label="Odometer (km) *" type="number" value={formData.odometer} onChange={v => updateField('odometer', v)} error={errors.odometer} />
          </div>
        </div>
      </div>
    );

    const renderPhotosSection = () => (
      <div className="space-y-6 animate-fadeIn">
         <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
          <h2 className="text-xl font-bold text-gray-800 mb-6">Inspection Photos</h2>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
            <CameraCapture label="Horse: Front" existingImage={formData.photoFront} onCapture={img => updateField('photoFront', img)} />
            <CameraCapture label="Horse: Left Side" existingImage={formData.photoLS} onCapture={img => updateField('photoLS', img)} />
            <CameraCapture label="Horse: Right Side" existingImage={formData.photoRS} onCapture={img => updateField('photoRS', img)} />
            <CameraCapture label="Trailer: Rear" existingImage={formData.photoBack} onCapture={img => updateField('photoBack', img)} />
          </div>
        </div>
      </div>
    );

    const renderInspectionSection = (categoriesToShow: string[]) => {
        const itemsToRender = getItemsForStep(currentSection).filter(i => categoriesToShow.includes(i.category));
        const grouping: Record<string, InspectionItemConfig[]> = {};
        categoriesToShow.forEach(cat => {
            grouping[cat] = itemsToRender.filter(i => i.category === cat);
        });

        return (
          <div className="space-y-8 animate-fadeIn">
            {categoriesToShow.map(cat => (
              <div key={cat} className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
                <div className="bg-gray-50 px-6 py-4 border-b border-gray-100 flex justify-between items-center">
                  <h3 className="text-base font-bold text-slate-700 uppercase tracking-widest">{cat}</h3>
                  <span className="text-[10px] text-red-500 font-bold uppercase tracking-widest">Required</span>
                </div>
                <div className="divide-y divide-gray-100">
                  {grouping[cat].map(item => (
                    <div key={item.id} className={`p-6 transition-colors ${errors[item.id] ? 'bg-red-50/50' : ''}`}>
                      <div className="flex justify-between items-start mb-4">
                          <span className={`font-bold text-sm leading-tight ${errors[item.id] ? 'text-red-800' : 'text-gray-800'}`}>
                              {item.label}
                          </span>
                      </div>
                      <div className="grid grid-cols-4 gap-2 sm:gap-4 max-w-lg">
                         <StatusButton label="OK" status={InspectionStatus.GOOD} current={formData[item.id]} onClick={() => updateField(item.id, InspectionStatus.GOOD)} colorClass="green" />
                         <StatusButton label="Fail" status={InspectionStatus.BAD} current={formData[item.id]} onClick={() => updateField(item.id, InspectionStatus.BAD)} colorClass="red" />
                         <StatusButton label="Attn" status={InspectionStatus.ATTENTION} current={formData[item.id]} onClick={() => updateField(item.id, InspectionStatus.ATTENTION)} colorClass="yellow" />
                         <StatusButton label="N/A" status={InspectionStatus.NIL} current={formData[item.id]} onClick={() => updateField(item.id, InspectionStatus.NIL)} colorClass="gray" />
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            ))}
          </div>
        );
    };

    const renderSignaturesSection = () => (
      <div className="space-y-6 animate-fadeIn">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
          <h2 className="text-xl font-bold text-gray-800 mb-6">Authorization</h2>

          <div className="mb-8">
            <label className={`block text-[10px] font-bold uppercase mb-2 tracking-widest ${errors.remarks ? 'text-red-600' : 'text-slate-500'}`}>Finding Details *</label>
            <textarea className="w-full p-4 border rounded-xl h-32 outline-none font-medium text-sm border-gray-200 focus:ring-2 focus:ring-blue-100 bg-slate-50" placeholder="Condition details..." value={formData.remarks} onChange={(e) => updateField('remarks', e.target.value)} />
          </div>

          <div className="mb-10">
             <label className="block text-[10px] font-bold uppercase mb-4 tracking-widest text-slate-500">Safety Rating *</label>
             <div className="flex gap-2 sm:gap-4 flex-wrap">
               {[1, 2, 3, 4, 5].map(num => (
                 <button key={num} type="button" onClick={() => updateField('rate', num)} className={`w-12 h-12 rounded-xl font-black text-lg transition-all ${formData.rate === num ? 'bg-slate-900 text-white shadow-xl scale-110' : 'bg-gray-100 text-slate-400 hover:bg-gray-200'}`}>{num}</button>
               ))}
             </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 pt-8 border-t border-slate-100">
             <SignaturePad label="Inspector Sign-off" existingSignature={formData.inspectorSignature} onSave={sig => updateField('inspectorSignature', sig)} />
             <SignaturePad label="Driver Acknowledgement" existingSignature={formData.driverSignature} onSave={sig => updateField('driverSignature', sig)} />
          </div>
        </div>
      </div>
    );

    const renderSummarySection = () => (
      <div className="space-y-6 animate-fadeIn pb-12">
        <div className="bg-white p-10 rounded-2xl shadow-lg border border-gray-100 text-center">
          <div className="w-16 h-16 bg-emerald-100 rounded-full flex items-center justify-center mx-auto mb-6">
              <svg className="w-8 h-8 text-emerald-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
          </div>
          <h2 className="text-2xl font-bold text-slate-800 mb-2">Checklist Verified</h2>
          <p className="text-slate-500 font-medium text-sm">Please confirm all details are correct before performing the final upload to the server.</p>
        </div>

        <div className="mt-8 bg-emerald-950 rounded-3xl p-8 text-white shadow-2xl relative overflow-hidden group">
            <div className="relative z-10 flex flex-col md:flex-row items-center justify-between gap-8">
                <div className="text-center md:text-left">
                    <h3 className="text-2xl font-black mb-2 text-white uppercase tracking-tight">Final Upload</h3>
                    <p className="text-emerald-400 text-xs font-medium uppercase tracking-widest opacity-80">Synchronize with Fleet Server</p>
                </div>
                <button onClick={handleSubmitInspection} disabled={submissionStatus !== 'idle'} className={`w-full md:w-auto px-10 py-5 text-white rounded-2xl font-black text-lg shadow-2xl transition-all flex items-center justify-center gap-3 active:scale-95 border-2 border-white/20 uppercase tracking-[0.2em] ${submissionStatus !== 'idle' ? 'bg-slate-700' : 'bg-emerald-600 hover:bg-emerald-500'}`}>
                    {submissionStatus === 'submitting' ? 'Processing...' : submissionStatus === 'offline_saved' ? 'Queued Offline' : 'Submit Inspection'}
                    {submissionStatus === 'idle' && <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>}
                </button>
            </div>
        </div>
      </div>
    );

    return (
        <div className="flex flex-col min-h-screen bg-slate-50/50">
             <div className="bg-white border-b border-gray-200 sticky top-14 md:top-16 z-30 shadow-sm">
                <div className="w-full">
                    <div className="flex px-2 sm:px-4 py-4 justify-between md:justify-center items-center overflow-hidden">
                    {SECTIONS.map((section, idx) => {
                        const isActive = idx === currentSection;
                        const isCompleted = idx < currentSection;
                        return (
                        <div key={section.id} className="flex items-center flex-1 md:flex-none">
                            <div className="flex flex-col items-center gap-1.5 transition-all w-full">
                                <div className={`
                                    w-8 h-8 sm:w-9 sm:h-9 rounded-xl flex items-center justify-center text-[10px] sm:text-xs font-black transition-all duration-500
                                    ${isActive ? 'bg-slate-900 text-white shadow-xl scale-110' : isCompleted ? 'bg-emerald-100 text-emerald-600 border border-emerald-200' : 'bg-slate-100 text-slate-300'}
                                `}>
                                    {isCompleted ? '✓' : idx + 1}
                                </div>
                                <span className={`hidden sm:block text-[9px] uppercase font-black tracking-widest ${isActive ? 'text-slate-900' : 'text-slate-300'}`}>
                                    {section.title}
                                </span>
                            </div>
                            {idx < SECTIONS.length - 1 && (
                            <div className={`h-px flex-1 md:w-16 mx-1 sm:mx-3 ${isCompleted ? 'bg-emerald-400' : 'bg-slate-100'}`} />
                            )}
                        </div>
                        );
                    })}
                    </div>
                </div>
                <div className="sm:hidden flex items-center justify-center gap-2 py-2 bg-slate-900 text-white text-[9px] font-black uppercase tracking-[0.2em]">
                    Phase {currentSection + 1}: {SECTIONS[currentSection].label}
                </div>
            </div>

            <div className="flex-1 p-4 md:p-10 max-w-5xl mx-auto w-full">
                {currentSection === 0 && renderDetailsSection()}
                {currentSection === 1 && renderPhotosSection()}

                {activeModule === 'general' && currentSection === 2 && renderInspectionSection([INSPECTION_CATEGORIES.PPE, INSPECTION_CATEGORIES.DOCUMENTATION])}
                {activeModule === 'general' && currentSection === 3 && renderInspectionSection([INSPECTION_CATEGORIES.VEHICLE_EXTERIOR, INSPECTION_CATEGORIES.LIGHTS_ELECTRICAL])}
                {activeModule === 'general' && currentSection === 4 && renderInspectionSection([INSPECTION_CATEGORIES.MECHANICAL, INSPECTION_CATEGORIES.TRAILER])}

                {activeModule === 'petroleum' && currentSection === 2 && renderInspectionSection([PETROLEUM_CATEGORIES.TRUCK_EQUIPMENT])}
                {activeModule === 'petroleum' && currentSection === 3 && renderInspectionSection([PETROLEUM_CATEGORIES.TYRES, PETROLEUM_CATEGORIES.PPE_ID])}
                {activeModule === 'petroleum' && currentSection === 4 && renderInspectionSection([PETROLEUM_CATEGORIES.DOCUMENTS, PETROLEUM_CATEGORIES.ONBOARD])}

                {activeModule === 'petroleum_v2' && currentSection === 2 && renderInspectionSection([PETROLEUM_V2_CATEGORIES.PRIME_MOVER])}
                {activeModule === 'petroleum_v2' && currentSection === 3 && renderInspectionSection([PETROLEUM_V2_CATEGORIES.TRAILER_TANKS])}
                {activeModule === 'petroleum_v2' && currentSection === 4 && renderInspectionSection([PETROLEUM_V2_CATEGORIES.DRIVER, PETROLEUM_V2_CATEGORIES.SAFETY_SIGNS, PETROLEUM_V2_CATEGORIES.DOCUMENTS])}

                {activeModule === 'acid' && currentSection === 2 && renderInspectionSection([ACID_CATEGORIES.PPE])}
                {activeModule === 'acid' && currentSection === 3 && renderInspectionSection([ACID_CATEGORIES.VEHICLE])}
                {activeModule === 'acid' && currentSection === 4 && renderInspectionSection([ACID_CATEGORIES.SPILL_KIT, ACID_CATEGORIES.DOCUMENTATION])}

                {currentSection === 5 && renderSignaturesSection()}
                {currentSection === 6 && renderSummarySection()}
            </div>

            <footer className="bg-white border-t border-gray-200 p-4 sm:p-6 sticky bottom-0 z-30 shadow-2xl">
              <div className="max-w-5xl mx-auto flex justify-between gap-4">
                <button onClick={handleBack} className="flex-1 sm:flex-none px-6 py-3 rounded-xl border border-slate-200 font-bold text-slate-500 hover:bg-slate-50 transition-all text-xs uppercase tracking-widest">{currentSection === 0 ? 'Quit' : 'Back'}</button>
                <div className="flex gap-2 flex-1 justify-end">
                    <button onClick={() => onSaveDraft(formData)} className="px-6 py-3 rounded-xl border border-blue-200 bg-blue-50 text-blue-700 font-bold hover:bg-blue-100 transition-all flex items-center justify-center gap-2 text-xs uppercase tracking-widest">
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 7H5a2 2 0 00-2 2v9a2 2 0 002 2h14a2 2 0 002-2V9a2 2 0 00-2-2h-3m-1 4l-3 3m0 0l-3-3m3 3V4"></path></svg>
                        Draft
                    </button>
                    {currentSection < SECTIONS.length - 1 && (
                    <button onClick={handleNext} className="px-8 py-3 rounded-xl bg-slate-900 text-white font-black hover:bg-black shadow-xl transition-all flex items-center justify-center gap-2 text-xs uppercase tracking-widest">
                        Next
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M14 5l7 7m0 0l-7 7m7-7H3"></path></svg>
                    </button>
                    )}
                </div>
              </div>
            </footer>
        </div>
    );
};

