import { useState, useEffect, useRef } from 'react';
import { AppNotification, User } from '../types';

const MAX_NOTIFICATIONS = 50; 
const POLLING_INTERVAL = 90000; // Increased to 90 seconds to reduce server load

export const useNotifications = (appScriptUrl: string, currentUser: User | null, showToast: (msg: string, type: 'success' | 'error' | 'info') => void) => {
    const [notifications, setNotifications] = useState<AppNotification[]>([]);
    const [readNotificationIds, setReadNotificationIds] = useState<string[]>([]);
    const [dismissedNotificationIds, setDismissedNotificationIds] = useState<string[]>([]);
    const [globalAcknowledgedIds, setGlobalAcknowledgedIds] = useState<string[]>([]);
    const [notifiedIds, setNotifiedIds] = useState<string[]>([]); 
    const [pushEnabled, setPushEnabled] = useState(false);

    const pollingRef = useRef<number | null>(null);

    // 1. Initial State & Permissions
    useEffect(() => {
        if (!currentUser) {
            if (pollingRef.current) window.clearInterval(pollingRef.current);
            return;
        }

        const userPrefix = currentUser.username + '_';
        const savedRead = localStorage.getItem(`sc_read_notifications_${userPrefix}`);
        const savedDismissed = localStorage.getItem(`sc_dismissed_notifications_${userPrefix}`);

        if (savedRead) setReadNotificationIds(JSON.parse(savedRead));
        if (savedDismissed) setDismissedNotificationIds(JSON.parse(savedDismissed));

        if ('Notification' in window && Notification.permission === 'granted') {
            setPushEnabled(true);
        }

        // START POLLING
        fetchNotifications(); // Initial fetch

        // Setup visibility-aware polling
        const handleVisibilityChange = () => {
            if (document.visibilityState === 'visible') {
                // Instantly sync when user returns
                fetchNotifications();
                if (!pollingRef.current) {
                    pollingRef.current = window.setInterval(fetchNotifications, POLLING_INTERVAL);
                }
            } else {
                // Pause polling when tab is inactive to save resources
                if (pollingRef.current) {
                    window.clearInterval(pollingRef.current);
                    pollingRef.current = null;
                }
            }
        };

        document.addEventListener('visibilitychange', handleVisibilityChange);
        pollingRef.current = window.setInterval(fetchNotifications, POLLING_INTERVAL);

        return () => {
            if (pollingRef.current) window.clearInterval(pollingRef.current);
            document.removeEventListener('visibilitychange', handleVisibilityChange);
        };
    }, [currentUser, appScriptUrl]);

    const requestPushPermission = async () => {
        if (!('Notification' in window)) {
            showToast("This browser does not support system notifications.", "error");
            return false;
        }

        try {
            const permission = await Notification.requestPermission();
            if (permission === 'granted') {
                setPushEnabled(true);
                sendSystemNotification("Notifications Enabled", {
                    body: "You will now receive system alerts for critical inspection updates.",
                    icon: "https://cdn-icons-png.flaticon.com/512/716/716766.png"
                });
                return true;
            } else {
                setPushEnabled(false);
                return false;
            }
        } catch (e) {
            console.error("Permission request error", e);
            return false;
        }
    };

    const sendSystemNotification = (title: string, options: NotificationOptions) => {
        if (Notification.permission === 'granted') {
            try {
                if ('serviceWorker' in navigator && navigator.serviceWorker.ready) {
                    navigator.serviceWorker.ready.then(registration => {
                        registration.showNotification(title, options);
                    });
                } else {
                    new Notification(title, options);
                }
            } catch (e) {
                console.error("Notification trigger failed", e);
            }
        }
    };

    const saveReadState = (ids: string[]) => {
        if (!currentUser) return;
        const userPrefix = currentUser.username + '_';
        localStorage.setItem(`sc_read_notifications_${userPrefix}`, JSON.stringify(ids));
        setReadNotificationIds(ids);
    };

    const saveDismissedState = (ids: string[]) => {
        if (!currentUser) return;
        const userPrefix = currentUser.username + '_';
        localStorage.setItem(`sc_dismissed_notifications_${userPrefix}`, JSON.stringify(ids));
        setDismissedNotificationIds(ids);
    };

    const fetchNotifications = async () => {
        if (!appScriptUrl || typeof appScriptUrl !== 'string' || !appScriptUrl.startsWith('http')) return;
        if (!navigator.onLine || !currentUser) return;

        try {
            const response = await fetch(`${appScriptUrl}?t=${new Date().getTime()}`);
            if (!response.ok) return;

            const text = await response.text();
            if (!text || text.trim().startsWith('<')) return;

            let json;
            try {
                json = JSON.parse(text);
            } catch (parseErr) {
                return;
            }

            const serverAcknowledgements = json['Acknowledgements'] || [];
            setGlobalAcknowledgedIds(serverAcknowledgements);

            let allAlerts: AppNotification[] = [];

            // Persistence Helper: Check if already dismissed or globally resolved
            const isDismissed = (id: string) => dismissedNotificationIds.includes(id);
            const isRead = (id: string) => readNotificationIds.includes(id);

            // --- 1. Inspection Alerts Logic ---
            const processForAlerts = (rows: any[], type: string): AppNotification[] => {
                if (!Array.isArray(rows) || rows.length <= 1) return [];

                const rateIndex = type === 'General' ? 8 : 9;
                const truckIndex = 2;

                const alerts: AppNotification[] = [];
                // Only process recent history to reduce CPU/memory
                const recentRows = rows.slice(Math.max(1, rows.length - 100));

                recentRows.forEach((row: any[]) => {
                    const rate = Number(row[rateIndex]);
                    const truck = row[truckIndex] || 'Unknown Truck';
                    const timestamp = row[1]; 

                    // UNIQUE STABLE ID
                    const alertId = `${type}_${new Date(timestamp).getTime()}_${truck.replace(/\s/g, '')}`;

                    if (isDismissed(alertId)) return;
                    if (serverAcknowledgements.includes(alertId)) return;

                    if (rate <= 2) {
                        alerts.push({
                            id: alertId,
                            title: `Critical: ${truck}`,
                            message: `${type} Check rated ${rate}/5. Urgent attention needed.`,
                            type: 'critical',
                            timestamp: timestamp,
                            read: isRead(alertId),
                            module: type
                        });
                    } else if (rate === 3) {
                        alerts.push({
                            id: alertId,
                            title: `Warning: ${truck}`,
                            message: `${type} Check rated ${rate}/5. Maintenance review required.`,
                            type: 'warning',
                            timestamp: timestamp,
                            read: isRead(alertId),
                            module: type
                        });
                    }
                });
                return alerts;
            };

            // --- 2. System Notifications Sheet Logic ---
            const systemRows = json['SystemNotification'] || [];
            const userEmail = currentUser.username.toLowerCase().trim();
            const userRole = currentUser.role.toLowerCase().trim();

            if (Array.isArray(systemRows) && systemRows.length > 1) {
                systemRows.forEach((row: any[]) => {
                    const notifId = String(row[0]);

                    // Filter based on persistent dismissal first
                    if (isDismissed(notifId)) return;

                    const recipientId = String(row[1]).trim().toLowerCase();
                    const isReadOnServer = String(row[5]).toUpperCase() === 'TRUE';

                    const isForUser = recipientId === userEmail;
                    const isForRole = recipientId === userRole || (userRole === 'superadmin' && recipientId === 'admin');
                    const isForAll = recipientId === 'all';

                    if (!isReadOnServer && (isForUser || isForRole || isForAll)) {
                        const typeRaw = String(row[2]).toLowerCase();
                        let notifType: 'info' | 'critical' | 'warning' | 'success' = 'info';
                        if (typeRaw === 'critical') notifType = 'critical';
                        else if (typeRaw === 'warning') notifType = 'warning';
                        else if (typeRaw === 'success') notifType = 'success';

                        allAlerts.push({
                            id: notifId,
                            title: typeRaw === 'success' ? 'System Update' : 'Notification',
                            message: String(row[3]),
                            type: notifType,
                            timestamp: row[4],
                            read: isRead(notifId),
                            actionLink: row[6],
                            isServerEvent: true,
                            module: 'System'
                        });
                    }
                });
            }

            // --- 3. Support Ticket Sync Logic ---
            const ticketRows = json['Support_Tickets'] || [];
            if (Array.isArray(ticketRows) && ticketRows.length > 1) {
                ticketRows.slice(Math.max(1, ticketRows.length - 50)).forEach((row: any[]) => {
                    const ticketId = row[0];
                    const subject = row[2];
                    const status = row[9];
                    const assignedTo = row[11] ? String(row[11]) : null;
                    const isAssignedAgent = assignedTo && assignedTo.toLowerCase() === currentUser.name.toLowerCase();

                    const shouldSeeAsAdmin = (userRole === 'superadmin' || userRole === 'admin' || isAssignedAgent) && (status === 'Open' || status === 'In Progress');

                    if (shouldSeeAsAdmin) {
                        const alertId = `ticket_active_${ticketId}_${status}`;
                        if (!isDismissed(alertId)) {
                            allAlerts.push({
                                id: alertId,
                                title: status === 'Open' ? 'New Ticket' : 'Ticket In Progress',
                                message: `#${ticketId}: ${subject}`,
                                type: 'info',
                                timestamp: row[8],
                                read: isRead(alertId),
                                module: 'Support',
                                actionLink: 'view:support'
                            });
                        }
                    }
                });
            }

            // --- 4. Derive from Main Sheets ---
            if (json['General']) allAlerts = [...allAlerts, ...processForAlerts(json['General'], 'General')];
            if (json['Petroleum']) allAlerts = [...allAlerts, ...processForAlerts(json['Petroleum'], 'Petroleum')];
            if (json['Petroleum_V2']) allAlerts = [...allAlerts, ...processForAlerts(json['Petroleum_V2'], 'Petroleum_V2')];
            if (json['Acid']) allAlerts = [...allAlerts, ...processForAlerts(json['Acid'], 'Acid')];

            // SMART SORTING
            allAlerts.sort((a, b) => {
                const aScore = (a.read ? 0 : 2) + (a.type === 'critical' ? 1 : 0);
                const bScore = (b.read ? 0 : 2) + (b.type === 'critical' ? 1 : 0);
                if (aScore !== bScore) return bScore - aScore;
                return new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime();
            });

            if (allAlerts.length > MAX_NOTIFICATIONS) {
                allAlerts = allAlerts.slice(0, MAX_NOTIFICATIONS);
            }

            // TRIGGER TOASTS ONLY FOR NEW UNREAD
            const newlyFetched = allAlerts.filter(a => !notifiedIds.includes(a.id) && !a.read);
            if (newlyFetched.length > 0) {
                const latest = newlyFetched[0];
                if (latest.type === 'critical') showToast(latest.message, 'error');
                setNotifiedIds(prev => [...prev, ...newlyFetched.map(a => a.id)]);
            }

            setNotifications(allAlerts);

        } catch (e) {
            console.warn("Fetch notifications error", e);
        }
    };

    const handleMarkNotificationRead = async (id: string, onNavigate?: (module: string) => void) => {
        setNotifications(prev => prev.map(n => n.id === id ? {...n, read: true} : n));

        const target = notifications.find(n => n.id === id);
        if (target?.isServerEvent && appScriptUrl && navigator.onLine) {
            try {
                await fetch(appScriptUrl, {
                    method: 'POST',
                    body: JSON.stringify({ action: 'mark_notification_read', id: id }),
                    mode: 'no-cors'
                });
            } catch(e) {}
        }

        const newReadIds = [...new Set([...readNotificationIds, id])];
        saveReadState(newReadIds);

        if (target?.actionLink && onNavigate) {
            onNavigate(target.actionLink);
        }
    };

    const handleDismissNotification = (id: string) => {
        // Remove from active state
        setNotifications(prev => prev.filter(n => n.id !== id));
        // Persistent blacklist - this ID will never show up again for this user on this device
        const newDismissedIds = [...new Set([...dismissedNotificationIds, id])];
        saveDismissedState(newDismissedIds);
    };

    const handleGlobalAcknowledge = async (id: string) => {
        if (!appScriptUrl || !navigator.onLine) return;
        setNotifications(prev => prev.filter(n => n.id !== id));
        setGlobalAcknowledgedIds(prev => [...prev, id]);

        try {
            await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify({
                    action: 'acknowledge_issue',
                    issueId: id,
                    user: currentUser?.name || 'Unknown',
                    role: currentUser?.role || 'Unknown'
                }),
                mode: 'no-cors'
            });
            showToast("Resolved.", 'success');
        } catch (e) {}
    };

    const handleClearAllNotifications = () => {
        const allIds = notifications.map(n => n.id);
        const newReadIds = [...new Set([...readNotificationIds, ...allIds])];
        const newDismissedIds = [...new Set([...dismissedNotificationIds, ...allIds])];

        saveReadState(newReadIds);
        saveDismissedState(newDismissedIds);
        setNotifications([]);
    };

    return {
        notifications,
        fetchNotifications,
        handleMarkNotificationRead,
        handleDismissNotification,
        handleGlobalAcknowledge,
        handleClearAllNotifications,
        requestPushPermission,
        pushEnabled
    };
};

import { useState, useEffect, useRef, useCallback } from 'react';
import { AppNotification, User } from '../types';

const MAX_NOTIFICATIONS = 50; 
const POLLING_INTERVAL = 120000; // 2 minutes - Optimized for multi-user/high-concurrency environments

export const useNotifications = (appScriptUrl: string, currentUser: User | null, showToast: (msg: string, type: 'success' | 'error' | 'info') => void) => {
    const [notifications, setNotifications] = useState<AppNotification[]>([]);
    const [readNotificationIds, setReadNotificationIds] = useState<string[]>([]);
    const [dismissedNotificationIds, setDismissedNotificationIds] = useState<string[]>([]);
    const [globalAcknowledgedIds, setGlobalAcknowledgedIds] = useState<string[]>([]);
    const [notifiedIds, setNotifiedIds] = useState<string[]>([]); 
    const [pushEnabled, setPushEnabled] = useState(false);

    const pollingRef = useRef<number | null>(null);

    // Initial State Loader
    useEffect(() => {
        if (!currentUser) {
            if (pollingRef.current) window.clearInterval(pollingRef.current);
            return;
        }

        const userPrefix = currentUser.username.replace(/[^a-z0-9]/gi, '_') + '_';
        const savedRead = localStorage.getItem(`sc_read_notifications_${userPrefix}`);
        const savedDismissed = localStorage.getItem(`sc_dismissed_notifications_${userPrefix}`);

        if (savedRead) setReadNotificationIds(JSON.parse(savedRead));
        if (savedDismissed) setDismissedNotificationIds(JSON.parse(savedDismissed));

        if ('Notification' in window && Notification.permission === 'granted') {
            setPushEnabled(true);
        }

        fetchNotifications();

        // visibility-aware polling: Stop network calls when user isn't looking at the tab
        const handleVisibilityChange = () => {
            if (document.visibilityState === 'visible') {
                fetchNotifications();
                if (!pollingRef.current) {
                    pollingRef.current = window.setInterval(fetchNotifications, POLLING_INTERVAL);
                }
            } else {
                if (pollingRef.current) {
                    window.clearInterval(pollingRef.current);
                    pollingRef.current = null;
                }
            }
        };

        document.addEventListener('visibilitychange', handleVisibilityChange);
        pollingRef.current = window.setInterval(fetchNotifications, POLLING_INTERVAL);

        return () => {
            if (pollingRef.current) window.clearInterval(pollingRef.current);
            document.removeEventListener('visibilitychange', handleVisibilityChange);
        };
    }, [currentUser, appScriptUrl]);

    const saveReadState = (ids: string[]) => {
        if (!currentUser) return;
        const userPrefix = currentUser.username.replace(/[^a-z0-9]/gi, '_') + '_';
        localStorage.setItem(`sc_read_notifications_${userPrefix}`, JSON.stringify(ids));
        setReadNotificationIds(ids);
    };

    const saveDismissedState = (ids: string[]) => {
        if (!currentUser) return;
        const userPrefix = currentUser.username.replace(/[^a-z0-9]/gi, '_') + '_';
        localStorage.setItem(`sc_dismissed_notifications_${userPrefix}`, JSON.stringify(ids));
        setDismissedNotificationIds(ids);
    };

    const fetchNotifications = async () => {
        if (!appScriptUrl || !navigator.onLine || !currentUser) return;

        try {
            const response = await fetch(`${appScriptUrl}?t=${new Date().getTime()}`);
            if (!response.ok) return;

            const text = await response.text();
            if (!text || text.trim().startsWith('<')) return;

            let json;
            try {
                json = JSON.parse(text);
            } catch (parseErr) {
                return;
            }

            const serverAcknowledgements = json['Acknowledgements'] || [];
            setGlobalAcknowledgedIds(serverAcknowledgements);

            let allAlerts: AppNotification[] = [];

            // HELPER: Use local state for immediate filtering
            const isDismissed = (id: string) => dismissedNotificationIds.includes(id);
            const isRead = (id: string) => readNotificationIds.includes(id);

            // --- 1. Inspection Alerts Logic ---
            const processForAlerts = (rows: any[], type: string): AppNotification[] => {
                if (!Array.isArray(rows) || rows.length <= 1) return [];

                const rateIndex = type === 'General' ? 8 : 9;
                const truckIndex = 2;

                const alerts: AppNotification[] = [];
                // Only look at most recent 50 rows to reduce processing on large sheets
                const recentRows = rows.slice(Math.max(1, rows.length - 50));

                recentRows.forEach((row: any[]) => {
                    const rate = Number(row[rateIndex]);
                    const truck = String(row[truckIndex] || 'Unknown').trim();
                    const timestampRaw = String(row[1]); // Original raw string from sheet (STABLE ID)

                    // FIX: Create a stable ID that doesn't change with client-side date parsing
                    const alertId = `ALERT_${type}_${timestampRaw.replace(/[^a-z0-9]/gi, '')}_${truck.replace(/\s/g, '')}`;

                    if (isDismissed(alertId)) return;
                    if (serverAcknowledgements.includes(alertId)) return;

                    if (rate <= 2) {
                        alerts.push({
                            id: alertId,
                            title: `Critical: ${truck}`,
                            message: `${type} Check rated ${rate}/5. Attention needed.`,
                            type: 'critical',
                            timestamp: timestampRaw,
                            read: isRead(alertId),
                            module: type
                        });
                    } else if (rate === 3) {
                        alerts.push({
                            id: alertId,
                            title: `Warning: ${truck}`,
                            message: `${type} Check rated ${rate}/5. Review recommended.`,
                            type: 'warning',
                            timestamp: timestampRaw,
                            read: isRead(alertId),
                            module: type
                        });
                    }
                });
                return alerts;
            };

            // --- 2. System Notifications Sheet Logic ---
            const systemRows = json['SystemNotification'] || [];
            const userEmail = currentUser.username.toLowerCase().trim();
            const userRole = currentUser.role.toLowerCase().trim();

            if (Array.isArray(systemRows) && systemRows.length > 1) {
                systemRows.forEach((row: any[]) => {
                    const notifId = String(row[0]);
                    if (isDismissed(notifId)) return;

                    const recipientId = String(row[1]).trim().toLowerCase();
                    const isReadOnServer = String(row[5]).toUpperCase() === 'TRUE';

                    const isForUser = recipientId === userEmail;
                    const isForRole = recipientId === userRole || (userRole === 'superadmin' && recipientId === 'admin');
                    const isForAll = recipientId === 'all';

                    if (!isReadOnServer && (isForUser || isForRole || isForAll)) {
                        const typeRaw = String(row[2]).toLowerCase();
                        let notifType: 'info' | 'critical' | 'warning' | 'success' = 'info';
                        if (typeRaw === 'critical') notifType = 'critical';
                        else if (typeRaw === 'warning') notifType = 'warning';
                        else if (typeRaw === 'success') notifType = 'success';

                        allAlerts.push({
                            id: notifId,
                            title: typeRaw === 'success' ? 'System Update' : 'Broadcast',
                            message: String(row[3]),
                            type: notifType,
                            timestamp: row[4],
                            read: isRead(notifId),
                            actionLink: row[6],
                            isServerEvent: true,
                            module: 'System'
                        });
                    }
                });
            }

            // --- 3. Tickets ---
            const ticketRows = json['Support_Tickets'] || [];
            if (Array.isArray(ticketRows) && ticketRows.length > 1) {
                ticketRows.slice(Math.max(1, ticketRows.length - 20)).forEach((row: any[]) => {
                    const ticketId = row[0];
                    const status = row[9];
                    const alertId = `TKT_${ticketId}_${status}`;
                    if (isDismissed(alertId)) return;

                    const userRoleLower = currentUser.role.toLowerCase();
                    if ((userRoleLower === 'admin' || userRoleLower === 'superadmin') && (status === 'Open')) {
                        allAlerts.push({
                            id: alertId,
                            title: 'New Support Ticket',
                            message: `#${ticketId}: ${row[2]}`,
                            type: 'info',
                            timestamp: row[8],
                            read: isRead(alertId),
                            module: 'Support',
                            actionLink: 'view:support'
                        });
                    }
                });
            }

            if (json['General']) allAlerts = [...allAlerts, ...processForAlerts(json['General'], 'General')];
            if (json['Petroleum']) allAlerts = [...allAlerts, ...processForAlerts(json['Petroleum'], 'Petroleum')];
            if (json['Petroleum_V2']) allAlerts = [...allAlerts, ...processForAlerts(json['Petroleum_V2'], 'Petroleum_V2')];
            if (json['Acid']) allAlerts = [...allAlerts, ...processForAlerts(json['Acid'], 'Acid')];

            allAlerts.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
            if (allAlerts.length > MAX_NOTIFICATIONS) allAlerts = allAlerts.slice(0, MAX_NOTIFICATIONS);

            // Toast logic for new unread notifications
            const newlyFetched = allAlerts.filter(a => !notifiedIds.includes(a.id) && !a.read);
            if (newlyFetched.length > 0) {
                const latest = newlyFetched[0];
                if (latest.type === 'critical') showToast(latest.message, 'error');
                setNotifiedIds(prev => [...new Set([...prev, ...newlyFetched.map(a => a.id)])]);
            }

            setNotifications(allAlerts);

        } catch (e) {
            console.warn("Sync failed (silent)");
        }
    };

    const handleMarkNotificationRead = async (id: string, onNavigate?: (module: string) => void) => {
        setNotifications(prev => prev.map(n => n.id === id ? {...n, read: true} : n));
        const newReadIds = [...new Set([...readNotificationIds, id])];
        saveReadState(newReadIds);

        const target = notifications.find(n => n.id === id);
        if (target?.isServerEvent && appScriptUrl && navigator.onLine) {
            try {
                await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify({ action: 'mark_notification_read', id: id }), mode: 'no-cors' });
            } catch(e) {}
        }

        if (target?.actionLink && onNavigate) onNavigate(target.actionLink);
    };

    const handleDismissNotification = (id: string) => {
        // Immediate UI removal
        setNotifications(prev => prev.filter(n => n.id !== id));
        // Permanent persistent blacklist
        const newDismissedIds = [...new Set([...dismissedNotificationIds, id])];
        saveDismissedState(newDismissedIds);
    };

    const handleGlobalAcknowledge = async (id: string) => {
        if (!appScriptUrl || !navigator.onLine) return;
        setNotifications(prev => prev.filter(n => n.id !== id));
        setGlobalAcknowledgedIds(prev => [...prev, id]);

        // Ensure it's also dismissed locally
        const newDismissedIds = [...new Set([...dismissedNotificationIds, id])];
        saveDismissedState(newDismissedIds);

        try {
            await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify({ action: 'acknowledge_issue', issueId: id, user: currentUser?.name || 'Unknown', role: currentUser?.role || 'Unknown' }),
                mode: 'no-cors'
            });
            showToast("Issue Resolved.", 'success');
        } catch (e) {}
    };

    const handleClearAllNotifications = () => {
        const allIds = notifications.map(n => n.id);
        const newReadIds = [...new Set([...readNotificationIds, ...allIds])];
        const newDismissedIds = [...new Set([...dismissedNotificationIds, ...allIds])];

        saveReadState(newReadIds);
        saveDismissedState(newDismissedIds);
        setNotifications([]);
    };

    return {
        notifications,
        fetchNotifications,
        handleMarkNotificationRead,
        handleDismissNotification,
        handleGlobalAcknowledge,
        handleClearAllNotifications,
        requestPushPermission,
        pushEnabled
    };
};

