    }, [currentUser, appScriptUrl]);

    const saveReadState = (ids: string[]) => {
        if (!currentUser) return;
        const userPrefix = currentUser.username.replace(/[^a-z0-9]/gi, '_') + '_';
        localStorage.setItem(`sc_read_notifications_${userPrefix}`, JSON.stringify(ids));
        setReadNotificationIds(ids);
    };

    const saveDismissedState = (ids: string[]) => {
        if (!currentUser) return;
        const userPrefix = currentUser.username.replace(/[^a-z0-9]/gi, '_') + '_';
        localStorage.setItem(`sc_dismissed_notifications_${userPrefix}`, JSON.stringify(ids));
        setDismissedNotificationIds(ids);
    };

    const fetchNotifications = async () => {
        if (!appScriptUrl || !navigator.onLine || !currentUser) return;

        try {
            const response = await fetch(`${appScriptUrl}?t=${new Date().getTime()}`);
            if (!response.ok) return;

            const text = await response.text();
            if (!text || text.trim().startsWith('<')) return;

            let json;
            try {
                json = JSON.parse(text);
            } catch (parseErr) {
                return;
            }

            const serverAcknowledgements = json['Acknowledgements'] || [];
            setGlobalAcknowledgedIds(serverAcknowledgements);

            let allAlerts: AppNotification[] = [];

            // HELPER: Use local state for immediate filtering
            const isDismissed = (id: string) => dismissedNotificationIds.includes(id);
            const isRead = (id: string) => readNotificationIds.includes(id);

            // --- 1. Inspection Alerts Logic ---
            const processForAlerts = (rows: any[], type: string): AppNotification[] => {
                if (!Array.isArray(rows) || rows.length <= 1) return [];

                const rateIndex = type === 'General' ? 8 : 9;
                const truckIndex = 2;

                const alerts: AppNotification[] = [];
                // Only look at most recent 50 rows to reduce processing on large sheets
                const recentRows = rows.slice(Math.max(1, rows.length - 50));

                recentRows.forEach((row: any[]) => {
                    const rate = Number(row[rateIndex]);
                    const truck = String(row[truckIndex] || 'Unknown').trim();
                    const timestampRaw = String(row[1]); // Original raw string from sheet (STABLE ID)

                    // FIX: Create a stable ID that doesn't change with client-side date parsing
                    const alertId = `ALERT_${type}_${timestampRaw.replace(/[^a-z0-9]/gi, '')}_${truck.replace(/\s/g, '')}`;

                    if (isDismissed(alertId)) return;
                    if (serverAcknowledgements.includes(alertId)) return;

                    if (rate <= 2) {
                        alerts.push({
                            id: alertId,
                            title: `Critical: ${truck}`,
                            message: `${type} Check rated ${rate}/5. Attention needed.`,
                            type: 'critical',
                            timestamp: timestampRaw,
                            read: isRead(alertId),
                            module: type
                        });
                    } else if (rate === 3) {
                        alerts.push({
                            id: alertId,
                            title: `Warning: ${truck}`,
                            message: `${type} Check rated ${rate}/5. Review recommended.`,
                            type: 'warning',
                            timestamp: timestampRaw,
                            read: isRead(alertId),
                            module: type
                        });
                    }
                });
                return alerts;
            };

            // --- 2. System Notifications Sheet Logic ---
            const systemRows = json['SystemNotification'] || [];
            const userEmail = currentUser.username.toLowerCase().trim();
            const userRole = currentUser.role.toLowerCase().trim();

            if (Array.isArray(systemRows) && systemRows.length > 1) {
                systemRows.forEach((row: any[]) => {
                    const notifId = String(row[0]);
                    if (isDismissed(notifId)) return;

                    const recipientId = String(row[1]).trim().toLowerCase();
                    const isReadOnServer = String(row[5]).toUpperCase() === 'TRUE';

                    const isForUser = recipientId === userEmail;
                    const isForRole = recipientId === userRole || (userRole === 'superadmin' && recipientId === 'admin');
                    const isForAll = recipientId === 'all';

                    if (!isReadOnServer && (isForUser || isForRole || isForAll)) {
                        const typeRaw = String(row[2]).toLowerCase();
                        let notifType: 'info' | 'critical' | 'warning' | 'success' = 'info';
                        if (typeRaw === 'critical') notifType = 'critical';
                        else if (typeRaw === 'warning') notifType = 'warning';
                        else if (typeRaw === 'success') notifType = 'success';

                        allAlerts.push({
                            id: notifId,
                            title: typeRaw === 'success' ? 'System Update' : 'Broadcast',
                            message: String(row[3]),
                            type: notifType,
                            timestamp: row[4],
                            read: isRead(notifId),
                            actionLink: row[6],
                            isServerEvent: true,
                            module: 'System'
                        });
                    }
                });
            }

            // --- 3. Tickets ---
            const ticketRows = json['Support_Tickets'] || [];
            if (Array.isArray(ticketRows) && ticketRows.length > 1) {
                ticketRows.slice(Math.max(1, ticketRows.length - 20)).forEach((row: any[]) => {
                    const ticketId = row[0];
                    const status = row[9];
                    const alertId = `TKT_${ticketId}_${status}`;
                    if (isDismissed(alertId)) return;

                    const userRoleLower = currentUser.role.toLowerCase();
                    if ((userRoleLower === 'admin' || userRoleLower === 'superadmin') && (status === 'Open')) {
                        allAlerts.push({
                            id: alertId,
                            title: 'New Support Ticket',
                            message: `#${ticketId}: ${row[2]}`,
                            type: 'info',
                            timestamp: row[8],
                            read: isRead(alertId),
                            module: 'Support',
                            actionLink: 'view:support'
                        });
                    }
                });
            }

            if (json['General']) allAlerts = [...allAlerts, ...processForAlerts(json['General'], 'General')];
            if (json['Petroleum']) allAlerts = [...allAlerts, ...processForAlerts(json['Petroleum'], 'Petroleum')];
            if (json['Petroleum_V2']) allAlerts = [...allAlerts, ...processForAlerts(json['Petroleum_V2'], 'Petroleum_V2')];
            if (json['Acid']) allAlerts = [...allAlerts, ...processForAlerts(json['Acid'], 'Acid')];

            allAlerts.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
            if (allAlerts.length > MAX_NOTIFICATIONS) allAlerts = allAlerts.slice(0, MAX_NOTIFICATIONS);

            // Toast logic for new unread notifications
            const newlyFetched = allAlerts.filter(a => !notifiedIds.includes(a.id) && !a.read);
            if (newlyFetched.length > 0) {
                const latest = newlyFetched[0];
                if (latest.type === 'critical') showToast(latest.message, 'error');
                setNotifiedIds(prev => [...new Set([...prev, ...newlyFetched.map(a => a.id)])]);
            }

            setNotifications(allAlerts);

        } catch (e) {
            console.warn("Sync failed (silent)");
        }
    };

    const handleMarkNotificationRead = async (id: string, onNavigate?: (module: string) => void) => {
        setNotifications(prev => prev.map(n => n.id === id ? {...n, read: true} : n));
        const newReadIds = [...new Set([...readNotificationIds, id])];
        saveReadState(newReadIds);

        const target = notifications.find(n => n.id === id);
        if (target?.isServerEvent && appScriptUrl && navigator.onLine) {
            try {
                await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify({ action: 'mark_notification_read', id: id }), mode: 'no-cors' });
            } catch(e) {}
        }

        if (target?.actionLink && onNavigate) onNavigate(target.actionLink);
    };

    const handleDismissNotification = (id: string) => {
        // Immediate UI removal
        setNotifications(prev => prev.filter(n => n.id !== id));
        // Permanent persistent blacklist
        const newDismissedIds = [...new Set([...dismissedNotificationIds, id])];
        saveDismissedState(newDismissedIds);
    };

    const handleGlobalAcknowledge = async (id: string) => {
        if (!appScriptUrl || !navigator.onLine) return;
        setNotifications(prev => prev.filter(n => n.id !== id));
        setGlobalAcknowledgedIds(prev => [...prev, id]);

        // Ensure it's also dismissed locally
        const newDismissedIds = [...new Set([...dismissedNotificationIds, id])];
        saveDismissedState(newDismissedIds);

        try {
            await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify({ action: 'acknowledge_issue', issueId: id, user: currentUser?.name || 'Unknown', role: currentUser?.role || 'Unknown' }),
                mode: 'no-cors'
            });
            showToast("Issue Resolved.", 'success');
        } catch (e) {}
    };

    const handleClearAllNotifications = () => {
        const allIds = notifications.map(n => n.id);
        const newReadIds = [...new Set([...readNotificationIds, ...allIds])];
        const newDismissedIds = [...new Set([...dismissedNotificationIds, ...allIds])];

        saveReadState(newReadIds);
        saveDismissedState(newDismissedIds);
        setNotifications([]);
    };

    // Fix: Added missing requestPushPermission implementation
    const requestPushPermission = async () => {
        if (!('Notification' in window)) return;
        const permission = await Notification.requestPermission();
        if (permission === 'granted') {
            setPushEnabled(true);
        }
    };

    return {
        notifications,
        fetchNotifications,
        handleMarkNotificationRead,
        handleDismissNotification,
        handleGlobalAcknowledge,
        handleClearAllNotifications,
        requestPushPermission,
        pushEnabled
    };
};

import { useState, useEffect, useRef } from 'react';
import { AppNotification, User } from '../types';

const MAX_NOTIFICATIONS = 50; 
const POLLING_INTERVAL = 120000; // 2 minutes

export const useNotifications = (appScriptUrl: string, currentUser: User | null, showToast: (msg: string, type: 'success' | 'error' | 'info' | 'warning') => void) => {
    const [notifications, setNotifications] = useState<AppNotification[]>([]);
    const [readNotificationIds, setReadNotificationIds] = useState<string[]>([]);
    const [dismissedNotificationIds, setDismissedNotificationIds] = useState<string[]>([]);
    const [notifiedIds, setNotifiedIds] = useState<string[]>([]); 
    const [pushEnabled, setPushEnabled] = useState(false);

    // CRITICAL: Use Refs for background polling to avoid stale closures
    const dismissedRef = useRef<string[]>([]);
    const readRef = useRef<string[]>([]);
    const pollingRef = useRef<number | null>(null);

    // Sync state to refs whenever state updates
    useEffect(() => {
        dismissedRef.current = dismissedNotificationIds;
    }, [dismissedNotificationIds]);

    useEffect(() => {
        readRef.current = readNotificationIds;
    }, [readNotificationIds]);

    // Initial Load & Polling Setup
    useEffect(() => {
        if (!currentUser) {
            if (pollingRef.current) window.clearInterval(pollingRef.current);
            return;
        }

        const userPrefix = currentUser.username.replace(/[^a-z0-9]/gi, '_') + '_';
        const savedRead = localStorage.getItem(`sc_read_notifications_${userPrefix}`);
        const savedDismissed = localStorage.getItem(`sc_dismissed_notifications_${userPrefix}`);

        const initialRead = savedRead ? JSON.parse(savedRead) : [];
        const initialDismissed = savedDismissed ? JSON.parse(savedDismissed) : [];

        setReadNotificationIds(initialRead);
        setDismissedNotificationIds(initialDismissed);
        readRef.current = initialRead;
        dismissedRef.current = initialDismissed;

        if ('Notification' in window && Notification.permission === 'granted') {
            setPushEnabled(true);
        }

        fetchNotifications();

        const handleVisibilityChange = () => {
            if (document.visibilityState === 'visible') {
                fetchNotifications();
                if (!pollingRef.current) {
                    pollingRef.current = window.setInterval(fetchNotifications, POLLING_INTERVAL);
                }
            } else {
                if (pollingRef.current) {
                    window.clearInterval(pollingRef.current);
                    pollingRef.current = null;
                }
            }
        };

        document.addEventListener('visibilitychange', handleVisibilityChange);
        pollingRef.current = window.setInterval(fetchNotifications, POLLING_INTERVAL);

        return () => {
            if (pollingRef.current) window.clearInterval(pollingRef.current);
            document.removeEventListener('visibilitychange', handleVisibilityChange);
        };
    }, [currentUser, appScriptUrl]);

    const saveReadState = (ids: string[]) => {
        if (!currentUser) return;
        const userPrefix = currentUser.username.replace(/[^a-z0-9]/gi, '_') + '_';
        localStorage.setItem(`sc_read_notifications_${userPrefix}`, JSON.stringify(ids));
        setReadNotificationIds(ids);
    };

    const saveDismissedState = (ids: string[]) => {
        if (!currentUser) return;
        const userPrefix = currentUser.username.replace(/[^a-z0-9]/gi, '_') + '_';
        localStorage.setItem(`sc_dismissed_notifications_${userPrefix}`, JSON.stringify(ids));
        setDismissedNotificationIds(ids);
    };

    const fetchNotifications = async () => {
        if (!appScriptUrl || !navigator.onLine || !currentUser) return;

        try {
            const response = await fetch(`${appScriptUrl}?t=${Date.now()}`);
            if (!response.ok) return;

            const text = await response.text();
            if (!text || text.trim().startsWith('<')) return;

            const json = JSON.parse(text);
            const serverAcknowledgements = json['Acknowledgements'] || [];

            let allAlerts: AppNotification[] = [];

            // Check against REF (the absolute latest list)
            const isDismissed = (id: string) => dismissedRef.current.includes(id);
            const isRead = (id: string) => readRef.current.includes(id);

            // --- 1. Inspection Alerts Logic ---
            const processForAlerts = (rows: any[], type: string): AppNotification[] => {
                if (!Array.isArray(rows) || rows.length <= 1) return [];
                const rateIndex = type === 'General' ? 8 : 9;
                const truckIndex = 2;

                const alerts: AppNotification[] = [];
                const recentRows = rows.slice(Math.max(1, rows.length - 60));

                recentRows.forEach((row: any[]) => {
                    const rate = Number(row[rateIndex]);
                    const truck = String(row[truckIndex] || 'Unknown').trim();
                    const tsRaw = String(row[1]); 

                    // NORMALIZED STABLE ID (Prevents reappearances if date format shifts)
                    const cleanTs = tsRaw.replace(/[^0-9]/g, '');
                    const alertId = `INS_${type}_${cleanTs}_${truck.replace(/[^a-z0-9]/gi, '')}`;

                    if (isDismissed(alertId) || serverAcknowledgements.includes(alertId)) return;

                    if (rate <= 2 || rate === 3) {
                        alerts.push({
                            id: alertId,
                            title: rate <= 2 ? `Critical: ${truck}` : `Warning: ${truck}`,
                            message: `${type} check rated ${rate}/5.`,
                            type: rate <= 2 ? 'critical' : 'warning',
                            timestamp: tsRaw,
                            read: isRead(alertId),
                            module: type
                        });
                    }
                });
                return alerts;
            };

            // --- 2. System Notifications ---
            const systemRows = json['SystemNotification'] || [];
            const userEmail = currentUser.username.toLowerCase().trim();
            const userRole = currentUser.role.toLowerCase().trim();

            if (Array.isArray(systemRows) && systemRows.length > 1) {
                systemRows.forEach((row: any[]) => {
                    const notifId = String(row[0]);
                    if (isDismissed(notifId)) return;

                    const recipientId = String(row[1]).trim().toLowerCase();
                    const isReadOnServer = String(row[5]).toUpperCase() === 'TRUE';

                    const isForUser = recipientId === userEmail;
                    const isForRole = recipientId === userRole || (userRole === 'superadmin' && recipientId === 'admin');
                    const isForAll = recipientId === 'all';

                    if (!isReadOnServer && (isForUser || isForRole || isForAll)) {
                        allAlerts.push({
                            id: notifId,
                            title: 'System Message',
                            message: String(row[3]),
                            type: String(row[2]).toLowerCase() as any || 'info',
                            timestamp: row[4],
                            read: isRead(notifId),
                            actionLink: row[6],
                            isServerEvent: true,
                            module: 'System'
                        });
                    }
                });
            }

            // --- 3. Tickets ---
            const ticketRows = json['Support_Tickets'] || [];
            if (Array.isArray(ticketRows) && ticketRows.length > 1) {
                ticketRows.slice(Math.max(1, ticketRows.length - 30)).forEach((row: any[]) => {
                    const ticketId = row[0];
                    const status = row[9];
                    // STABLE TICKET ID (status changes shouldn't revive a dismissed alert for the same ticket)
                    const alertId = `TKT_ALERT_${ticketId}`; 

                    if (isDismissed(alertId)) return;

                    if ((userRole === 'admin' || userRole === 'superadmin') && status === 'Open') {
                        allAlerts.push({
                            id: alertId,
                            title: 'New Ticket',
                            message: `#${ticketId}: ${row[2]}`,
                            type: 'info',
                            timestamp: row[8],
                            read: isRead(alertId),
                            module: 'Support',
                            actionLink: 'view:support'
                        });
                    }
                });
            }

            if (json['General']) allAlerts = [...allAlerts, ...processForAlerts(json['General'], 'General')];
            if (json['Petroleum']) allAlerts = [...allAlerts, ...processForAlerts(json['Petroleum'], 'Petroleum')];
            if (json['Petroleum_V2']) allAlerts = [...allAlerts, ...processForAlerts(json['Petroleum_V2'], 'Petroleum_V2')];
            if (json['Acid']) allAlerts = [...allAlerts, ...processForAlerts(json['Acid'], 'Acid')];

            allAlerts.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
            if (allAlerts.length > MAX_NOTIFICATIONS) allAlerts = allAlerts.slice(0, MAX_NOTIFICATIONS);

            // Toast only for truly new unread items
            const newUnread = allAlerts.filter(a => !notifiedIds.includes(a.id) && !a.read);
            if (newUnread.length > 0) {
                if (newUnread[0].type === 'critical') showToast(newUnread[0].message, 'error');
                setNotifiedIds(prev => [...new Set([...prev, ...newUnread.map(a => a.id)])]);
            }

            setNotifications(allAlerts);
        } catch (e) {}
    };

    const handleMarkNotificationRead = async (id: string, onNavigate?: (module: string) => void) => {
        setNotifications(prev => prev.map(n => n.id === id ? {...n, read: true} : n));
        const newReadIds = [...new Set([...readRef.current, id])];
        saveReadState(newReadIds);

        const target = notifications.find(n => n.id === id);
        if (target?.isServerEvent && appScriptUrl && navigator.onLine) {
            try {
                await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify({ action: 'mark_notification_read', id: id }), mode: 'no-cors' });
            } catch(e) {}
        }
        if (target?.actionLink && onNavigate) onNavigate(target.actionLink);
    };

    const handleDismissNotification = (id: string) => {
        setNotifications(prev => prev.filter(n => n.id !== id));
        const newDismissedIds = [...new Set([...dismissedRef.current, id])];
        saveDismissedState(newDismissedIds);
    };

    const handleGlobalAcknowledge = async (id: string) => {
        if (!appScriptUrl || !navigator.onLine) return;
        setNotifications(prev => prev.filter(n => n.id !== id));
        const newDismissedIds = [...new Set([...dismissedRef.current, id])];
        saveDismissedState(newDismissedIds);

        try {
            await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify({ action: 'acknowledge_issue', issueId: id, user: currentUser?.name, role: currentUser?.role }),
                mode: 'no-cors'
            });
            showToast("Acknowledge recorded.", 'success');
        } catch (e) {}
    };

    const handleClearAllNotifications = () => {
        const allIds = notifications.map(n => n.id);
        const newDismissedIds = [...new Set([...dismissedRef.current, ...allIds])];
        saveDismissedState(newDismissedIds);
        setNotifications([]);
    };

    const requestPushPermission = async () => {
        if (!('Notification' in window)) return;
        const permission = await Notification.requestPermission();
        if (permission === 'granted') setPushEnabled(true);
    };

    return {
        notifications,
        fetchNotifications,
        handleMarkNotificationRead,
        handleDismissNotification,
        handleGlobalAcknowledge,
        handleClearAllNotifications,
        requestPushPermission,
        pushEnabled
    };
};

import React, { useState, useEffect } from 'react';
import { INITIAL_DATA, InspectionData, User } from './types';
import { 
    SHEET_HEADERS, PETROLEUM_HEADERS, PETROLEUM_V2_HEADERS, ACID_HEADERS,
    INSPECTION_ITEMS, PETROLEUM_INSPECTION_ITEMS, PETROLEUM_V2_ITEMS, ACID_INSPECTION_ITEMS
} from './constants';

// Hooks
import { useAuth } from './hooks/useAuth';
import { useSettings } from './hooks/useSettings';
import { useNotifications } from './hooks/useNotifications';
import { useHistory } from './hooks/useHistory';
import { useOfflineSync } from './hooks/useOfflineSync';
import { useSubscription } from './hooks/useSubscription';

// UI Components
import Toast from './components/ui/Toast';
import ReportViewerModal from './components/ui/ReportViewerModal';
import SubmissionOverlay from './components/ui/SubmissionOverlay';
import ProfileModal from './components/ui/ProfileModal';
import NotificationCenter from './components/ui/NotificationCenter'; 
import UpgradeModal from './components/ui/UpgradeModal';
import InspectionStartModal from './components/ui/InspectionStartModal';
import SubscriptionAlert from './components/ui/SubscriptionAlert';
import MaintenanceOverlay from './components/ui/MaintenanceOverlay';
import RequestInspectionModal from './components/ui/RequestInspectionModal'; 
import OnboardingWizard from './components/ui/OnboardingWizard'; 
import SystemTour from './components/ui/SystemTour'; 
import InstallPwaPrompt from './components/ui/InstallPwaPrompt';

// Views
import LoginView from './views/LoginView';
import SettingsView from './views/SettingsView';
import GeneralDashboard from './views/GeneralDashboard';
import PetroleumDashboard from './views/PetroleumDashboard';
import PetroleumV2Dashboard from './views/PetroleumV2Dashboard';
import AcidDashboard from './views/AcidDashboard';
import UserManagementView from './views/UserManagementView';
import OverviewDashboard from './views/OverviewDashboard';
import InspectionFormView from './views/InspectionFormView';
import SupportView from './views/SupportView';
import MaintenanceView from './views/MaintenanceView';
import RequestTrackingView from './views/RequestTrackingView';

// Report Components
import PrintableGeneralReport from './components/reports/PrintableGeneralReport';
import PrintablePetroleumReport from './components/reports/PrintablePetroleumReport';
import PrintablePetroleumV2Report from './components/reports/PrintablePetroleumV2Report';
import PrintableAcidReport from './components/reports/PrintableAcidReport';

const App = () => {
  const { currentUser, setCurrentUser, handleLogin, handleLogout, sessionExpired, setSessionExpired } = useAuth();
  const { settings, setSettings, appScriptUrl, setAppScriptUrl, isSavingSettings, handleSaveSettings } = useSettings();
  const { subscription } = useSubscription(appScriptUrl, currentUser);

  const [activeModule, setActiveModule] = useState('overview'); 
  const [viewMode, setViewMode] = useState<'dashboard' | 'form'>('dashboard');
  const [isProfileModalOpen, setIsProfileModalOpen] = useState(false);
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error' | 'info' | 'warning'} | null>(null);
  const [isRequestModalOpen, setIsRequestModalOpen] = useState(false);
  const [showTour, setShowTour] = useState(false);

  const { historyList, isLoadingHistory, validationLists, stats, fetchHistory } = useHistory(appScriptUrl, activeModule, currentUser);

  const showToast = (message: string, type: 'success' | 'error' | 'info' | 'warning') => {
      setToast({ message, type });
      setTimeout(() => setToast(null), 4000);
  };

  useEffect(() => {
      if (sessionExpired === 'idle') showToast("Session expired due to inactivity.", 'warning');
      else if (sessionExpired === 'max_duration') showToast("Session limit reached. Log in again.", 'info');
      if (sessionExpired) setSessionExpired(null);
  }, [sessionExpired]);

  const { submissionStatus, setSubmissionStatus, isSyncing, addToQueue } = useOfflineSync(appScriptUrl, showToast, () => fetchHistory(true));

  const handleNavigate = (module: string) => {
    // Check if it's a deep link request from notifications
    if (module.startsWith('request:start_inspection')) {
        const parts = module.split('|');
        const type = parts[1]?.toLowerCase();
        const truck = parts[2];
        const trailer = parts[3];
        const requester = parts[4];
        const reason = parts[5];

        let moduleKey = 'general';
        if (type === 'petroleum') moduleKey = 'petroleum';
        else if (type === 'petroleum_v2') moduleKey = 'petroleum_v2';
        else if (type === 'acid') moduleKey = 'acid';

        setActiveModule(moduleKey);
        startFreshInspection(moduleKey, {
            truckNo: truck,
            trailerNo: trailer,
            remarks: `Requested by ${requester}: ${reason}`,
            requestId: parts[0].split('-')[1] // REQ ID
        });
        return;
    }

    setActiveModule(module);
    setViewMode('dashboard');
  };

  const { notifications, handleMarkNotificationRead, handleDismissNotification, handleClearAllNotifications, handleGlobalAcknowledge } = useNotifications(appScriptUrl, currentUser, showToast);

  const [isReportModalOpen, setIsReportModalOpen] = useState(false);
  const [selectedReportData, setSelectedReportData] = useState<InspectionData | null>(null);
  const [formInitialData, setFormInitialData] = useState<InspectionData>(INITIAL_DATA);

  const isAdmin = currentUser?.role === 'Admin' || currentUser?.role === 'SuperAdmin';
  const isSuperAdmin = currentUser?.role === 'SuperAdmin';
  const showMaintenance = settings.maintenanceMode && currentUser && !isSuperAdmin;

  const startFreshInspection = (module: string, prefill?: Partial<InspectionData>) => {
      setFormInitialData({ ...INITIAL_DATA, timestamp: new Date().toISOString(), inspectedBy: currentUser?.name || '', ...prefill });
      setViewMode('form');
  };

  const handleExitForm = (savedData?: InspectionData) => setViewMode('dashboard');

  const handleGoogleSheetSubmit = async (formData: InspectionData) => {
    if (!appScriptUrl) {
        showToast("Server URL not configured", "error");
        return;
    }

    setSubmissionStatus('submitting');

    let sheetName = 'General';
    let headers = SHEET_HEADERS;
    let moduleTitle = "General Vehicle Inspection";
    let activeItems = INSPECTION_ITEMS;

    if (activeModule === 'petroleum') { 
        sheetName = 'Petroleum'; 
        headers = PETROLEUM_HEADERS; 
        moduleTitle = "Petroleum Tanker Inspection";
        activeItems = PETROLEUM_INSPECTION_ITEMS;
    }
    else if (activeModule === 'petroleum_v2') { 
        sheetName = 'Petroleum_V2'; 
        headers = PETROLEUM_V2_HEADERS; 
        moduleTitle = "Petroleum Tanker Inspection V2";
        activeItems = PETROLEUM_V2_ITEMS;
    }
    else if (activeModule === 'acid') { 
        sheetName = 'Acid'; 
        headers = ACID_HEADERS; 
        moduleTitle = "Acid Tanker Inspection";
        activeItems = ACID_INSPECTION_ITEMS;
    }

    const row = headers.map(h => formData[h] !== undefined ? formData[h] : "");

    const reportData = {
        title: moduleTitle,
        timestamp: formData.timestamp,
        truckNo: formData.truckNo,
        trailerNo: formData.trailerNo,
        jobCard: formData.jobCard,
        location: formData.location,
        odometer: formData.odometer,
        inspectedBy: formData.inspectedBy,
        driverName: formData.driverName,
        remarks: formData.remarks,
        rate: formData.rate,
        signatures: {
            inspector: formData.inspectorSignature,
            driver: formData.driverSignature
        },
        photos: {
            front: formData.photoFront,
            ls: formData.photoLS,
            rs: formData.photoRS,
            back: formData.photoBack,
            damage: formData.photoDamage
        },
        items: activeItems.map(item => ({
            label: item.label,
            category: item.category,
            status: formData[item.id] || 'N/A'
        })),
        companyName: settings.companyName,
        companyLogo: settings.companyLogo
    };

    const payload = {
        action: 'create',
        sheet: sheetName,
        headers: headers,
        row: row,
        requestId: formData.requestId || null,
        reportData: reportData 
    };

    if (!navigator.onLine) {
        addToQueue(payload);
        setSubmissionStatus('offline_saved');
        setTimeout(() => {
            setSubmissionStatus('idle');
            setViewMode('dashboard');
        }, 3500);
        return;
    }

    try {
        await fetch(appScriptUrl, {
            method: 'POST',
            body: JSON.stringify(payload),
            mode: 'no-cors' 
        });

        setSubmissionStatus('success');
        fetchHistory(true); 

        setTimeout(() => {
            setSubmissionStatus('idle');
            setViewMode('dashboard');
        }, 3000);

    } catch (error) {
        console.error("Submission error", error);
        addToQueue(payload);
        setSubmissionStatus('offline_saved');
        setTimeout(() => {
            setSubmissionStatus('idle');
            setViewMode('dashboard');
        }, 3500);
    }
  };

  const handleRequestSubmit = async (data: any) => {
      if (!appScriptUrl) return;
      try {
          await fetch(appScriptUrl, {
              method: 'POST',
              body: JSON.stringify({
                  action: 'request_inspection',
                  requester: currentUser?.name,
                  role: currentUser?.role,
                  ...data
              }),
              mode: 'no-cors'
          });
          showToast("Inspection Request submitted successfully", "success");
      } catch (e) {
          showToast("Failed to submit request", "error");
      }
  };

  const handleViewReport = (item: InspectionData | null) => {
    setSelectedReportData(item);
    setIsReportModalOpen(true);
  };

  const handleOnboardingComplete = (updatedUser: User) => {
      const userWithSetup = { ...updatedUser, needsSetup: false };
      setCurrentUser(userWithSetup);
      localStorage.setItem('safetyCheck_user', JSON.stringify(userWithSetup));
      setActiveModule('overview');
      setViewMode('dashboard');
      showToast("Profile updated successfully.", "success");
      setShowTour(true);
  };

  const isAtRoot = activeModule === 'overview';

  if (!currentUser) {
      return (
          <>
            <InstallPwaPrompt />
            {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
            <LoginView 
                onLogin={handleLogin} 
                appScriptUrl={appScriptUrl}
                setAppScriptUrl={setAppScriptUrl}
                settings={settings}
            />
          </>
      );
  }

  if (currentUser && (currentUser as any).needsSetup) {
      return (
          <OnboardingWizard 
            user={currentUser} 
            appScriptUrl={appScriptUrl} 
            onComplete={handleOnboardingComplete} 
          />
      );
  }

  if (showMaintenance) {
      return (
        <>
           <MaintenanceOverlay isActive={true} message={settings.maintenanceMessage || ''} onLogout={() => handleLogout()} />
           {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
        </>
      );
  }

  return (
    <div className="min-h-screen bg-white font-sans text-gray-900 relative">
      <SubmissionOverlay status={submissionStatus} />
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      {showTour && <SystemTour onComplete={() => setShowTour(false)} />}

      {isProfileModalOpen && (
          <ProfileModal 
            user={currentUser} 
            settings={settings}
            appScriptUrl={appScriptUrl} 
            onClose={() => setIsProfileModalOpen(false)} 
            showToast={showToast} 
            onUpdateSuccess={(u) => setCurrentUser(u)} 
            onLogout={() => { setIsProfileModalOpen(false); handleLogout(); }}
          />
      )}

      <RequestInspectionModal
          isOpen={isRequestModalOpen}
          onClose={() => setIsRequestModalOpen(false)}
          onSubmit={handleRequestSubmit}
          validationLists={validationLists}
          currentUserRole={currentUser.role}
      />

      <div className="relative z-10 min-h-screen flex flex-col">
          <div className="no-print">
            <SubscriptionAlert subscription={subscription} user={currentUser} onManage={() => setActiveModule('settings')} />
          </div>

          <header className="bg-white border-b border-gray-100 sticky top-0 z-40 px-4 py-2 flex items-center justify-between h-14 no-print">
              <div className="flex items-center gap-1 sm:gap-2">
                  {!isAtRoot ? (
                      <button 
                          onClick={() => { setActiveModule('overview'); setViewMode('dashboard'); }}
                          title="Back to Overview"
                          className="p-2 text-slate-900 hover:bg-slate-50 rounded-lg transition-all flex items-center group"
                      >
                          <svg className="w-5 h-5 transition-transform group-hover:-translate-x-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M15 19l-7-7 7-7"></path></svg>
                          <span className="text-[10px] font-bold uppercase tracking-widest ml-1 hidden sm:inline">Back</span>
                      </button>
                  ) : (
                      <div className="w-10"></div>
                  )}
              </div>

              <button 
                  onClick={() => { setActiveModule('overview'); setViewMode('dashboard'); }}
                  className="flex flex-col items-center hover:opacity-70 transition-opacity"
              >
                  <h1 className="text-lg font-bold text-slate-900 tracking-tight leading-none uppercase">
                      {settings.companyName || 'SafetyCheck Pro'}
                  </h1>
                  <span className="text-[7px] font-bold text-slate-400 tracking-[0.3em] mt-1 uppercase">Fleet Portal</span>
              </button>

              <div className="flex items-center gap-1">
                  <NotificationCenter 
                      id="notification-bell"
                      notifications={notifications}
                      onMarkAsRead={(id) => handleMarkNotificationRead(id, handleNavigate)}
                      onDismiss={handleDismissNotification}
                      onClearAll={handleClearAllNotifications}
                      onAcknowledge={handleGlobalAcknowledge}
                      canAcknowledge={isAdmin}
                  />
                  <button 
                      onClick={() => setIsProfileModalOpen(true)} 
                      className={`p-2 transition-colors ${isProfileModalOpen ? 'text-slate-900 bg-slate-50 rounded-full' : 'text-slate-400 hover:text-slate-600'}`}
                  >
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z"></path></svg>
                  </button>
              </div>
          </header>

          <main className="flex-1 p-4 md:p-8 w-full max-w-7xl mx-auto no-print">
              {viewMode === 'form' ? (
                  <InspectionFormView 
                      initialData={formInitialData}
                      activeModule={activeModule}
                      validationLists={validationLists}
                      settings={settings}
                      onSaveDraft={handleExitForm} 
                      onExit={() => setViewMode('dashboard')} 
                      onSubmit={handleGoogleSheetSubmit}
                      submissionStatus={submissionStatus}
                      onViewReport={handleViewReport}
                  />
              ) : (
                  <div className="animate-fadeIn">
                      {activeModule === 'overview' && (
                          <OverviewDashboard 
                              appScriptUrl={appScriptUrl} 
                              onNavigate={handleNavigate} 
                              userRole={currentUser.role}
                              historyList={historyList}
                              isLoading={isLoadingHistory}
                              onViewReport={handleViewReport}
                              isMaintenanceActive={settings.maintenanceMode}
                              pendingAlertsCount={notifications.filter(n => !n.read && n.type === 'critical').length}
                          />
                      )}
                      {(activeModule === 'settings' && isAdmin) && <SettingsView settings={settings} setSettings={setSettings} appScriptUrl={appScriptUrl} setAppScriptUrl={setAppScriptUrl} handleSaveSettings={handleSaveSettings} isSavingSettings={isSavingSettings} showToast={showToast} user={currentUser} />}
                      {(activeModule === 'maintenance' && isSuperAdmin) && <MaintenanceView user={currentUser} appScriptUrl={appScriptUrl} settings={settings} onSettingsUpdate={(s) => setSettings(p => ({...p, ...s}))} showToast={showToast} />}
                      {activeModule === 'general' && <GeneralDashboard userRole={currentUser.role} stats={stats} startNewInspection={() => startFreshInspection('general')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} />}
                      {activeModule === 'petroleum' && <PetroleumDashboard userRole={currentUser.role} stats={stats} startNewInspection={() => startFreshInspection('petroleum')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} />}
                      {activeModule === 'petroleum_v2' && <PetroleumV2Dashboard userRole={currentUser.role} stats={stats} startNewInspection={() => startFreshInspection('petroleum_v2')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} />}
                      {activeModule === 'acid' && <AcidDashboard userRole={currentUser.role} stats={stats} startNewInspection={() => startFreshInspection('acid')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} />}
                      {(activeModule === 'users' && isAdmin) && <UserManagementView currentUser={currentUser} appScriptUrl={appScriptUrl} showToast={showToast} validationLists={validationLists} settings={settings} />}
                      {activeModule === 'support' && <SupportView appScriptUrl={appScriptUrl} currentUser={currentUser} showToast={showToast} settings={settings} validationLists={validationLists} />}
                      {activeModule === 'track_requests' && <RequestTrackingView appScriptUrl={appScriptUrl} currentUser={currentUser} showToast={showToast} onRequestNew={() => setIsRequestModalOpen(true)} />}
                  </div>
              )}
          </main>

          <footer className="mt-auto py-6 border-t border-slate-50 text-center no-print">
              <span className="text-[9px] font-bold text-slate-300 uppercase tracking-[0.2em]">scbc@2026</span>
          </footer>
      </div>

      {isReportModalOpen && selectedReportData && (
          <ReportViewerModal 
            onClose={() => setIsReportModalOpen(false)} 
            onPrint={() => window.print()}
            title={`Report_${selectedReportData.id || 'History'}`}
          >
              {activeModule === 'petroleum' ? (
                  <PrintablePetroleumReport data={selectedReportData} settings={settings} />
              ) : activeModule === 'petroleum_v2' ? (
                  <PrintablePetroleumV2Report data={selectedReportData} settings={settings} />
              ) : activeModule === 'acid' ? (
                  <PrintableAcidReport data={selectedReportData} settings={settings} />
              ) : (
                  <PrintableGeneralReport data={selectedReportData} settings={settings} />
              )}
          </ReportViewerModal>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { User, SystemSettings } from '../types';

interface LoginViewProps {
  onLogin: (user: User) => void;
  appScriptUrl: string;
  setAppScriptUrl: (url: string) => void;
  settings: SystemSettings;
}

const LoginView: React.FC<LoginViewProps> = ({ onLogin, appScriptUrl, setAppScriptUrl, settings }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [rememberMe, setRememberMe] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');
  const [isRegistering, setIsRegistering] = useState(false);
  const [fullName, setFullName] = useState('');
  const [position, setPosition] = useState('');
  const [logoError, setLogoError] = useState(false);

  // Load remembered credentials on mount
  useEffect(() => {
    const saved = localStorage.getItem('sc_remembered_creds');
    if (saved) {
      try {
        const { u, p } = JSON.parse(atob(saved));
        setUsername(u);
        setPassword(p);
        setRememberMe(true);
      } catch (e) {
        localStorage.removeItem('sc_remembered_creds');
      }
    }
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!appScriptUrl || !appScriptUrl.startsWith('https://script.google.com')) {
      setError("System connection not configured. Please contact your IT Administrator.");
      return;
    }

    setError('');
    setIsLoading(true);

    try {
      // Special logic: Regular login
      // Note: Backend handleLogin will allow empty password if user.name is empty (Invite mode)
      const payload = isRegistering 
        ? { action: 'register_user', username, password, name: fullName, position: position, role: 'SuperAdmin' }
        : { action: 'login', username, password };

      const response = await fetch(appScriptUrl, {
        method: 'POST',
        body: JSON.stringify(payload)
      });

      const result = await response.json();

      if (result.status === 'success') {
          const rawUser = result.user;

          if (rememberMe && password) {
            const creds = btoa(JSON.stringify({ u: username, p: password }));
            localStorage.setItem('sc_remembered_creds', creds);
          } else {
            localStorage.removeItem('sc_remembered_creds');
          }

          if (isRegistering) {
              setError("Admin account created. Log in now.");
              setIsRegistering(false);
              setFullName('');
              setPosition('');
              setPassword('');
          } else {
              let safeRole: User['role'] = 'Inspector';
              const rawRole = rawUser.role ? String(rawUser.role).trim().toLowerCase() : '';

              if (rawRole === 'superadmin') safeRole = 'SuperAdmin';
              else if (rawRole === 'admin') safeRole = 'Admin';
              else if (rawRole === 'operations') safeRole = 'Operations';
              else if (rawRole === 'maintenance') safeRole = 'Maintenance';
              else if (rawRole === 'secretary') safeRole = 'Secretary';
              else if (rawRole === 'other') safeRole = 'Other';

              onLogin({ 
                ...rawUser, 
                role: safeRole, 
                position: rawUser.position || '',
                // Flag onboarding if name is missing
                needsSetup: !rawUser.name
              });
          }
      } else if (result.code === 'NO_USERS') {
          setError("Initial setup needed. Create Master Admin.");
          setIsRegistering(true);
      } else {
          setError(result.message || "Authentication failed.");
      }

    } catch (err) {
      setError("Unable to reach server. Check connection.");
    } finally {
      setIsLoading(false); 
    }
  };

  const isUrlValid = appScriptUrl && appScriptUrl.startsWith('https://script.google.com');

  return (
    <div className="min-h-screen w-full bg-slate-50 flex flex-col md:flex-row font-sans text-slate-700 overflow-x-hidden">

      <div className="w-full md:w-[35%] lg:w-[30%] bg-emerald-950 p-6 md:p-12 flex flex-col justify-between relative overflow-hidden shrink-0 border-b md:border-b-0 border-emerald-900 shadow-xl z-10">
        <div className="absolute top-0 left-0 w-full h-full pointer-events-none opacity-10">
            <div className="absolute -top-10 -left-10 w-64 h-64 bg-emerald-400 rounded-full blur-[80px]"></div>
        </div>

        <div className="relative z-10 flex md:block items-center justify-between">
          <div className="bg-white p-2 rounded-xl inline-block shadow-lg">
             {settings.companyLogo && !logoError ? (
                <img src={settings.companyLogo} alt="Logo" className="h-8 md:h-12 w-auto object-contain" onError={() => setLogoError(true)} />
             ) : (
                <div className="flex items-center gap-2 px-1">
                    <svg className="w-6 h-6 text-emerald-900" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" />
                    </svg>
                    <span className="font-black text-emerald-950 text-base md:text-xl tracking-tight uppercase">SafetyPro</span>
                </div>
             )}
          </div>

          <div className="md:mt-8 text-right md:text-left">
            <h1 className="text-xl md:text-3xl font-black text-white leading-tight uppercase">
                {settings.companyName || 'SafetyPro Fleet'}
            </h1>
            <p className="text-emerald-400 font-bold uppercase tracking-widest text-[9px] mt-1 opacity-60">Fleet Management Portal</p>
          </div>
        </div>

        <div className="relative z-10 mt-4 space-y-4">
            <div className="flex items-center gap-2 animate-fadeIn">
                <div className={`w-[2px] h-3.5 rounded-full transition-all duration-500 
                    ${isLoading ? 'bg-blue-400 animate-pulse' : isUrlValid ? 'bg-emerald-500 shadow-sm' : 'bg-red-500'}`}
                ></div>
                <div className="flex flex-col">
                    <span className={`text-[8px] font-black tracking-widest leading-none uppercase 
                        ${isLoading ? 'text-blue-200' : isUrlValid ? 'text-white' : 'text-red-100'}`}
                    >
                        {isLoading ? 'Processing' : isUrlValid ? 'Server Ready' : 'Server Disconnected'}
                    </span>
                </div>
            </div>
            <div className="hidden md:block border-t border-white/5 pt-4">
                <span className="text-[8px] text-emerald-100/30 font-medium uppercase tracking-[0.2em]">© SCBC FLEET SOLUTIONS 2026</span>
            </div>
        </div>
      </div>

      <div className="flex-1 flex flex-col bg-white">
        <div className="flex-1 overflow-y-auto px-6 py-10 md:px-12 flex items-center justify-center">
          <div className="w-full max-w-sm mx-auto">
            <div className="mb-8">
              <h2 className="text-2xl font-black text-slate-800 tracking-tight">
                {isRegistering ? 'Admin Setup' : 'Login'}
              </h2>
              <p className="text-slate-400 text-sm mt-1 font-medium">
                {isRegistering ? 'Create system owner account.' : 'Sign in to access inspections.'}
              </p>
            </div>

            {error && (
              <div className={`mb-6 p-4 rounded-lg text-xs font-medium border animate-fadeIn
                ${error.includes("created") ? 'bg-green-50 text-green-700 border-green-200' : 'bg-red-50 text-red-700 border-red-100'}`}>
                {error}
              </div>
            )}

            <form onSubmit={handleSubmit} className="space-y-5">
              {isRegistering && (
                <div className="space-y-4 bg-slate-50/50 p-5 rounded-xl border border-slate-100 mb-4">
                  <input type="text" required className="w-full px-4 py-3 bg-white border border-slate-200 rounded-lg outline-none text-sm font-bold" value={fullName} onChange={e => setFullName(e.target.value)} placeholder="Full Name" />
                  <input type="text" required className="w-full px-4 py-3 bg-white border border-slate-200 rounded-lg outline-none text-sm font-bold" value={position} onChange={e => setPosition(e.target.value)} placeholder="Job Title" />
                </div>
              )}

              <div className="space-y-4">
                <input 
                  type="email" 
                  required 
                  className="w-full px-4 py-3.5 bg-slate-50 border border-slate-200 rounded-lg focus:bg-white focus:border-emerald-500 outline-none font-bold text-sm" 
                  value={username} 
                  onChange={e => setUsername(e.target.value)} 
                  placeholder="Email Address"
                />
                {!isRegistering && (
                  <div className="space-y-1">
                    <input 
                      type="password" 
                      className="w-full px-4 py-3.5 bg-slate-50 border border-slate-200 rounded-lg focus:bg-white focus:border-emerald-500 outline-none font-bold text-sm" 
                      value={password} 
                      onChange={e => setPassword(e.target.value)} 
                      placeholder="Password"
                    />
                    <p className="text-[10px] text-slate-400 px-1">First-time login? Leave password blank if you were invited.</p>
                  </div>
                )}
                {isRegistering && (
                  <input type="password" required className="w-full px-4 py-3.5 bg-slate-50 border border-slate-200 rounded-lg outline-none font-bold text-sm" value={password} onChange={e => setPassword(e.target.value)} placeholder="Setup Password" />
                )}
              </div>

              <div className="flex items-center justify-between px-1">
                  <label className="flex items-center gap-2 cursor-pointer group select-none">
                      <input type="checkbox" className="w-4 h-4 rounded border-gray-300 text-emerald-600 focus:ring-emerald-500" checked={rememberMe} onChange={e => setRememberMe(e.target.checked)} />
                      <span className="text-xs text-slate-400 font-medium group-hover:text-slate-600">Stay signed in</span>
                  </label>
              </div>

              <div className="pt-4">
                <button 
                  type="submit" 
                  disabled={isLoading || !isUrlValid} 
                  className={`w-full h-[56px] rounded-xl font-bold text-white shadow-lg transition-all text-xs uppercase tracking-widest active:scale-[0.98] flex items-center justify-center gap-3
                    ${!isUrlValid ? 'bg-slate-200 cursor-not-allowed text-slate-400 shadow-none' : isLoading ? 'bg-emerald-900 cursor-wait' : 'bg-slate-900 hover:bg-black'}`}
                >
                  {isLoading ? (
                    <svg className="animate-spin h-5 w-5 text-emerald-400" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                  ) : null}
                  {isLoading ? 'Verifying...' : isRegistering ? 'Create Admin' : 'Sign In'}
                </button>
              </div>
            </form>
          </div>
        </div>
      </div>
    </div>
  );
};

export default LoginView;

import React, { useState, useEffect } from 'react';
import { User, ValidationLists, SystemSettings } from '../types';
import AutocompleteInput from '../components/ui/AutocompleteInput';

interface UserManagementViewProps {
    currentUser: User;
    appScriptUrl: string;
    showToast: (msg: string, type: 'success' | 'error' | 'info' | 'warning') => void;
    validationLists: ValidationLists;
    settings?: SystemSettings;
}

const UserManagementView: React.FC<UserManagementViewProps> = ({ currentUser, appScriptUrl, showToast, validationLists, settings }) => {
    const [users, setUsers] = useState<(User & {password?: string})[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [viewMode, setViewMode] = useState<'list' | 'form'>('list');
    const [isEditing, setIsEditing] = useState(false);
    const [originalUsername, setOriginalUsername] = useState('');

    const [formData, setFormData] = useState({
        name: '', username: '', password: '', role: 'Inspector' as any, position: ''
    });
    const [isSubmitting, setIsSubmitting] = useState(false);

    const isSuperAdmin = currentUser.role === 'SuperAdmin';
    const isAdmin = currentUser.role === 'Admin' || isSuperAdmin;

    useEffect(() => { 
        if (isAdmin) fetchUsers(); 
    }, [isAdmin]);

    if (!isAdmin) {
        return (
            <div className="flex flex-col items-center justify-center py-20 text-center font-sans">
                <div className="w-16 h-16 bg-red-50 text-red-500 rounded-full flex items-center justify-center mb-4">
                    <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z"></path></svg>
                </div>
                <h3 className="text-xl font-medium text-slate-800 tracking-tight">Access Restricted</h3>
                <p className="text-slate-500 max-w-xs mt-2 text-sm font-normal">You do not have the required permissions to access Staff Management.</p>
            </div>
        );
    }

    const fetchUsers = async (force: boolean = false) => {
        if (!appScriptUrl) return;
        setIsLoading(true);
        try {
            const response = await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify({ action: 'get_users' }) });
            const result = await response.json();
            if (result.status === 'success' && Array.isArray(result.users)) {
                let fetchedUsers = result.users;
                if (!isSuperAdmin) fetchedUsers = fetchedUsers.filter((u: User) => u.role !== 'SuperAdmin');
                setUsers(fetchedUsers);
            }
        } catch (e) { showToast("Failed to load users", 'error'); } finally { setIsLoading(false); }
    };

    const handleDelete = async (username: string) => {
        if (!window.confirm(`Remove user "${username}"?`)) return;
        setIsLoading(true);
        try {
            const response = await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify({ action: 'delete_user', username }) });
            const result = await response.json();
            if (result.status === 'success') {
                showToast("User removed successfully", 'success');
                fetchUsers();
            } else { showToast(result.message || "Delete failed", 'error'); }
        } catch (e) { showToast("Connection failed", 'error'); } finally { setIsLoading(false); }
    };

    const handleEdit = (user: User) => {
        setFormData({ name: user.name || '', username: user.username, role: user.role as any, position: user.position || '', password: '' });
        setOriginalUsername(user.username);
        setIsEditing(true);
        setViewMode('form');
    };

    const handleShare = async (u: User) => {
        const orgName = settings?.companyName || 'Fleet Operations';
        const msg = `*${orgName.toUpperCase()} - STAFF IDENTITY*\n\n*Name:* ${u.name || 'Setup Pending'}\n*Role:* ${u.role}\n*Job Title:* ${u.position || 'N/A'}\n*Login Email:* ${u.username}\n\n_Security Notice: This confirms identity mapping in the Fleet Portal._`;

        if (navigator.share) {
            try {
                await navigator.share({
                    title: 'Staff Identity Detail',
                    text: msg
                });
            } catch (e) {
                if (e instanceof Error && e.name !== 'AbortError') {
                    fallbackCopy(msg);
                }
            }
        } else {
            fallbackCopy(msg);
        }
    };

    const fallbackCopy = (text: string) => {
        navigator.clipboard.writeText(text).then(() => {
            showToast("Professional details copied to clipboard", "success");
        }).catch(() => {
            showToast("Failed to share details", "error");
        });
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!formData.username) { showToast("Login Email is required.", 'error'); return; }

        setIsSubmitting(true);
        try {
            const payload: any = { 
                action: isEditing ? 'update_user' : 'register_user', 
                ...formData,
                preferences: {
                    ... (isEditing ? {} : { mustChangePassword: true })
                }
            };

            if (isEditing) payload.originalUsername = originalUsername;

            const response = await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify(payload) });
            const result = await response.json();

            if (result.status === 'success') {
                showToast(isEditing ? "Staff details updated" : "Invite sent to new staff member", 'success');
                setViewMode('list');
                fetchUsers();
            } else { 
                showToast(result.message || "Operation failed", 'error'); 
            }
        } catch (e) { 
            showToast("Connection failed", 'error'); 
        } finally { 
            setIsSubmitting(false); 
        }
    };

    if (viewMode === 'form') {
        return (
            <div className="max-w-lg mx-auto animate-fadeIn py-4 px-4 font-sans">
                <button onClick={() => setViewMode('list')} className="mb-6 text-[10px] font-medium text-slate-400 hover:text-slate-800 flex items-center gap-2 transition-colors group uppercase tracking-widest">
                    <svg className="w-4 h-4 group-hover:-translate-x-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M15 19l-7-7 7-7"></path></svg>
                    Back to Directory
                </button>
                <div className="bg-white rounded-3xl shadow-xl border border-slate-100 overflow-hidden p-6 sm:p-10">
                    <h2 className="text-2xl font-normal text-slate-800 mb-2 uppercase tracking-tight leading-none">{isEditing ? 'Edit Profile' : 'Invite Staff'}</h2>
                    <p className="text-slate-400 text-[10px] font-normal mb-10 uppercase tracking-[0.2em]">Configure workspace permissions</p>

                    <form onSubmit={handleSubmit} className="space-y-6">
                        <div className="space-y-5">
                            <div>
                                <label className="block text-[10px] font-normal uppercase text-slate-400 mb-2 tracking-[0.15em]">Login Identity (Email) *</label>
                                <input 
                                    type="email" 
                                    required 
                                    className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-indigo-500 outline-none transition font-normal text-slate-700" 
                                    value={formData.username} 
                                    onChange={e => setFormData({...formData, username: e.target.value})} 
                                    placeholder="e.g. staff@company.com" 
                                />
                            </div>

                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-[10px] font-normal uppercase text-slate-400 mb-2 tracking-[0.15em]">System Role</label>
                                    <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-normal text-slate-700 focus:ring-2 focus:ring-indigo-500 outline-none h-[58px] appearance-none" value={formData.role} onChange={e => setFormData({...formData, role: e.target.value as any})}>
                                        <option value="Inspector">Inspector</option>
                                        <option value="Operations">Operations</option>
                                        <option value="Maintenance">Maintenance</option>
                                        <option value="Admin">Admin</option>
                                        {isSuperAdmin && <option value="SuperAdmin">SuperAdmin</option>}
                                    </select>
                                </div>
                                <AutocompleteInput 
                                    label="Job Title" 
                                    value={formData.position} 
                                    onChange={v => setFormData({...formData, position: v})} 
                                    options={validationLists.positions} 
                                    isTitleCase={true} 
                                    placeholder="Optional"
                                />
                            </div>
                        </div>

                        {!isEditing && (
                            <div className="p-4 bg-indigo-50 border border-indigo-100 rounded-2xl flex items-start gap-3">
                                <svg className="w-5 h-5 text-indigo-500 shrink-0 mt-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                                <p className="text-[10px] text-indigo-800 font-normal leading-relaxed uppercase tracking-wider">
                                    <strong>Security Notice:</strong> New users will be prompted to establish their credentials upon first access via the invite email.
                                </p>
                            </div>
                        )}

                        {isEditing && (
                            <div className="pt-4 border-t border-slate-100">
                                <AutocompleteInput label="Full Name" value={formData.name} onChange={v => setFormData({...formData, name: v})} options={validationLists.inspectors} isTitleCase={true} />
                            </div>
                        )}

                        <button type="submit" disabled={isSubmitting} className="w-full py-5 bg-slate-900 hover:bg-black text-white font-normal rounded-2xl shadow-xl transition-all active:scale-95 flex items-center justify-center gap-3 mt-4 uppercase tracking-[0.2em] text-xs">
                            {isSubmitting ? (
                                <svg className="animate-spin h-5 w-5 text-indigo-400" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                            ) : null}
                            {isSubmitting ? 'Processing' : isEditing ? 'Update Profile' : 'Dispatch Invite'}
                        </button>
                    </form>
                </div>
            </div>
        );
    }

    return (
        <div className="max-w-6xl mx-auto space-y-10 animate-fadeIn px-4 md:px-0 font-sans">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6">
                <div>
                    <h2 className="text-3xl font-normal text-slate-800 uppercase tracking-tight leading-none flex items-center gap-3">
                        Staff Directory
                    </h2>
                    <p className="text-[10px] text-slate-400 font-normal uppercase tracking-[0.25em] mt-2">Access Control & Identity Center</p>
                </div>
                <button onClick={() => { setFormData({ name: '', username: '', password: '', role: 'Inspector', position: '' }); setIsEditing(false); setViewMode('form'); }} className="w-full sm:w-auto px-8 py-4 bg-slate-900 hover:bg-black text-white font-normal rounded-2xl shadow-xl transition-all flex items-center justify-center gap-2 group text-xs uppercase tracking-[0.2em]">
                    <svg className="w-5 h-5 group-hover:rotate-90 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M12 4v16m8-8H4"></path></svg>
                    New Member
                </button>
            </div>

            <div className="bg-white rounded-[2rem] shadow-sm border border-slate-100 overflow-hidden">
                <table className="w-full text-left text-sm border-collapse block md:table">
                    <thead className="bg-slate-50 text-[10px] font-normal text-slate-400 uppercase tracking-[0.25em] border-b border-slate-100 hidden md:table-header-group">
                        <tr className="md:table-row">
                            <th className="px-10 py-6 md:table-cell">Identity</th>
                            <th className="px-10 py-6 md:table-cell">Role</th>
                            <th className="px-10 py-6 md:table-cell">Integrity Status</th>
                            <th className="px-10 py-6 text-right md:table-cell">Actions</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50 block md:table-row-group">
                        {users.map((u, i) => (
                            <tr key={i} className="hover:bg-slate-50/50 transition-colors group block md:table-row relative p-8 md:p-0">
                                <td className="md:px-10 md:py-6 block md:table-cell mb-6 md:mb-0">
                                    <div className="flex items-center gap-5">
                                        <div className="w-12 h-12 rounded-2xl bg-white border border-slate-100 shadow-sm flex items-center justify-center font-normal text-slate-300 text-sm tracking-tighter">
                                            {u.name ? u.name.substring(0, 2).toUpperCase() : '??'}
                                        </div>
                                        <div className="min-w-0">
                                            <div className="font-normal text-slate-800 text-base leading-tight truncate">{u.name || 'Setup Pending'}</div>
                                            <div className="text-[11px] text-slate-400 font-normal tracking-tight truncate">{u.username}</div>
                                        </div>
                                    </div>
                                </td>
                                <td className="md:px-10 md:py-6 block md:table-cell mb-6 md:mb-0">
                                    <div className="md:hidden text-[9px] font-normal text-slate-300 uppercase tracking-[0.2em] mb-2">Access Role</div>
                                    <span className={`px-4 py-2 rounded-xl text-[10px] font-normal uppercase tracking-widest
                                        ${u.role === 'Admin' || u.role === 'SuperAdmin' ? 'bg-indigo-50 text-indigo-600 border border-indigo-100 shadow-sm' : 'bg-slate-50 text-slate-500 border border-slate-100'}
                                    `}>
                                        {u.role}
                                    </span>
                                </td>
                                <td className="md:px-10 md:py-6 block md:table-cell mb-6 md:mb-0">
                                    <div className="md:hidden text-[9px] font-normal text-slate-300 uppercase tracking-[0.2em] mb-2">System Status</div>
                                    {u.name ? (
                                        <span className="flex items-center gap-2 text-emerald-500 font-normal text-[10px] uppercase tracking-[0.2em]">
                                            <div className="w-2 h-2 rounded-full bg-emerald-500 shadow-[0_0_10px_rgba(16,185,129,0.5)]"></div>
                                            Verified
                                        </span>
                                    ) : (
                                        <span className="flex items-center gap-2 text-amber-500 font-normal text-[10px] uppercase tracking-[0.2em] animate-pulse">
                                            <div className="w-2 h-2 rounded-full bg-amber-500 shadow-[0_0_10px_rgba(245,158,11,0.5)]"></div>
                                            Active Invite
                                        </span>
                                    )}
                                </td>
                                <td className="md:px-10 md:py-6 md:text-right block md:table-cell">
                                    <div className="flex justify-start md:justify-end gap-3 md:opacity-0 group-hover:opacity-100 transition-all border-t md:border-0 pt-6 md:pt-0 mt-6 md:mt-0">
                                        <button onClick={() => handleShare(u)} className="p-3 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-2xl transition-all border md:border-0 bg-white md:bg-transparent shadow-sm md:shadow-none" title="Share Identity">
                                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z"></path></svg>
                                        </button>
                                        <button onClick={() => handleEdit(u)} className="p-3 text-blue-500 hover:bg-blue-50 rounded-2xl transition-all border md:border-0 bg-white md:bg-transparent shadow-sm md:shadow-none" title="Edit Profile">
                                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z"></path></svg>
                                        </button>
                                        <button onClick={() => handleDelete(u.username)} className="p-3 text-red-400 hover:bg-red-50 rounded-2xl transition-all border md:border-0 bg-white md:bg-transparent shadow-sm md:shadow-none" title="Remove User">
                                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
                                        </button>
                                    </div>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    );
};

export default UserManagementView;

import React, { useState } from 'react';
import { User, SystemSettings, UserPreferences } from '../../types';

interface ProfileModalProps {
    user: User;
    settings: SystemSettings;
    appScriptUrl: string;
    onClose: () => void;
    showToast: (msg: string, type: 'success' | 'error' | 'info' | 'warning') => void;
    onUpdateSuccess: (newUser: User) => void;
    onLogout: () => void;
}

const ProfileModal: React.FC<ProfileModalProps> = ({ 
    user, 
    settings, 
    appScriptUrl, 
    onClose, 
    showToast, 
    onUpdateSuccess, 
    onLogout
}) => {
    const nameParts = (user.name || '').split(' ');
    const firstName = nameParts[0] || '';
    const lastName = nameParts.slice(1).join(' ') || '';

    // Password State
    const [password, setPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [isUpdatingPassword, setIsUpdatingPassword] = useState(false);

    // Preferences State
    const [prefs, setPrefs] = useState<UserPreferences>(user.preferences || {
        emailNotifications: true,
        notifyGeneral: true,
        notifyPetroleum: true,
        notifyPetroleumV2: true,
        notifyAcid: true
    });
    const [isUpdatingPrefs, setIsUpdatingPrefs] = useState(false);

    const handlePasswordChange = async () => {
        if (!password) {
            showToast("Please enter a new password.", "warning");
            return;
        }
        if (password !== confirmPassword) {
            showToast("Passwords do not match.", "error");
            return;
        }

        setIsUpdatingPassword(true);
        try {
            const response = await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify({
                    action: 'update_user',
                    originalUsername: user.username,
                    password: password
                })
            });
            const result = await response.json();

            if (result.status === 'success') {
                showToast("Security updated!", 'success');
                setPassword('');
                setConfirmPassword('');
            } else {
                showToast(result.message || "Failed to update.", 'error');
            }
        } catch (e) {
            showToast("Sync failed.", 'error');
        } finally {
            setIsUpdatingPassword(false);
        }
    };

    const handleUpdatePrefs = async (newPrefs: UserPreferences) => {
        setPrefs(newPrefs);
        setIsUpdatingPrefs(true);
        try {
            const response = await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify({
                    action: 'update_user',
                    originalUsername: user.username,
                    preferences: newPrefs
                })
            });
            const result = await response.json();
            if (result.status === 'success') {
                onUpdateSuccess({ ...user, preferences: newPrefs });
                showToast("Preferences synced.", 'success');
            }
        } catch (e) {
            showToast("Sync failed.", 'error');
        } finally {
            setIsUpdatingPrefs(false);
        }
    };

    const togglePref = (key: keyof UserPreferences) => {
        const next = { ...prefs, [key]: !prefs[key] };
        handleUpdatePrefs(next);
    };

    return (
        <div className="fixed inset-0 z-[100] bg-white flex flex-col animate-fadeIn overflow-y-auto">
            {/* Header */}
            <div className="sticky top-0 bg-white border-b border-gray-100 px-4 py-3 flex items-center shrink-0 z-10 shadow-sm">
                <button 
                    onClick={onClose}
                    className="p-2 text-blue-500 hover:bg-blue-50 rounded-full transition-all"
                >
                    <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M15 19l-7-7 7-7"></path></svg>
                </button>
                <h1 className="flex-1 text-center font-bold text-slate-800 text-sm uppercase tracking-widest">My Workspace</h1>
                <div className="w-10"></div>
            </div>

            <div className="max-w-2xl mx-auto w-full px-6 py-10 space-y-12 pb-24">

                {/* 1. YOUR DETAILS */}
                <section className="space-y-4">
                    <h3 className="text-lg font-bold text-slate-800 border-b border-gray-100 pb-2 uppercase tracking-tight">Identity Profile</h3>
                    <div className="space-y-3">
                        <div className="flex justify-between items-center text-sm py-1">
                            <span className="font-semibold text-slate-600">Organization</span>
                            <span className="text-slate-400 font-medium">{settings.companyName || 'Transport Pro'}</span>
                        </div>
                        <div className="flex justify-between items-center text-sm py-1">
                            <span className="font-semibold text-slate-600">First Name</span>
                            <span className="text-slate-400 font-medium">{firstName}</span>
                        </div>
                        <div className="flex justify-between items-center text-sm py-1">
                            <span className="font-semibold text-slate-600">Last Name</span>
                            <span className="text-slate-400 font-medium">{lastName}</span>
                        </div>
                        <div className="flex justify-between items-center text-sm py-1">
                            <span className="font-semibold text-slate-600">Login ID</span>
                            <span className="text-slate-400 font-medium">{user.username}</span>
                        </div>
                    </div>
                </section>

                {/* 2. CHANGE PASSWORD */}
                <section className="space-y-4">
                    <h3 className="text-lg font-bold text-slate-800 border-b border-gray-100 pb-2 uppercase tracking-tight">Security Access</h3>
                    <div className="space-y-4">
                        <input 
                            type="password" 
                            placeholder="Set New Password"
                            className="w-full p-3.5 border border-gray-200 rounded-xl text-sm bg-slate-50 focus:bg-white focus:ring-2 focus:ring-blue-100 outline-none transition-all font-semibold"
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                        />
                        <input 
                            type="password" 
                            placeholder="Confirm Password"
                            className="w-full p-3.5 border border-gray-200 rounded-xl text-sm bg-slate-50 focus:bg-white focus:ring-2 focus:ring-blue-100 outline-none transition-all font-semibold"
                            value={confirmPassword}
                            onChange={(e) => setConfirmPassword(e.target.value)}
                        />
                        <button 
                            onClick={handlePasswordChange}
                            disabled={isUpdatingPassword}
                            className="w-full py-4 bg-slate-900 hover:bg-black text-white font-bold rounded-xl shadow-lg transition-all active:scale-95 flex items-center justify-center gap-2 text-xs uppercase tracking-widest"
                        >
                            {isUpdatingPassword ? (
                                <>
                                    <svg className="animate-spin h-5 w-5 text-white" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                                    Verifying...
                                </>
                            ) : 'Update Security'}
                        </button>
                    </div>
                </section>

                {/* 3. EMAIL NOTIFICATIONS */}
                <section className="space-y-4">
                    <div className="flex items-center justify-between border-b border-gray-100 pb-2">
                        <h3 className="text-lg font-bold text-slate-800 uppercase tracking-tight">Alert Preferences</h3>
                        {isUpdatingPrefs && <svg className="animate-spin h-4 w-4 text-blue-500" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>}
                    </div>

                    <div className="space-y-2">
                        <label className="flex items-center justify-between p-4 rounded-2xl bg-slate-50 border border-slate-100 cursor-pointer group">
                            <div>
                                <p className="text-sm font-bold text-slate-800">Master Email Alert</p>
                                <p className="text-[10px] text-slate-400 font-semibold uppercase tracking-wider">Automated system triggers</p>
                            </div>
                            <input type="checkbox" className="w-5 h-5 rounded border-gray-300 text-blue-600 focus:ring-blue-500" checked={prefs.emailNotifications} onChange={() => togglePref('emailNotifications')} />
                        </label>

