  settings: SystemSettings;
  user?: User; 
  onLogout?: () => void;
  onEditProfile?: () => void; 
  onLockedItemClick?: (featureName: string) => void;
  subscription?: SubscriptionDetails | null;
  onRequestInspection?: () => void; 
}

const Sidebar: React.FC<SidebarProps> = ({ isOpen, onClose, activeModule, onSelectModule, settings, user, onLogout, onEditProfile, onLockedItemClick, subscription, onRequestInspection }) => {

    const roleStr = user?.role ? String(user.role).toLowerCase() : '';
    const isAdmin = roleStr === 'admin' || roleStr === 'superadmin';
    const isSuperAdmin = roleStr === 'superadmin';

    const canAccessRequests = isAdmin || ['operations', 'maintenance', 'secretary', 'other', 'clerk'].includes(roleStr);

    const [logoError, setLogoError] = useState(false);

    useEffect(() => {
        setLogoError(false);
    }, [settings.companyLogo]);

    const NavItem = ({ id, label, icon, isLocked = false, isDanger = false, onClickCustom }: { id: string, label: string, icon: React.ReactNode, isLocked?: boolean, isDanger?: boolean, onClickCustom?: () => void }) => {
        const isActive = activeModule === id;

        return (
            <button
                onClick={() => { 
                    if (onClickCustom) {
                        onClickCustom();
                        return;
