            {isAdmin && (
                <div className="animate-fadeIn">
                     <div className="flex items-center justify-between mb-10 px-4">
                        <h3 className="text-[10px] font-bold text-indigo-600 uppercase tracking-[0.25em]">System Administration</h3>
                        <div className="h-px bg-indigo-50 flex-1 mx-6"></div>
                    </div>
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-x-6 gap-y-10 justify-items-center">
                        <LauncherTile 
