};

export default MaintenanceView;

import React, { useState, useEffect } from 'react';
import { INITIAL_DATA, InspectionData, User } from './types';
import { 
    SHEET_HEADERS, PETROLEUM_HEADERS, PETROLEUM_V2_HEADERS, ACID_HEADERS,
    INSPECTION_ITEMS, PETROLEUM_INSPECTION_ITEMS, PETROLEUM_V2_ITEMS, ACID_INSPECTION_ITEMS
} from './constants';

// Hooks
import { useAuth } from './hooks/useAuth';
import { useSettings } from './hooks/useSettings';
import { useNotifications } from './hooks/useNotifications';
import { useHistory } from './hooks/useHistory';
import { useOfflineSync } from './hooks/useOfflineSync';
import { useSubscription } from './hooks/useSubscription';

// UI Components
import Toast from './components/ui/Toast';
import ReportViewerModal from './components/ui/ReportViewerModal';
import SubmissionOverlay from './components/ui/SubmissionOverlay';
import ProfileModal from './components/ui/ProfileModal';
import NotificationCenter from './components/ui/NotificationCenter'; 
import UpgradeModal from './components/ui/UpgradeModal';
import InspectionStartModal from './components/ui/InspectionStartModal';
import SubscriptionAlert from './components/ui/SubscriptionAlert';
import MaintenanceOverlay from './components/ui/MaintenanceOverlay';
import RequestInspectionModal from './components/ui/RequestInspectionModal'; 
import OnboardingWizard from './components/ui/OnboardingWizard'; 
import SystemTour from './components/ui/SystemTour'; 
import InstallPwaPrompt from './components/ui/InstallPwaPrompt';

// Views
import LoginView from './views/LoginView';
import SettingsView from './views/SettingsView';
import GeneralDashboard from './views/GeneralDashboard';
import PetroleumDashboard from './views/PetroleumDashboard';
import PetroleumV2Dashboard from './views/PetroleumV2Dashboard';
import AcidDashboard from './views/AcidDashboard';
import UserManagementView from './views/UserManagementView';
import OverviewDashboard from './views/OverviewDashboard';
import InspectionFormView from './views/InspectionFormView';
import SupportView from './views/SupportView';
import MaintenanceView from './views/MaintenanceView';
import RequestTrackingView from './views/RequestTrackingView';

// Report Components
import PrintableGeneralReport from './components/reports/PrintableGeneralReport';
import PrintablePetroleumReport from './components/reports/PrintablePetroleumReport';
import PrintablePetroleumV2Report from './components/reports/PrintablePetroleumV2Report';
import PrintableAcidReport from './components/reports/PrintableAcidReport';

const App = () => {
  const { currentUser, setCurrentUser, handleLogin, handleLogout, sessionExpired, setSessionExpired } = useAuth();
  const { settings, setSettings, appScriptUrl, setAppScriptUrl, isSavingSettings, handleSaveSettings } = useSettings();
  const { subscription, refreshSubscription } = useSubscription(appScriptUrl, currentUser);

  const [activeModule, setActiveModule] = useState('overview'); 
  const [viewMode, setViewMode] = useState<'dashboard' | 'form'>('dashboard');
  const [isProfileModalOpen, setIsProfileModalOpen] = useState(false);
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error' | 'info' | 'warning'} | null>(null);
  const [isRequestModalOpen, setIsRequestModalOpen] = useState(false);
  const [showTour, setShowTour] = useState(false);

  const { historyList, isLoadingHistory, validationLists, stats, fetchHistory } = useHistory(appScriptUrl, activeModule, currentUser);

  const showToast = (message: string, type: 'success' | 'error' | 'info' | 'warning') => {
      setToast({ message, type });
      setTimeout(() => setToast(null), 4000);
  };

  useEffect(() => {
      if (sessionExpired === 'idle') showToast("Session expired due to inactivity.", 'warning');
      else if (sessionExpired === 'max_duration') showToast("Session limit reached. Log in again.", 'info');
      if (sessionExpired) setSessionExpired(null);
  }, [sessionExpired]);

  const { submissionStatus, setSubmissionStatus, isSyncing, addToQueue } = useOfflineSync(appScriptUrl, showToast, () => fetchHistory(true));

  const handleNavigate = (module: string) => {
    // Check if it's a deep link request from notifications
    if (module.startsWith('request:start_inspection')) {
        const parts = module.split('|');
        const type = parts[1]?.toLowerCase();
        const truck = parts[2];
        const trailer = parts[3];
        const requester = parts[4];
        const reason = parts[5];

        let moduleKey = 'general';
        if (type === 'petroleum') moduleKey = 'petroleum';
        else if (type === 'petroleum_v2') moduleKey = 'petroleum_v2';
        else if (type === 'acid') moduleKey = 'acid';

        setActiveModule(moduleKey);
        startFreshInspection(moduleKey, {
            truckNo: truck,
            trailerNo: trailer,
            remarks: `Requested by ${requester}: ${reason}`,
            requestId: parts[0].split('-')[1] // REQ ID
        });
        return;
    }

    setActiveModule(module);
    setViewMode('dashboard');
  };

  const { notifications, handleMarkNotificationRead, handleDismissNotification, handleClearAllNotifications, handleGlobalAcknowledge } = useNotifications(appScriptUrl, currentUser, showToast);

  const [isReportModalOpen, setIsReportModalOpen] = useState(false);
  const [selectedReportData, setSelectedReportData] = useState<InspectionData | null>(null);
  const [formInitialData, setFormInitialData] = useState<InspectionData>(INITIAL_DATA);

  const isAdmin = currentUser?.role === 'Admin' || currentUser?.role === 'SuperAdmin';
  const isSuperAdmin = currentUser?.role === 'SuperAdmin';
  const showMaintenance = settings.maintenanceMode && currentUser && !isSuperAdmin;

  const startFreshInspection = (module: string, prefill?: Partial<InspectionData>) => {
      setFormInitialData({ ...INITIAL_DATA, timestamp: new Date().toISOString(), inspectedBy: currentUser?.name || '', ...prefill });
      setViewMode('form');
  };

  const handleExitForm = (savedData?: InspectionData) => setViewMode('dashboard');

  const handleGoogleSheetSubmit = async (formData: InspectionData) => {
    if (!appScriptUrl) {
        showToast("Server URL not configured", "error");
        return;
    }

    setSubmissionStatus('submitting');

    let sheetName = 'General';
    let headers = SHEET_HEADERS;
    let moduleTitle = "General Vehicle Inspection";
    let activeItems = INSPECTION_ITEMS;

    if (activeModule === 'petroleum') { 
        sheetName = 'Petroleum'; 
        headers = PETROLEUM_HEADERS; 
        moduleTitle = "Petroleum Tanker Inspection";
        activeItems = PETROLEUM_INSPECTION_ITEMS;
    }
    else if (activeModule === 'petroleum_v2') { 
        sheetName = 'Petroleum_V2'; 
        headers = PETROLEUM_V2_HEADERS; 
        moduleTitle = "Petroleum Tanker Inspection V2";
        activeItems = PETROLEUM_V2_ITEMS;
    }
    else if (activeModule === 'acid') { 
        sheetName = 'Acid'; 
        headers = ACID_HEADERS; 
        moduleTitle = "Acid Tanker Inspection";
        activeItems = ACID_INSPECTION_ITEMS;
    }

    const row = headers.map(h => formData[h] !== undefined ? formData[h] : "");

    const reportData = {
        title: moduleTitle,
        timestamp: formData.timestamp,
        truckNo: formData.truckNo,
        trailerNo: formData.trailerNo,
        jobCard: formData.jobCard,
        location: formData.location,
        odometer: formData.odometer,
        inspectedBy: formData.inspectedBy,
        driverName: formData.driverName,
        remarks: formData.remarks,
        rate: formData.rate,
        signatures: {
            inspector: formData.inspectorSignature,
            driver: formData.driverSignature
        },
        photos: {
            front: formData.photoFront,
            ls: formData.photoLS,
            rs: formData.photoRS,
            back: formData.photoBack,
            damage: formData.photoDamage
        },
        items: activeItems.map(item => ({
            label: item.label,
            category: item.category,
            status: formData[item.id] || 'N/A'
        })),
        companyName: settings.companyName,
        companyLogo: settings.companyLogo
    };

    const payload = {
        action: 'create',
        sheet: sheetName,
        headers: headers,
        row: row,
        requestId: formData.requestId || null,
        reportData: reportData 
    };

    if (!navigator.onLine) {
        addToQueue(payload);
        setSubmissionStatus('offline_saved');
        setTimeout(() => {
            setSubmissionStatus('idle');
            setViewMode('dashboard');
        }, 3500);
        return;
    }

    try {
        await fetch(appScriptUrl, {
            method: 'POST',
            body: JSON.stringify(payload),
            mode: 'no-cors' 
        });

        setSubmissionStatus('success');
        fetchHistory(true); 

        setTimeout(() => {
            setSubmissionStatus('idle');
            setViewMode('dashboard');
        }, 3000);

    } catch (error) {
        console.error("Submission error", error);
        addToQueue(payload);
        setSubmissionStatus('offline_saved');
        setTimeout(() => {
            setSubmissionStatus('idle');
            setViewMode('dashboard');
        }, 3500);
    }
  };

  const handleRequestSubmit = async (data: any) => {
      if (!appScriptUrl) return;
      try {
          await fetch(appScriptUrl, {
              method: 'POST',
              body: JSON.stringify({
                  action: 'request_inspection',
                  requester: currentUser?.name,
                  role: currentUser?.role,
                  ...data
              }),
              mode: 'no-cors'
          });
          showToast("Inspection Request submitted successfully", "success");
      } catch (e) {
          showToast("Failed to submit request", "error");
      }
  };

  const handleViewReport = (item: InspectionData | null) => {
    setSelectedReportData(item);
    setIsReportModalOpen(true);
  };

  const handleOnboardingComplete = (updatedUser: User) => {
      const userWithSetup = { ...updatedUser, needsSetup: false };
      setCurrentUser(userWithSetup);
      localStorage.setItem('safetyCheck_user', JSON.stringify(userWithSetup));
      setActiveModule('overview');
      setViewMode('dashboard');
      showToast("Profile updated successfully.", "success");
      setShowTour(true);
  };

  const isAtRoot = activeModule === 'overview';

  if (!currentUser) {
      return (
          <>
            <InstallPwaPrompt />
            {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
            <LoginView 
                onLogin={handleLogin} 
                appScriptUrl={appScriptUrl}
                setAppScriptUrl={setAppScriptUrl}
                settings={settings}
            />
          </>
      );
  }

  if (currentUser && (currentUser as any).needsSetup) {
      return (
          <OnboardingWizard 
            user={currentUser} 
            appScriptUrl={appScriptUrl} 
            onComplete={handleOnboardingComplete} 
          />
      );
  }

  if (showMaintenance) {
      return (
        <>
           <MaintenanceOverlay isActive={true} message={settings.maintenanceMessage || ''} onLogout={() => handleLogout()} />
           {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
        </>
      );
  }

  return (
    <div className="min-h-screen bg-white font-sans text-gray-900 relative">
      <SubmissionOverlay status={submissionStatus} />
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      {showTour && <SystemTour onComplete={() => setShowTour(false)} />}

      {isProfileModalOpen && (
          <ProfileModal 
            user={currentUser} 
            settings={settings}
            appScriptUrl={appScriptUrl} 
            onClose={() => setIsProfileModalOpen(false)} 
            showToast={showToast} 
            onUpdateSuccess={(u) => setCurrentUser(u)} 
            onLogout={() => { setIsProfileModalOpen(false); handleLogout(); }}
          />
      )}

      <RequestInspectionModal
          isOpen={isRequestModalOpen}
          onClose={() => setIsRequestModalOpen(false)}
          onSubmit={handleRequestSubmit}
          validationLists={validationLists}
          currentUserRole={currentUser.role}
      />

      <div className="relative z-10 min-h-screen flex flex-col">
          <div className="no-print">
            <SubscriptionAlert subscription={subscription} user={currentUser} onManage={() => setActiveModule('maintenance')} />
          </div>

          <header className="bg-white border-b border-gray-100 sticky top-0 z-40 px-4 py-2 flex items-center justify-between h-14 no-print">
              <div className="flex items-center gap-1 sm:gap-2">
                  {!isAtRoot ? (
                      <button 
                          onClick={() => { setActiveModule('overview'); setViewMode('dashboard'); }}
                          title="Back to Overview"
                          className="p-2 text-slate-900 hover:bg-slate-50 rounded-lg transition-all flex items-center group"
                      >
                          <svg className="w-5 h-5 transition-transform group-hover:-translate-x-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M15 19l-7-7 7-7"></path></svg>
                          <span className="text-[10px] font-bold uppercase tracking-widest ml-1 hidden sm:inline">Back</span>
                      </button>
                  ) : (
                      <div className="w-10"></div>
                  )}
              </div>

              <button 
                  onClick={() => { setActiveModule('overview'); setViewMode('dashboard'); }}
                  className="flex flex-col items-center hover:opacity-70 transition-opacity"
              >
                  <h1 className="text-lg font-bold text-slate-900 tracking-tight leading-none uppercase">
                      {settings.companyName || 'SafetyCheck Pro'}
                  </h1>
                  <span className="text-[7px] font-bold text-slate-400 tracking-[0.3em] mt-1 uppercase">Fleet Portal</span>
              </button>

              <div className="flex items-center gap-1">
                  <NotificationCenter 
                      id="notification-bell"
                      notifications={notifications}
                      onMarkAsRead={(id) => handleMarkNotificationRead(id, handleNavigate)}
                      onDismiss={handleDismissNotification}
                      onClearAll={handleClearAllNotifications}
                      onAcknowledge={handleGlobalAcknowledge}
                      canAcknowledge={isAdmin}
                  />
                  <button 
                      onClick={() => setIsProfileModalOpen(true)} 
                      className={`p-2 transition-colors ${isProfileModalOpen ? 'text-slate-900 bg-slate-50 rounded-full' : 'text-slate-400 hover:text-slate-600'}`}
                  >
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z"></path></svg>
                  </button>
              </div>
          </header>

          <main className="flex-1 p-4 md:p-8 w-full max-w-7xl mx-auto no-print">
              {viewMode === 'form' ? (
                  <InspectionFormView 
                      initialData={formInitialData}
                      activeModule={activeModule}
                      validationLists={validationLists}
                      settings={settings}
                      onSaveDraft={handleExitForm} 
                      onExit={() => setViewMode('dashboard')} 
                      onSubmit={handleGoogleSheetSubmit}
                      submissionStatus={submissionStatus}
                      onViewReport={handleViewReport}
                  />
              ) : (
                  <div className="animate-fadeIn">
                      {activeModule === 'overview' && (
                          <OverviewDashboard 
                              appScriptUrl={appScriptUrl} 
                              onNavigate={handleNavigate} 
                              userRole={currentUser.role}
                              historyList={historyList}
                              isLoading={isLoadingHistory}
                              onViewReport={handleViewReport}
                              isMaintenanceActive={settings.maintenanceMode}
                              pendingAlertsCount={notifications.filter(n => !n.read && n.type === 'critical').length}
                          />
                      )}
                      {(activeModule === 'settings' && isAdmin) && <SettingsView settings={settings} setSettings={setSettings} appScriptUrl={appScriptUrl} setAppScriptUrl={setAppScriptUrl} handleSaveSettings={handleSaveSettings} isSavingSettings={isSavingSettings} showToast={showToast} user={currentUser} />}
                      {(activeModule === 'maintenance' && isSuperAdmin) && <MaintenanceView user={currentUser} appScriptUrl={appScriptUrl} settings={settings} onSettingsUpdate={(s) => setSettings(p => ({...p, ...s}))} showToast={showToast} onRefreshSubscription={refreshSubscription} />}
                      {activeModule === 'general' && <GeneralDashboard userRole={currentUser.role} stats={stats} startNewInspection={() => startFreshInspection('general')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} />}
                      {activeModule === 'petroleum' && <PetroleumDashboard userRole={currentUser.role} stats={stats} startNewInspection={() => startFreshInspection('petroleum')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} />}
                      {activeModule === 'petroleum_v2' && <PetroleumV2Dashboard userRole={currentUser.role} stats={stats} startNewInspection={() => startFreshInspection('petroleum_v2')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} />}
                      {activeModule === 'acid' && <AcidDashboard userRole={currentUser.role} stats={stats} startNewInspection={() => startFreshInspection('acid')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} />}
                      {(activeModule === 'users' && isAdmin) && <UserManagementView currentUser={currentUser} appScriptUrl={appScriptUrl} showToast={showToast} validationLists={validationLists} settings={settings} />}
                      {activeModule === 'support' && <SupportView appScriptUrl={appScriptUrl} currentUser={currentUser} showToast={showToast} settings={settings} validationLists={validationLists} />}
                      {activeModule === 'track_requests' && <RequestTrackingView appScriptUrl={appScriptUrl} currentUser={currentUser} showToast={showToast} onRequestNew={() => setIsRequestModalOpen(true)} />}
                  </div>
              )}
          </main>

          <footer className="mt-auto py-6 border-t border-slate-50 text-center no-print">
              <span className="text-[9px] font-bold text-slate-300 uppercase tracking-[0.2em]">scbc@2026</span>
          </footer>
      </div>

      {isReportModalOpen && selectedReportData && (
          <ReportViewerModal 
            onClose={() => setIsReportModalOpen(false)} 
            onPrint={() => window.print()}
            title={`Report_${selectedReportData.id || 'History'}`}
          >
              {activeModule === 'petroleum' ? (
                  <PrintablePetroleumReport data={selectedReportData} settings={settings} />
              ) : activeModule === 'petroleum_v2' ? (
                  <PrintablePetroleumV2Report data={selectedReportData} settings={settings} />
              ) : activeModule === 'acid' ? (
                  <PrintableAcidReport data={selectedReportData} settings={settings} />
              ) : (
                  <PrintableGeneralReport data={selectedReportData} settings={settings} />
              )}
          </ReportViewerModal>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { SystemSettings, User } from '../types';

interface SettingsViewProps {
    settings: SystemSettings;
    setSettings: React.Dispatch<React.SetStateAction<SystemSettings>>;
    appScriptUrl: string;
    setAppScriptUrl: (url: string) => void;
    handleSaveSettings: () => void;
    isSavingSettings: boolean;
    showToast: (msg: string, type: 'success' | 'error' | 'info' | 'warning') => void;
    user?: User | null;
}

const SettingsView: React.FC<SettingsViewProps> = ({ 
    settings, setSettings, handleSaveSettings, isSavingSettings, user
}) => {
    const [logoError, setLogoError] = useState(false);

    useEffect(() => { setLogoError(false); }, [settings.companyLogo]);

    const isAdmin = user?.role === 'SuperAdmin' || user?.role === 'Admin';

    return (
        <div className="max-w-4xl mx-auto animate-fadeIn space-y-8 pb-12 font-sans">
             <div>
                <h2 className="text-2xl font-black text-slate-800 uppercase tracking-tight">Account Settings</h2>
                <p className="text-slate-400 text-[10px] font-bold uppercase tracking-[0.3em] mt-1">Workspace & Brand Identity</p>
             </div>

             {/* Company Profile Section */}
             <div className="bg-white p-10 rounded-3xl shadow-sm border border-slate-100 space-y-8">
                <div className="flex justify-between items-center">
                    <h3 className="text-lg font-bold text-slate-800 uppercase tracking-tight">Organization Profile</h3>
                    {!isAdmin && (
                        <span className="text-[10px] font-bold text-amber-600 bg-amber-50 px-3 py-1.5 rounded-full border border-amber-100 uppercase tracking-widest">Read Only Access</span>
                    )}
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                    <div className="space-y-2">
                        <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em] ml-1">Company Name</label>
                        <input 
                            type="text" 
                            disabled={!isAdmin}
                            value={settings.companyName} 
                            onChange={(e) => setSettings(s => ({...s, companyName: e.target.value}))} 
                            className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold text-slate-700 focus:ring-2 focus:ring-indigo-500/20 outline-none transition-all disabled:opacity-50" 
                        />
                    </div>
                    <div className="space-y-2">
                        <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em] ml-1">Support/Admin Email</label>
                        <input 
                            type="email" 
                            disabled={!isAdmin}
                            value={settings.managerEmail} 
                            onChange={(e) => setSettings(s => ({...s, managerEmail: e.target.value}))} 
                            className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold text-slate-700 focus:ring-2 focus:ring-indigo-500/20 outline-none transition-all disabled:opacity-50" 
                        />
                    </div>
                </div>

                <div className="space-y-2">
                    <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em] ml-1">Brand Logo (Base64/URL)</label>
                    <textarea 
                        disabled={!isAdmin}
                        value={settings.companyLogo} 
                        onChange={(e) => setSettings(s => ({...s, companyLogo: e.target.value}))} 
                        className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-mono text-[10px] text-slate-500 h-24 outline-none focus:ring-2 focus:ring-indigo-500/20 disabled:opacity-50" 
                        placeholder="Paste logo image string here..."
                    />
                </div>

                {isAdmin && (
                    <div className="flex justify-end pt-4 border-t border-slate-50">
                        <button 
                            onClick={handleSaveSettings} 
                            disabled={isSavingSettings} 
                            className="px-10 py-4 bg-slate-900 hover:bg-black text-white rounded-2xl font-black shadow-xl shadow-slate-200 flex items-center justify-center gap-3 transition-all active:scale-95 disabled:opacity-50 uppercase tracking-[0.2em] text-xs"
                        >
                            {isSavingSettings && <svg className="animate-spin h-4 w-4 text-white" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>}
                            Synchronize Profile
                        </button>
                    </div>
                )}
             </div>
        </div>
    );
}

export default SettingsView;

import React, { useState, useEffect, useMemo } from 'react';
import { User, SystemSettings, SubscriptionDetails } from '../types';
import { BACKEND_FILES } from '../constants';

interface MaintenanceViewProps {
    user: User;
    appScriptUrl: string;
    settings: SystemSettings;
    onSettingsUpdate: (newSettings: Partial<SystemSettings>) => void;
    showToast: (msg: string, type: 'success' | 'error' | 'info' | 'warning') => void;
    onRefreshSubscription?: () => void;
    subscription?: SubscriptionDetails | null;
}

interface RenewalEntry {
    id: string;
    date: string;
    durationValue: number;
    durationUnit: 'month' | 'year';
    durationLabel: string;
    expiry: string;
    admin: string;
}

const MaintenanceView: React.FC<MaintenanceViewProps> = ({ 
    user, appScriptUrl, settings, onSettingsUpdate, showToast, onRefreshSubscription, subscription 
}) => {
    // --- 1. System Control State ---
    const [msgType, setMsgType] = useState<'info' | 'warning' | 'critical'>('info');
    const [msgBody, setMsgBody] = useState('');
    const [isSending, setIsSending] = useState(false);
    const [maintMode, setMaintMode] = useState(settings.maintenanceMode || false);
    const [maintMessage, setMaintMessage] = useState(settings.maintenanceMessage || 'System under scheduled maintenance.');
    const [isSavingMaint, setIsSavingMaint] = useState(false);

    // --- 2. License Calculator State ---
    const [startDate, setStartDate] = useState(new Date().toISOString().split('T')[0]);
    const [durationValue, setDurationValue] = useState(1);
    const [durationUnit, setDurationUnit] = useState<'month' | 'year'>('month');
    const [isSavingLicense, setIsSavingLicense] = useState(false);

    // Auto-calculate expiry
    const calculatedExpiry = useMemo(() => {
        const start = new Date(startDate);
        if (durationUnit === 'month') {
            start.setMonth(start.getMonth() + Number(durationValue));
        } else {
            start.setFullYear(start.getFullYear() + Number(durationValue));
        }
        return start.toISOString().split('T')[0];
    }, [startDate, durationValue, durationUnit]);

    // Renewal History
    const [renewalHistory, setRenewalHistory] = useState<RenewalEntry[]>(() => {
        const saved = localStorage.getItem('sc_renewal_history');
        return saved ? JSON.parse(saved) : [
            { id: 'init-01', date: '2025-01-01', durationValue: 1, durationUnit: 'year', durationLabel: '1 Year', expiry: '2026-01-01', admin: 'System' }
        ];
    });

    useEffect(() => {
        setMaintMode(settings.maintenanceMode || false);
        setMaintMessage(settings.maintenanceMessage || 'System under scheduled maintenance.');
    }, [settings.maintenanceMode, settings.maintenanceMessage]);

    const handleBroadcast = async () => {
        if (!msgBody.trim()) { showToast("Please enter a message.", "error"); return; }
        setIsSending(true);
        try {
            await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify({ action: 'broadcast', type: msgType, message: msgBody }), mode: 'no-cors' });
            showToast("Broadcast sent successfully!", "success");
            setMsgBody('');
        } catch (e) { showToast("Failed to send broadcast.", "error"); } finally { setIsSending(false); }
    };

    const handleSaveMaintenance = async () => {
        setIsSavingMaint(true);
        try {
            await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify({
                    action: 'update_settings',
                    ...settings,
                    maintenanceMode: maintMode,
                    maintenanceMessage: maintMessage
                }),
                mode: 'no-cors'
            });
            onSettingsUpdate({ maintenanceMode: maintMode, maintenanceMessage: maintMessage });
            showToast(maintMode ? "SYSTEM LOCKDOWN ACTIVATED" : "System Access Restored", "success");
        } catch (e) { showToast("Failed to update status.", "error"); } finally { setIsSavingMaint(false); }
    };

    const handleUpdateLicense = async () => {
        setIsSavingLicense(true);
        try {
            const response = await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify({
                    action: 'extend_subscription',
                    expiryDate: calculatedExpiry
                })
            });

            const result = await response.json();

            if (result.status === 'success') {
                const newEntry: RenewalEntry = {
                    id: `renew-${Date.now()}`,
                    date: new Date().toISOString().split('T')[0],
                    durationValue: durationValue,
                    durationUnit: durationUnit,
                    durationLabel: `${durationValue} ${durationUnit}${durationValue > 1 ? 's' : ''}`,
                    expiry: calculatedExpiry,
                    admin: user.name || 'Admin'
                };
                const newHistory = [newEntry, ...renewalHistory].slice(0, 10);
                setRenewalHistory(newHistory);
                localStorage.setItem('sc_renewal_history', JSON.stringify(newHistory));

                showToast(`License extended until ${calculatedExpiry}`, "success");
                if (onRefreshSubscription) onRefreshSubscription();
            } else {
                throw new Error(result.message);
            }
        } catch (e) {
            showToast("Failed to update license on server.", "error");
        } finally {
            setIsSavingLicense(false);
        }
    };

    const handleDeleteHistory = (id: string) => {
        const filtered = renewalHistory.filter(h => h.id !== id);
        setRenewalHistory(filtered);
        localStorage.setItem('sc_renewal_history', JSON.stringify(filtered));
        showToast("History record removed", "info");
    };

    const handleLoadHistoryToCalculator = (entry: RenewalEntry) => {
        // Find a reasonable start date (either original entry date or now)
        setStartDate(entry.date);
        setDurationValue(entry.durationValue);
        setDurationUnit(entry.durationUnit);
        showToast("Loaded entry into calculator", "success");
        window.scrollTo({ top: 0, behavior: 'smooth' });
    };

    // --- 3. Backend/API State ---
    const [selectedFile, setSelectedFile] = useState<string>('1_Controller.gs');
    const [copyStatus, setCopyStatus] = useState<string | null>(null);
    const [localApiUrl, setLocalApiUrl] = useState(appScriptUrl);

    const handleCopyCode = () => {
        const code = BACKEND_FILES[selectedFile];
        if (code) {
            navigator.clipboard.writeText(code).then(() => {
                setCopyStatus(selectedFile);
                showToast(`${selectedFile} copied`, 'success');
                setTimeout(() => setCopyStatus(null), 2000);
            });
        }
    };

    const handleUpdateApiUrl = () => {
        onSettingsUpdate({ webAppUrl: localApiUrl });
        showToast("API Endpoint updated locally.", "success");
    };

    return (
        <div className="max-w-5xl mx-auto animate-fadeIn pb-24 space-y-12 font-sans">
            <div>
                <h1 className="text-3xl font-black text-slate-900 uppercase tracking-tight text-center sm:text-left">System Security & Core</h1>
                <p className="text-slate-400 text-[10px] font-bold uppercase tracking-[0.3em] mt-1 text-center sm:text-left">Master Administrator Console</p>
            </div>

            {/* SECTION 1: SUBSCRIPTION MANAGEMENT */}
            <section className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
                <div className="bg-slate-900 p-6 text-white flex justify-between items-center">
                    <div>
                        <h3 className="font-bold text-lg uppercase tracking-tight">Subscription & Licensing</h3>
                        <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest mt-0.5">Manage enterprise access duration</p>
                    </div>
                    <div className="w-10 h-10 bg-white/10 rounded-xl flex items-center justify-center">
                        <svg className="w-6 h-6 text-emerald-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" /></svg>
                    </div>
                </div>

                <div className="p-8 grid grid-cols-1 lg:grid-cols-2 gap-12">
                    {/* Calculator */}
                    <div className="space-y-6">
                        <h4 className="text-[11px] font-black text-slate-400 uppercase tracking-widest">New License Calculator</h4>

                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                            <div>
                                <label className="block text-[10px] font-bold text-slate-500 uppercase mb-2">Start Date</label>
                                <input 
                                    type="date" 
                                    value={startDate} 
                                    onChange={(e) => setStartDate(e.target.value)}
                                    className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl font-bold text-slate-700 outline-none focus:ring-2 focus:ring-indigo-500/20"
                                />
                            </div>
                            <div>
                                <label className="block text-[10px] font-bold text-slate-500 uppercase mb-2">Duration</label>
                                <div className="flex gap-2">
                                    <input 
                                        type="number" 
                                        min="1" 
                                        value={durationValue} 
                                        onChange={(e) => setDurationValue(Math.max(1, parseInt(e.target.value) || 1))}
                                        className="w-20 p-3 bg-slate-50 border border-slate-200 rounded-xl font-bold text-slate-700 outline-none"
                                    />
                                    <select 
                                        value={durationUnit} 
                                        onChange={(e) => setDurationUnit(e.target.value as any)}
                                        className="flex-1 p-3 bg-slate-50 border border-slate-200 rounded-xl font-bold text-slate-700 outline-none"
                                    >
                                        <option value="month">Month(s)</option>
                                        <option value="year">Year(s)</option>
                                    </select>
                                </div>
                            </div>
                        </div>

                        <div className="bg-indigo-50 rounded-2xl p-6 border border-indigo-100 flex items-center justify-between">
                            <div>
                                <p className="text-[10px] font-bold text-indigo-400 uppercase tracking-widest">Calculated Expiry</p>
                                <p className="text-2xl font-black text-indigo-900 tracking-tight">{new Date(calculatedExpiry).toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' })}</p>
                            </div>
                            <button 
                                onClick={handleUpdateLicense}
                                disabled={isSavingLicense}
                                className="px-6 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-bold text-xs uppercase tracking-widest shadow-lg shadow-indigo-200 transition-all active:scale-95 flex items-center gap-2"
                            >
                                {isSavingLicense && <svg className="animate-spin h-3 w-3 text-white" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>}
                                Commit Renewal
                            </button>
                        </div>
                    </div>

                    {/* History Table */}
                    <div className="space-y-4">
                        <h4 className="text-[11px] font-black text-slate-400 uppercase tracking-widest">Renewal History</h4>
                        <div className="border border-slate-50 rounded-2xl overflow-hidden">
                            <table className="w-full text-left text-[11px]">
                                <thead className="bg-slate-50 text-slate-400 font-bold uppercase tracking-wider">
                                    <tr>
                                        <th className="px-4 py-3">Log</th>
                                        <th className="px-4 py-3">Plan</th>
                                        <th className="px-4 py-3">Expiry Date</th>
                                        <th className="px-4 py-3 text-right pr-6">Manage</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-50">
                                    {renewalHistory.length === 0 ? (
                                        <tr><td colSpan={4} className="p-10 text-center text-slate-300 font-bold italic uppercase tracking-widest">Log Empty</td></tr>
                                    ) : (
                                        renewalHistory.map((entry) => {
                                            const isActive = subscription?.expiryDate === entry.expiry;
                                            return (
                                                <tr key={entry.id} className={`group hover:bg-slate-50/50 transition-colors ${isActive ? 'bg-indigo-50/20' : ''}`}>
                                                    <td className="px-4 py-4">
                                                        <div className="flex flex-col">
                                                            <span className="text-slate-400 opacity-60 text-[9px] font-bold uppercase">{entry.date}</span>
                                                            <span className="text-slate-700 font-bold">{entry.admin}</span>
                                                        </div>
                                                    </td>
                                                    <td className="px-4 py-4">
                                                        <span className="px-2 py-1 bg-slate-100 text-slate-500 rounded text-[9px] font-black uppercase">{entry.durationLabel}</span>
                                                    </td>
                                                    <td className="px-4 py-4">
                                                        <div className="flex items-center gap-2">
                                                            <span className={`font-black uppercase tracking-tight text-sm ${isActive ? 'text-indigo-600' : 'text-slate-500'}`}>{entry.expiry}</span>
                                                            {isActive && (
                                                                <span className="flex items-center gap-1.5 px-2 py-0.5 bg-indigo-100 text-indigo-700 rounded-full text-[8px] font-black uppercase tracking-widest animate-pulse shadow-sm shadow-indigo-100">
                                                                    <div className="w-1 h-1 rounded-full bg-indigo-600"></div>
                                                                    Active
                                                                </span>
                                                            )}
                                                        </div>
                                                    </td>
                                                    <td className="px-4 py-4 text-right pr-6">
                                                        <div className="flex justify-end gap-2 sm:opacity-0 group-hover:opacity-100 transition-opacity">
                                                            <button 
                                                                onClick={() => handleLoadHistoryToCalculator(entry)}
                                                                className="p-2 text-indigo-500 hover:bg-indigo-50 rounded-lg transition-colors"
                                                                title="Load to Calculator"
                                                            >
                                                                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
                                                            </button>
                                                            <button 
                                                                onClick={() => handleDeleteHistory(entry.id)}
                                                                className="p-2 text-rose-300 hover:text-rose-600 hover:bg-rose-50 rounded-lg transition-colors"
                                                                title="Remove from Log"
                                                            >
                                                                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                                                            </button>
                                                        </div>
                                                    </td>
                                                </tr>
                                            );
                                        })
                                    )}
                                </tbody>
                            </table>
                        </div>
                        <p className="text-[9px] text-slate-300 italic">Historical log reflects manual renewals performed via this console.</p>
                    </div>
                </div>
            </section>

            {/* SECTION 2: LOCKDOWN & BROADCAST */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                <div className="bg-white rounded-3xl shadow-sm border border-slate-100 p-8 space-y-6">
                    <div className="flex items-center gap-3">
                        <div className="w-8 h-8 bg-blue-50 text-blue-600 rounded-lg flex items-center justify-center">
                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5.882V19.24a1.76 1.76 0 01-3.417.592l-2.147-6.15M18 13a3 3 0 100-6M5.436 13.683A4.001 4.001 0 017 6h1.832c4.1 0 7.625-1.234 9.168-3v14c-1.543-1.766-5.067-3-9.168-3H7a3.988 3.988 0 01-1.564-.317z"></path></svg>
                        </div>
                        <h3 className="font-bold text-slate-800 uppercase tracking-tight">Global Broadcast</h3>
                    </div>
                    <textarea 
                        className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl h-32 outline-none focus:ring-2 focus:ring-blue-100 text-sm font-medium" 
                        placeholder="Type system alert..." 
                        value={msgBody} 
                        onChange={e => setMsgBody(e.target.value)}
                    ></textarea>
                    <button onClick={handleBroadcast} disabled={isSending} className="w-full py-4 bg-blue-600 hover:bg-blue-700 text-white font-bold rounded-2xl shadow-lg transition-all flex items-center justify-center gap-2 uppercase tracking-widest text-xs active:scale-95">
                        {isSending ? 'Broadcasting...' : 'Dispatch Alert'}
                    </button>
                </div>

                <div className="bg-rose-50 rounded-3xl border border-rose-100 p-8 space-y-6">
                    <div className="flex items-center gap-3">
                        <div className="w-8 h-8 bg-rose-100 text-rose-600 rounded-lg flex items-center justify-center">
                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z"></path></svg>
                        </div>
                        <h3 className="font-bold text-rose-800 uppercase tracking-tight">System Lockdown</h3>
                    </div>
                    <div className="flex items-center justify-between p-4 bg-white/50 rounded-2xl">
                        <span className="text-sm font-bold text-rose-700">Maintenance Mode</span>
                        <button onClick={() => setMaintMode(!maintMode)} className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${maintMode ? 'bg-rose-600' : 'bg-slate-200'}`}>
                            <span className={`inline-block h-4 w-4 transform rounded-full bg-white transition ${maintMode ? 'translate-x-6' : 'translate-x-1'}`} />
                        </button>
                    </div>
                    <button onClick={handleSaveMaintenance} disabled={isSavingMaint} className="w-full py-4 bg-rose-600 hover:bg-rose-700 text-white font-bold rounded-2xl shadow-xl transition-all flex items-center justify-center gap-2 uppercase tracking-widest text-xs active:scale-95">
                        {isSavingMaint ? 'Locking...' : 'Update System Status'}
                    </button>
                </div>
            </div>

            {/* SECTION 3: BACKEND CODE MODULES */}
            <section className="bg-white rounded-3xl shadow-sm border border-slate-100 p-8 space-y-6">
                <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                    <div>
                        <h3 className="text-lg font-bold text-slate-800 uppercase tracking-tight">Backend Code Modules</h3>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-0.5">Copy modules to Google Apps Script</p>
                    </div>
                    <div className="flex gap-2">
                        <select 
                            value={selectedFile} 
                            onChange={(e) => setSelectedFile(e.target.value)}
                            className="p-2.5 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold text-slate-700 outline-none"
                        >
                            {Object.keys(BACKEND_FILES).map(file => (
                                <option key={file} value={file}>{file}</option>
                            ))}
                        </select>
                        <button onClick={handleCopyCode} className="px-4 py-2 bg-indigo-600 text-white rounded-xl font-bold text-[10px] uppercase tracking-widest transition-all active:scale-95">
                            {copyStatus === selectedFile ? 'Copied!' : 'Copy Code'}
                        </button>
                    </div>
                </div>
                <textarea 
                    readOnly 
                    value={BACKEND_FILES[selectedFile] || ''} 
                    className="w-full h-80 p-6 bg-slate-50 border border-slate-200 rounded-2xl font-mono text-[11px] leading-relaxed text-slate-500 focus:ring-0 outline-none resize-none scrollbar-hide"
                />
            </section>

            {/* SECTION 4: API SERVER ENDPOINT */}
            <section className="bg-white rounded-3xl shadow-sm border border-slate-100 p-8 space-y-6">
                <h3 className="text-lg font-bold text-slate-800 uppercase tracking-tight flex items-center gap-2">
                    <svg className="w-5 h-5 text-indigo-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 9l3 3-3 3m5 0h3M5 20h14a2 2 0 002-2V6a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>
                    API Server Endpoint
                </h3>
                <div className="flex gap-4">
                    <input 
                        type="text" 
                        value={localApiUrl} 
                        onChange={(e) => setLocalApiUrl(e.target.value)} 
                        className="flex-1 p-4 bg-slate-50 border border-slate-200 rounded-2xl font-mono text-xs text-slate-600 outline-none focus:ring-2 focus:ring-indigo-100" 
                    />
                    <button onClick={handleUpdateApiUrl} className="px-6 py-4 bg-slate-900 text-white rounded-2xl font-bold text-[10px] uppercase tracking-widest active:scale-95 shadow-lg">
                        Update Link
                    </button>
                </div>
            </section>
        </div>
    );
};

