interface DashboardTemplateProps {
    title: string;
    description: string;
    icon: React.ReactNode;
    colorTheme: 'emerald' | 'orange' | 'rose' | 'purple' | 'blue' | 'slate';
    stats: { total: number, passRate: number | string };
    startNewInspection: () => void;
    fetchHistory: (force?: boolean) => void;
    isLoadingHistory: boolean;
    historyList: InspectionData[];
    onViewReport: (item: InspectionData) => void;
    onPrint: (item: InspectionData) => void;
    userRole?: string;
    titlePrefix?: string;
}

const DashboardTemplate: React.FC<DashboardTemplateProps> = ({ 
    title, description, icon, colorTheme, stats, 
    startNewInspection, fetchHistory, isLoadingHistory, historyList, 
    onViewReport, onPrint, userRole, titlePrefix = "INSPECTION"
}) => {
    const [searchTerm, setSearchTerm] = useState('');

    const displayList = useMemo(() => {
        let list = historyList;
        if (searchTerm.trim()) {
            const lowerSearch = searchTerm.toLowerCase();
            list = list.filter(item => 
                (item.truckNo && item.truckNo.toLowerCase().includes(lowerSearch)) ||
                (item.driverName && item.driverName.toLowerCase().includes(lowerSearch)) ||
                (item.inspectedBy && item.inspectedBy.toLowerCase().includes(lowerSearch))
            );
        } else {
            list = list.slice(0, 10);
        }
        return list;
    }, [historyList, searchTerm]);

    const isLocked = (window as any).isSubscriptionLocked || false;
    const canCreate = (userRole === 'Admin' || userRole === 'Inspector' || userRole === 'SuperAdmin') && !isLocked;

    const getThemeClasses = () => {
        const base = "border-slate-200";
        switch(colorTheme) {
            case 'orange': return { btn: 'bg-slate-900', text: 'text-slate-600', bg: 'bg-slate-50', border: base };
            case 'rose': return { btn: 'bg-slate-900', text: 'text-slate-600', bg: 'bg-slate-50', border: base };
            case 'purple': return { btn: 'bg-slate-900', text: 'text-slate-600', bg: 'bg-slate-50', border: base };
            case 'blue': return { btn: 'bg-slate-900', text: 'text-slate-600', bg: 'bg-slate-50', border: base };
            case 'slate': return { btn: 'bg-slate-900', text: 'text-slate-600', bg: 'bg-slate-50', border: base };
            default: return { btn: 'bg-slate-900', text: 'text-slate-600', bg: 'bg-slate-50', border: base };
        }
    };
    const theme = getThemeClasses();

    return (
      <div className="max-w-5xl mx-auto space-y-6 animate-fadeIn py-1">
          {/* Action Header wrapped in Lock if expired */}
          <SubscriptionLock isLocked={isLocked}>
              <div className="bg-white rounded-[2rem] p-8 border border-slate-100 shadow-sm flex flex-col md:flex-row justify-between items-center gap-8">
                   <div className="flex-1">
                       <div className="flex items-center gap-3 mb-2">
                           <span className={`p-2.5 rounded-2xl ${theme.bg} ${theme.text} shadow-inner`}>{icon}</span>
                           <h2 className="text-2xl font-medium text-slate-800 tracking-tight uppercase">{title}</h2>
                       </div>
                       {description && <p className="text-slate-500 text-xs leading-relaxed max-w-md font-normal mb-6">{description}</p>}

                       <div className="flex flex-wrap gap-4">
                           {canCreate && (
                               <button 
                                 onClick={startNewInspection}
                                 className="relative px-7 py-3 bg-slate-900 hover:bg-slate-800 text-white text-[11px] font-black rounded-2xl transition-all flex items-center gap-3 uppercase tracking-[0.2em] shadow-[0_10px_20px_-5px_rgba(15,23,42,0.3)] hover:shadow-[0_15px_25px_-5px_rgba(15,23,42,0.4)] active:scale-[0.96] group/btn border-t border-white/10"
                               >
                                   <div className="w-5 h-5 bg-white/10 rounded-lg flex items-center justify-center group-hover/btn:scale-110 group-hover/btn:rotate-90 transition-all duration-300">
                                       <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M12 4v16m8-8H4"></path></svg>
                                   </div>
                                   New Check
                               </button>
                           )}
                           <button 
                             onClick={() => fetchHistory(true)}
                             disabled={isLoadingHistory}
                             className="px-6 py-3 bg-white border border-slate-200 text-slate-500 text-[10px] font-bold rounded-2xl hover:bg-slate-50 hover:text-slate-800 transition-all flex items-center gap-2.5 uppercase tracking-widest active:scale-95 shadow-sm disabled:opacity-50 disabled:cursor-wait"
                           >
                               <svg className={`w-4 h-4 ${isLoadingHistory ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"></path></svg>
                               Refresh History
                           </button>
                       </div>
                   </div>

                   <div className="flex gap-5">
                       <div className="bg-slate-50 rounded-[1.5rem] p-5 text-center min-w-[100px] border border-slate-100 shadow-inner">
                           <div className="text-3xl font-medium text-slate-800 leading-none">{stats.total}</div>
                           <div className="text-[9px] text-slate-400 uppercase font-medium tracking-[0.2em] mt-3">Verified</div>
                       </div>
                       <div className="bg-emerald-50 rounded-[1.5rem] p-5 text-center min-w-[100px] border border-emerald-100 shadow-inner">
                           <div className="text-3xl font-medium text-emerald-600 leading-none">{stats.passRate}%</div>
                           <div className="text-[9px] text-slate-400 uppercase font-medium tracking-[0.2em] mt-3">Pass Rate</div>
                       </div>
                   </div>
              </div>
          </SubscriptionLock>

          {/* Table Container - NOT blurred, but View-Only implied */}
          <div className="bg-white rounded-[2rem] border border-slate-100 overflow-hidden shadow-sm">
              <div className="px-8 py-5 border-b border-slate-50 flex justify-between items-center bg-slate-50/30">
                  <div className="flex items-center gap-4">
                      <h3 className="text-[10px] font-medium text-slate-400 uppercase tracking-[0.3em]">Audit History</h3>
                      {isLocked && (
                          <span className="text-[9px] font-bold text-amber-600 bg-amber-50 px-2 py-0.5 rounded border border-amber-100 uppercase tracking-tighter">View Only Mode</span>
                      )}
                  </div>
                  <div className="relative">
                    <svg className="w-4 h-4 absolute left-3 top-1/2 -translate-y-1/2 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
                    <input 
                        type="text" 
                        placeholder="Filter database..." 
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="w-44 pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-xl text-[11px] outline-none font-normal focus:ring-2 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all placeholder:text-slate-300"
                    />
                  </div>
              </div>

              {isLoadingHistory ? (
                  <div className="py-24 text-center">
                      <div className="w-10 h-10 border-4 border-slate-100 border-t-slate-900 rounded-full animate-spin mx-auto mb-5"></div>
                      <p className="text-[10px] font-medium text-slate-400 uppercase tracking-[0.3em]">Syncing Records</p>
                  </div>
              ) : displayList.length === 0 ? (
                  <div className="py-24 text-center text-[11px] font-medium text-slate-300 uppercase tracking-[0.3em]">Vault is empty</div>
              ) : (
                  <div className="w-full">
                      <div className="hidden md:grid grid-cols-12 px-8 py-5 border-b border-slate-50 bg-slate-50/10 text-[10px] font-medium text-slate-400 uppercase tracking-[0.25em]">
                          <div className="col-span-1">Rate</div>
                          <div className="col-span-3">Vehicle Asset</div>
                          <div className="col-span-3">Audit Date</div>
                          <div className="col-span-3">Personnel</div>
                          <div className="col-span-2 text-right">Document</div>
                      </div>

                      <div className="divide-y divide-slate-50">
                          {displayList.map((item, i) => (
                              <div key={i} className="md:grid md:grid-cols-12 flex flex-col md:items-center px-8 py-6 hover:bg-slate-50/30 transition-colors gap-4 md:gap-0 relative group">
                                  <div className="col-span-1">
                                      <span className={`inline-flex items-center justify-center w-8 h-8 rounded-xl text-[12px] font-medium text-white shadow-sm
                                          ${Number(item.rate) >= 4 ? 'bg-emerald-500' : Number(item.rate) === 3 ? 'bg-amber-500' : 'bg-rose-500'}
                                      `}>
                                          {item.rate}
                                      </span>
                                  </div>

                                  <div className="col-span-3 min-w-0">
                                      <div className="md:hidden text-[9px] font-medium text-slate-300 uppercase tracking-widest mb-1">Vehicle Asset</div>
                                      <div className="font-medium text-slate-800 text-base leading-tight truncate uppercase tracking-tight">{item.truckNo}</div>
                                      {item.trailerNo && <div className="text-[10px] text-slate-400 font-normal uppercase tracking-wide mt-0.5">{item.trailerNo}</div>}
                                  </div>

                                  <div className="col-span-3">
                                      <div className="md:hidden text-[9px] font-medium text-slate-300 uppercase tracking-widest mb-1">Audit Date</div>
                                      <div className="text-xs font-normal text-slate-700">{new Date(item.timestamp).toLocaleDateString()}</div>
                                      <div className="text-[9px] text-slate-400 font-normal uppercase mt-0.5">{new Date(item.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</div>
                                  </div>

                                  <div className="col-span-3">
                                      <div className="md:hidden text-[9px] font-medium text-slate-300 uppercase tracking-widest mb-1">Personnel</div>
                                      <div className="flex items-center gap-3">
                                          <div className="hidden md:flex w-8 h-8 rounded-xl bg-slate-100 items-center justify-center text-[10px] font-medium text-slate-400 border border-slate-200 uppercase shadow-sm">
                                              {String(item.inspectedBy || '?').charAt(0)}
                                          </div>
                                          <span className="text-slate-600 font-normal text-xs truncate">{item.inspectedBy}</span>
                                      </div>
                                  </div>

                                  <div className="col-span-2 text-right border-t md:border-none pt-4 md:pt-0">
                                      <button 
                                        onClick={() => onViewReport(item)}
                                        className="w-full md:w-auto inline-flex items-center justify-center gap-2 px-5 py-2.5 text-[10px] font-bold text-indigo-600 bg-indigo-50 hover:bg-indigo-600 hover:text-white rounded-xl transition-all uppercase tracking-widest border border-indigo-100 shadow-sm active:scale-95 group/btn"
                                      >
                                          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path><path d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z"></path></svg>
                                          Report
                                      </button>
                                  </div>
                              </div>
                          ))}
                      </div>
                  </div>
              )}
          </div>
      </div>
    );
};

export default DashboardTemplate;

import React from 'react';

interface SubscriptionLockProps {
    isLocked: boolean;
    children: React.ReactNode;
    isSuperAdmin?: boolean; // New prop to check role
    onUnlock?: () => void; // Handler to go to settings
}

const SubscriptionLock: React.FC<SubscriptionLockProps> = ({ isLocked, children, isSuperAdmin, onUnlock }) => {
    return (
        <div className="relative">
            {/* Content - Removed blur to support "View Only" mode */}
            <div className={`transition-all duration-500 ${isLocked ? 'opacity-40 pointer-events-none select-none grayscale' : ''}`}>
                {children}
            </div>

            {/* Lock Overlay - Made smaller and focused on action blocking */}
            {isLocked && (
                <div className="absolute inset-0 z-50 flex items-center justify-center p-4">
                    <div className="bg-white/95 border border-slate-200 rounded-2xl shadow-2xl p-6 max-w-sm w-full text-center transform scale-100 animate-fadeIn">
                        <div className="w-14 h-14 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-4 shadow-inner">
                            <svg className="w-7 h-7 text-red-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z"></path></svg>
                        </div>

                        <h2 className="text-xl font-black text-slate-800 mb-1">Action Restricted</h2>
                        <p className="text-[11px] text-slate-500 mb-4 leading-relaxed">
                            System is in <strong>View-Only</strong> mode because the license has expired. No new records or updates can be added.
                        </p>

                        {isSuperAdmin ? (
                            <button 
                                onClick={onUnlock}
                                className="w-full py-3 bg-red-600 hover:bg-red-700 text-white font-bold rounded-xl transition-all shadow-lg shadow-red-200 flex items-center justify-center gap-2 text-xs uppercase tracking-widest"
                            >
                                Manage License
                            </button>
                        ) : (
                            <div className="bg-slate-50 border border-slate-100 rounded-xl p-3">
                                <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest leading-normal">
                                    Please notify your supervisor to restore full administrative access.
                                </p>
                            </div>
                        )}
                    </div>
                </div>
            )}
        </div>
    );
};

export default SubscriptionLock;

import React, { useEffect, useState } from 'react';
import { User } from '../types';

interface RequestTrackingViewProps {
    appScriptUrl: string;
    currentUser: User | null;
    showToast: (msg: string, type: 'success' | 'error' | 'info') => void;
    onRequestNew?: () => void;
}

interface RequestItem {
    id: string;
    requester: string;
    truck: string;
    trailer: string;
    type: string;
    reason: string;
    priority: string;
    assignedTo: string;
    status: string;
    timestamp: string;
}

const RequestTrackingView: React.FC<RequestTrackingViewProps> = ({ appScriptUrl, currentUser, showToast, onRequestNew }) => {
    const [requests, setRequests] = useState<RequestItem[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const isLocked = (window as any).isSubscriptionLocked || false;

    useEffect(() => {
        fetchRequests();
    }, [currentUser, appScriptUrl]);

    const fetchRequests = async () => {
        if (!appScriptUrl || !currentUser) return;
        setIsLoading(true);
        try {
            const response = await fetch(`${appScriptUrl}?t=${new Date().getTime()}`);
            const json = await response.json();

            const reqSheet = json['Inspection_Requests'];
            if (reqSheet && Array.isArray(reqSheet) && reqSheet.length > 1) {
                const myRequests = reqSheet.slice(1)
                    .map((row: any[]) => ({
                        id: row[0],
                        requester: row[1],
                        truck: row[3],
                        trailer: row[4],
                        type: row[5],
                        reason: row[6],
                        priority: row[7],
                        assignedTo: row[8],
                        status: row[9] || 'Pending',
                        timestamp: row[10]
                    }))
                    .filter((req: RequestItem) => {
                        if (currentUser.role === 'Admin' || currentUser.role === 'SuperAdmin') return true;
                        return String(req.requester).toLowerCase() === String(currentUser.name).toLowerCase();
                    })
                    .sort((a: RequestItem, b: RequestItem) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());

                setRequests(myRequests);
            } else {
                setRequests([]);
            }
        } catch (error) {
            console.error("Failed to fetch requests", error);
            showToast("Failed to load requests.", 'error');
        } finally {
            setIsLoading(false);
        }
    };

    const pendingCount = requests.filter(r => r.status === 'Pending').length;
    const completedCount = requests.filter(r => r.status === 'Completed').length;
    const completionRate = requests.length > 0 ? Math.round((completedCount / requests.length) * 100) : 0;

    return (
        <div className="max-w-6xl mx-auto space-y-8 animate-fadeIn px-4 md:px-0">
            {/* Header */}
            <div className="flex flex-col md:flex-row justify-between items-end gap-4">
                <div>
                    <h2 className="text-3xl font-black text-gray-800 flex items-center gap-3">
                        <div className="p-2 bg-indigo-100 text-indigo-700 rounded-xl shrink-0">
                            <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-6 9l2 2 4-4"></path></svg>
                        </div>
                        Requests & Tracking
                    </h2>
                    <p className="text-gray-500 font-medium mt-1 uppercase tracking-widest text-[10px]">Fleet Request Pipeline Summary</p>
                </div>
                <div className="flex gap-3 w-full md:w-auto">
                    {onRequestNew && (
                        <button 
                            onClick={onRequestNew}
                            disabled={isLocked}
                            className={`flex-1 md:flex-none px-6 py-3 text-white font-bold rounded-xl shadow-lg transition-all transform flex items-center justify-center gap-2 text-xs uppercase tracking-widest
                                ${isLocked ? 'bg-slate-300 cursor-not-allowed grayscale' : 'bg-indigo-600 hover:bg-indigo-700 active:scale-95 shadow-indigo-200'}
                            `}
                        >
                            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 4v16m8-8H4"></path></svg>
                            {isLocked ? 'Locked' : 'New Request'}
                        </button>
                    )}
                </div>
            </div>

            {/* Stats Cards */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex items-center justify-between">
                    <div>
                        <p className="text-xs font-bold text-gray-400 uppercase tracking-wide">Queue</p>
                        <h3 className="text-3xl font-black text-amber-500">{pendingCount}</h3>
                    </div>
                    <div className="w-10 h-10 rounded-xl bg-amber-50 flex items-center justify-center text-amber-500">
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                    </div>
                </div>
                <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex items-center justify-between">
                    <div>
                        <p className="text-xs font-bold text-gray-400 uppercase tracking-wide">Finished</p>
                        <h3 className="text-3xl font-black text-emerald-600">{completedCount}</h3>
                    </div>
                    <div className="w-10 h-10 rounded-xl bg-emerald-50 flex items-center justify-center text-emerald-600">
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"></path></svg>
                    </div>
                </div>
                <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex items-center justify-between">
                    <div>
                        <p className="text-xs font-bold text-gray-400 uppercase tracking-wide">Fulfillment</p>
                        <h3 className="text-3xl font-black text-indigo-600">{completionRate}%</h3>
                    </div>
                    <div className="w-10 h-10 rounded-xl bg-indigo-50 flex items-center justify-center text-indigo-600">
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z"></path></svg>
                    </div>
                </div>
            </div>

            {/* Request List */}
            <div className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden">
                <div className="block md:table w-full">
                    <div className="bg-gray-50 text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em] border-b border-gray-100 hidden md:table-header-group">
                        <div className="md:table-row">
                            <div className="md:table-cell px-8 py-5">Status</div>
                            <div className="md:table-cell px-8 py-5">Vehicle</div>
                            <div className="md:table-cell px-8 py-5">Order Detail</div>
                            <div className="md:table-cell px-8 py-5">Personnel</div>
                            <div className="md:table-cell px-8 py-5 text-right">Requested</div>
                        </div>
                    </div>
                    <div className="block md:table-row-group divide-y divide-gray-100">
                        {isLoading ? (
                            <div className="p-12 text-center text-gray-400 flex flex-col items-center">
                                <div className="w-8 h-8 border-4 border-gray-200 border-t-indigo-500 rounded-full animate-spin mb-4"></div>
                                <p className="text-[10px] font-black uppercase tracking-widest">Updating Pipeline...</p>
                            </div>
                        ) : requests.length === 0 ? (
                            <div className="p-16 text-center">
                                <h3 className="text-gray-800 font-bold mb-1">Queue Empty</h3>
                                <p className="text-sm text-gray-400">No active inspection requests found.</p>
                            </div>
                        ) : requests.map((req) => (
                            <div key={req.id} className="hover:bg-gray-50 transition block md:table-row p-6 md:p-0 relative">
                                <div className="md:table-cell md:px-8 md:py-6 block mb-4 md:mb-0">
                                    {req.status === 'Completed' ? (
                                        <span className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-xl text-[10px] font-bold bg-emerald-50 text-emerald-600 border border-emerald-100 uppercase tracking-widest">
                                            <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"></path></svg>
                                            Fulfilled
                                        </span>
                                    ) : (
                                        <span className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-xl text-[10px] font-bold bg-amber-50 text-amber-700 border border-amber-100 animate-pulse uppercase tracking-widest">
                                            <div className="w-1.5 h-1.5 rounded-full bg-amber-500"></div>
                                            Active
                                        </span>
                                    )}
                                </div>
                                <div className="md:table-cell md:px-8 md:py-6 block mb-4 md:mb-0">
                                    <div className="md:hidden text-[9px] font-black text-slate-300 uppercase tracking-widest mb-1">Vehicle Asset</div>
                                    <div className="font-bold text-gray-800 text-base">{req.truck}</div>
                                    <div className="text-[10px] text-gray-400 font-bold">{req.trailer || 'Stand-alone Unit'}</div>
                                </div>
                                <div className="md:table-cell md:px-8 md:py-6 block mb-4 md:mb-0">
                                    <div className="md:hidden text-[9px] font-black text-slate-300 uppercase tracking-widest mb-1">Classification</div>
                                    <div className="text-xs font-bold text-gray-700">{req.type} Check</div>
                                    <div className={`text-[10px] font-black uppercase mt-0.5 tracking-wider ${
                                        req.priority === 'Critical' || req.priority === 'Urgent' ? 'text-red-600' : 'text-slate-400'
                                    }`}>
                                        {req.priority} Priority
                                    </div>
