                <button onClick={onRefresh} className="text-xs text-blue-600 font-bold">Refresh</button>
            </div>
            <div className="divide-y divide-gray-100">
                {isLoading ? <div className="p-8 text-center text-gray-400">Loading...</div> :
                 filtered.map(t => (
                    <div key={t.ticketId} onClick={() => onSelect(t)} className="p-4 hover:bg-gray-50 cursor-pointer">
                        <div className="flex justify-between mb-1"><span className="font-bold text-sm">#{t.ticketId}: {t.subject}</span><span className="text-[10px] font-bold text-blue-500 uppercase">{t.status}</span></div>
                        <p className="text-xs text-gray-500 truncate">{t.description}</p>
                    </div>
                ))}
            </div>
        </div>
    );
};

const TicketDetail: React.FC<{
    ticket: SupportTicket; currentUser: User | null; isAdmin: boolean; onClose: () => void; onReply: (msg: string) => void; isSendingReply: boolean; isLocked?: boolean;
}> = ({ ticket, currentUser, isAdmin, onClose, onReply, isSendingReply, isLocked }) => {
    const [replyText, setReplyText] = useState('');
    const handleSend = () => { if(!replyText.trim() || isLocked) return; onReply(replyText); setReplyText(''); };
    return (
        <div className="bg-white rounded-xl shadow-lg border border-gray-200 overflow-hidden flex flex-col h-[500px]">
            <div className="p-4 bg-gray-50 border-b flex justify-between items-center">
                <button onClick={onClose} className="text-xs font-bold text-gray-500">← Back</button>
                <div className="flex items-center gap-2">
                    <span className="font-bold text-gray-800">{ticket.subject}</span>
                    {isLocked && <span className="text-[8px] font-bold text-amber-600 bg-amber-50 px-2 py-0.5 rounded border border-amber-100 uppercase">View Only</span>}
                </div>
            </div>
            <div className="flex-1 overflow-y-auto p-4 space-y-4">
                {ticket.comments?.map((c, i) => (
                    <div key={i} className={`p-3 rounded-xl max-w-[80%] ${c.user === currentUser?.name ? 'bg-blue-600 text-white ml-auto' : 'bg-gray-100 text-gray-700'}`}>
                        <p className="text-xs font-bold mb-1">{c.user}</p>
                        <p className="text-sm">{c.message}</p>
                    </div>
                ))}
            </div>
            {!isLocked && (
                <div className="p-4 border-t flex gap-2">
                    <input className="flex-1 border rounded-lg px-3 text-sm" placeholder="Reply..." value={replyText} onChange={e => setReplyText(e.target.value)} />
                    <button onClick={handleSend} disabled={isSendingReply || !replyText.trim()} className="px-6 py-2 bg-indigo-600 text-white font-bold rounded-lg flex items-center justify-center gap-2">
                        {isSendingReply ? <svg className="animate-spin h-4 w-4 text-white" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg> : null}
                        {isSendingReply ? 'Sending...' : 'Send'}
                    </button>
                </div>
            )}
        </div>
    );
};

const SupportView: React.FC<SupportViewProps> = ({ appScriptUrl, currentUser, showToast }) => {
    const isLocked = (window as any).isSubscriptionLocked || false;
    const [activeTab, setActiveTab] = useState<'create' | 'list'>(isLocked ? 'list' : 'create');
    const [tickets, setTickets] = useState<SupportTicket[]>([]);
    const [selectedTicket, setSelectedTicket] = useState<SupportTicket | null>(null);
    const [isLoading, setIsLoading] = useState(false);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [isSendingReply, setIsSendingReply] = useState(false);
    const [formData, setFormData] = useState({ subject: '', description: '', priority: 'Medium' });

    const fetchTickets = async () => {
        if (!appScriptUrl || !currentUser) return;
        setIsLoading(true);
        try {
            const resp = await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify({ action: 'get_tickets', email: currentUser.username, role: currentUser.role }) });
            const res = await resp.json();
            if (res.status === 'success') setTickets(res.tickets);
        } finally { setIsLoading(false); }
    };

    useEffect(() => { fetchTickets(); }, []);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (isLocked) {
            showToast("System locked: Cannot create tickets.", "error");
            return;
        }
        setIsSubmitting(true);
        try {
            const payload = { action: 'submit_support_ticket', type: 'Issue', ...formData, user: currentUser?.name, email: currentUser?.username, role: currentUser?.role };
            const resp = await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify(payload) });
            const res = await resp.json();
            if (res.status === 'success') {
                showToast("Ticket submitted successfully", "success");
                setFormData({ subject: '', description: '', priority: 'Medium' });
                setActiveTab('list');
                fetchTickets();
            }
        } catch (e) { showToast("Submission failed", "error"); } finally { setIsSubmitting(false); }
    };

    const handleReply = async (message: string) => {
        if (!selectedTicket || isLocked) return;
        setIsSendingReply(true);
        try {
            const comment = { user: currentUser?.name, role: currentUser?.role, message, timestamp: new Date().toISOString() };
            await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify({ action: 'update_ticket', ticketId: selectedTicket.ticketId, comment }), mode: 'no-cors' });
            const updated = { ...selectedTicket, comments: [...selectedTicket.comments, comment as any] };
            setSelectedTicket(updated);
            setTickets(ts => ts.map(t => t.ticketId === updated.ticketId ? updated : t));
            showToast("Reply sent", "success");
        } finally { setIsSendingReply(false); }
    };

    return (
        <div className="max-w-6xl mx-auto space-y-6 animate-fadeIn pb-12">
            <div className="flex justify-between items-center">
                <h2 className="text-2xl font-bold text-gray-800">Support Hub</h2>
                {isLocked && (
                    <span className="px-3 py-1 bg-amber-50 text-amber-700 border border-amber-100 rounded-lg text-[10px] font-bold uppercase tracking-widest animate-pulse">View Only Mode Active</span>
                )}
            </div>
            <div className="flex gap-2">
                <button 
                    onClick={() => !isLocked && setActiveTab('create')} 
                    disabled={isLocked}
                    className={`px-4 py-2 rounded-lg font-bold text-sm transition-all ${activeTab === 'create' ? 'bg-indigo-600 text-white shadow-md' : 'bg-white text-gray-500 border border-slate-200'} ${isLocked ? 'opacity-50 cursor-not-allowed grayscale' : 'hover:bg-slate-50'}`}
                >
                    New Request
                </button>
                <button onClick={() => setActiveTab('list')} className={`px-4 py-2 rounded-lg font-bold text-sm transition-all ${activeTab === 'list' ? 'bg-indigo-600 text-white shadow-md' : 'bg-white text-gray-500 border border-slate-200'} hover:bg-slate-50`}>My Tickets</button>
            </div>
            {activeTab === 'create' ? (
                <div className="bg-white p-6 rounded-xl border border-slate-100 shadow-sm max-w-2xl">
                    <form onSubmit={handleSubmit} className="space-y-4">
                        <input className="w-full p-3 bg-gray-50 border border-slate-200 rounded-lg text-sm outline-none focus:ring-2 focus:ring-indigo-100 transition-all" placeholder="Subject" value={formData.subject} onChange={e => setFormData({...formData, subject: e.target.value})} required />
                        <textarea className="w-full p-3 bg-gray-50 border border-slate-200 rounded-lg text-sm h-32 outline-none focus:ring-2 focus:ring-indigo-100 transition-all" placeholder="Description..." value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} required />
                        <button type="submit" disabled={isSubmitting} className="w-full py-3 bg-indigo-600 text-white font-bold rounded-xl flex items-center justify-center gap-2 shadow-lg active:scale-95 transition-all">
                            {isSubmitting ? <svg className="animate-spin h-5 w-5 text-white" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg> : null}
                            {isSubmitting ? 'Submitting...' : 'Submit Request'}
                        </button>
                    </form>
                </div>
            ) : selectedTicket ? (
                <TicketDetail ticket={selectedTicket} currentUser={currentUser} isAdmin={currentUser?.role === 'Admin'} onClose={() => setSelectedTicket(null)} onReply={handleReply} isSendingReply={isSendingReply} isLocked={isLocked} />
            ) : (
                <TicketList tickets={tickets} isLoading={isLoading} onRefresh={fetchTickets} onSelect={setSelectedTicket} isAdmin={false} filterStatus="ALL" />
            )}
        </div>
    );
};

