const CODE_CONTROLLER = `// =========================================================
// 1. CONTROLLER (Main Entry & Routing)
// =========================================================

function doPost(e) {
  const lock = LockService.getScriptLock();
  lock.tryLock(30000); 

  try {
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const body = e.postData ? JSON.parse(e.postData.contents) : {};
    return routeRequest(ss, body);
  } catch (err) {
    return ResponseBuilder.error(err.toString());
  } finally {
    lock.releaseLock();
  }
}

function doGet(e) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  // Standard GET triggers cleanup of old notifications
  SystemHandlers.cleanupOldNotifications(ss);
  return DataHandlers.handleGetRequest(ss);
}

function routeRequest(ss, body) {
  const action = body.action;
  const routes = {
    'login': () => AuthHandlers.handleLogin(ss, body),
    'register_user': () => AuthHandlers.handleRegisterUser(ss, body),
    'get_users': () => AuthHandlers.handleGetUsers(ss),
    'delete_user': () => AuthHandlers.handleDeleteUser(ss, body),
    'update_user': () => AuthHandlers.handleUpdateUser(ss, body),
    'acknowledge_issue': () => SystemHandlers.handleAcknowledgeIssue(ss, body),
    'request_inspection': () => SystemHandlers.handleRequestInspection(ss, body), 
    'get_acknowledgements': () => SystemHandlers.handleGetAcknowledgements(ss),
    'mark_notification_read': () => SystemHandlers.handleMarkNotificationRead(ss, body),
    'update_settings': () => SystemHandlers.handleUpdateSettings(ss, body),
    'broadcast': () => SystemHandlers.handleBroadcast(ss, body),
    'extend_subscription': () => SubscriptionHandlers.handleExtendSubscription(ss, body),
    'submit_support_ticket': () => SupportHandlers.handleSubmitSupport(ss, body),
    'get_tickets': () => SupportHandlers.handleGetTickets(ss, body),
    'update_ticket': () => SupportHandlers.handleUpdateTicket(ss, body)
  };

  if (!action || action === 'create' || !routes[action]) {
    return DataHandlers.handleDataSubmission(ss, body);
  }
  return routes[action]();
}`;

const CODE_AUTH = `// =========================================================
// 2. AUTHENTICATION & USER MANAGEMENT
// =========================================================

const AuthHandlers = {
  handleLogin: function(ss, body) {
    const username = body.username ? String(body.username).trim().toLowerCase() : "";
    const password = body.password ? String(body.password) : "";
    let userSheet = ss.getSheetByName('Users');
    if (!userSheet || userSheet.getLastRow() <= 1) return ResponseBuilder.error("No users found.", "NO_USERS");

    const data = userSheet.getDataRange().getValues();
    for (let i = 1; i < data.length; i++) {
        const row = data[i];
        if (String(row[0]).trim().toLowerCase() === username && String(row[1]) === password) {
             let prefs = {};
             try { if (row[6]) prefs = JSON.parse(row[6]); } catch(e) {}
             const user = { username: row[0], name: row[2], role: String(row[3]).trim(), position: row[4] || '', preferences: prefs };
             userSheet.getRange(i + 1, 6).setValue(new Date().toISOString());
             return ResponseBuilder.success({ user: user });
        }
    }
    return ResponseBuilder.error("Invalid credentials.", "INVALID_CREDENTIALS");
  },

  handleRegisterUser: function(ss, body) {
    let userSheet = ss.getSheetByName('Users');
    if (!userSheet) {
        userSheet = ss.insertSheet('Users');
    }
    if (userSheet.getLastRow() === 0) {
        userSheet.appendRow(["Username", "Password", "Name", "Role", "Position", "Last_Login", "Preferences"]);
        userSheet.setFrozenRows(1);
    }
    const username = body.username ? String(body.username).trim().toLowerCase() : "";
    const data = userSheet.getDataRange().getValues();
    for(let i=1; i<data.length; i++) {
        if(String(data[i][0]).trim().toLowerCase() === username) return ResponseBuilder.error("User exists.");
    }
    const defaultPrefs = JSON.stringify({ emailNotifications: true, notifyGeneral: true, notifyPetroleum: true, notifyPetroleumV2: true, notifyAcid: true });
    userSheet.appendRow([username, body.password || "1234", body.name, String(body.role).trim(), body.position || "", new Date().toISOString(), defaultPrefs]);
    return ResponseBuilder.success({ message: "User registered." });
  },

  handleGetUsers: function(ss) {
    let userSheet = ss.getSheetByName('Users');
    if (!userSheet) return ResponseBuilder.success({ users: [] });
    const data = userSheet.getDataRange().getValues();
    const users = [];
    for (let i = 1; i < data.length; i++) {
        if (data[i][0]) users.push({ username: data[i][0], name: data[i][2], role: data[i][3], position: data[i][4], lastLogin: data[i][5] });
    }
    return ResponseBuilder.success({ users: users });
  },

  handleDeleteUser: function(ss, body) {
    let userSheet = ss.getSheetByName('Users');
    const username = String(body.username).toLowerCase();
    const data = userSheet.getDataRange().getValues();
    for (let i = 1; i < data.length; i++) {
        if (String(data[i][0]).toLowerCase() === username) {
            userSheet.deleteRow(i + 1);
            return ResponseBuilder.success();
        }
    }
    return ResponseBuilder.error("Not found");
  },

  handleUpdateUser: function(ss, body) {
    let userSheet = ss.getSheetByName('Users');
    const currentUsername = body.originalUsername ? String(body.originalUsername).toLowerCase() : String(body.username).toLowerCase();
    const data = userSheet.getDataRange().getValues();
    for (let i = 1; i < data.length; i++) {
        if (String(data[i][0]).toLowerCase() === currentUsername) {
            if (body.username) userSheet.getRange(i + 1, 1).setValue(String(body.username).toLowerCase());
            if (body.name) userSheet.getRange(i + 1, 3).setValue(body.name);
            if (body.role) userSheet.getRange(i + 1, 4).setValue(String(body.role).trim());
            if (body.position !== undefined) userSheet.getRange(i + 1, 5).setValue(body.position);
            if (body.preferences) userSheet.getRange(i + 1, 7).setValue(JSON.stringify(body.preferences));
            if (body.password) userSheet.getRange(i + 1, 2).setValue(body.password);
            return ResponseBuilder.success();
        }
    }
    return ResponseBuilder.error("Not found");
  }
};`;

const CODE_CORE_OPS = `// =========================================================
// 3. CORE OPERATIONS (Data, Systems, Subscription)
// =========================================================

const DataHandlers = {
  handleDataSubmission: function(ss, body) {
    const sheetName = body.sheet;
    let sheet = ss.getSheetByName(sheetName);
    if (!sheet) {
      sheet = ss.insertSheet(sheetName);
    }
    if (sheet.getLastRow() === 0 && body.headers) {
      sheet.appendRow(body.headers);
      sheet.setFrozenRows(1);
    }
    sheet.appendRow(body.row.map(r => r === null ? "" : String(r)));
    return ResponseBuilder.success({ sheet: sheetName });
  },

  handleGetRequest: function(ss) {
    const sheets = ss.getSheets();
    const data = {};
    sheets.forEach(sheet => {
      const name = sheet.getName();
      if (name === 'Users' || name === 'System_Logs') return;

      const lastRow = sheet.getLastRow();
      if (lastRow === 0) {
          data[name] = [];
          return;
      }

      if (name === 'Validation_Data') {
         const values = sheet.getDataRange().getValues();
         const columns = {};
         if (values.length > 0) {
             const headers = values[0];
             headers.forEach((h, idx) => {
                 columns[h] = values.slice(1).map(r => r[idx]).filter(v => v !== "");
             });
         }
         data[name] = columns;
      } else if (name === 'Acknowledgements') {
          data[name] = sheet.getRange(1, 1, lastRow, 1).getValues().flat().filter(v => v !== "");
      } else if (name === 'Subscription_Data') {
          const values = sheet.getDataRange().getValues();
          if (values.length > 1) {
            const history = values.slice(1).map(row => {
                // CLEAN DATES FOR FRONTEND
                let expiry = row[2];
                if (expiry instanceof Date) expiry = Utilities.formatDate(expiry, ss.getSpreadsheetTimeZone(), "yyyy-MM-dd");

                let ts = row[4];
                if (ts instanceof Date) ts = Utilities.formatDate(ts, ss.getSpreadsheetTimeZone(), "yyyy-MM-dd");
                else if (typeof ts === 'string') ts = ts.split('T')[0];

                return {
                    status: row[0],
                    plan: row[1],
                    expiryDate: String(expiry).split('T')[0],
                    processedBy: row[3] || 'System',
                    timestamp: ts || ''
                };
            });
            const last = history.length > 0 ? history[history.length - 1] : { status: "Expired", plan: "None", expiryDate: "" };
            data[name] = { current: last, history: history };
          } else {
            data[name] = { current: { status: "Expired", plan: "None", expiryDate: "" }, history: [] };
          }
      } else {
         const startRow = Math.max(1, lastRow - 150);
         data[name] = sheet.getRange(startRow, 1, lastRow - startRow + 1, sheet.getLastColumn()).getValues();
      }
    });
    return ContentService.createTextOutput(JSON.stringify(data)).setMimeType(ContentService.MimeType.JSON);
  }
};

const SystemHandlers = {
  handleUpdateSettings: function(ss, body) {
    let sheet = ss.getSheetByName('System_Settings');
    if (!sheet) {
        sheet = ss.insertSheet('System_Settings');
        sheet.appendRow(["Company_Name", "Admin_Email", "Last_Updated", "Updated_By", "Logo", "APK_Link", "Web_URL", "Maint_Mode", "Maint_Msg"]);
        sheet.setFrozenRows(1);
    }
    sheet.appendRow([
        body.companyName || '', 
        body.managerEmail || '', 
        new Date().toISOString(), 
        body.updatedBy || 'Admin',
        body.companyLogo || '',
        body.mobileApkLink || '',
        body.webAppUrl || '',
        body.maintenanceMode === true ? "TRUE" : "FALSE",
        body.maintenanceMessage || ''
    ]);
    return ResponseBuilder.success();
  },

  cleanupOldNotifications: function(ss) {
    const sheetsToClean = ['SystemNotification', 'Acknowledgements'];
    const now = new Date().getTime();
    const oneDay = 24 * 60 * 60 * 1000;

    sheetsToClean.forEach(name => {
        const sheet = ss.getSheetByName(name);
        if (!sheet) return;
        const data = sheet.getDataRange().getValues();
        if (data.length <= 1) return;
        const tsColIdx = (name === 'SystemNotification') ? 4 : 3;
        for (let i = data.length - 1; i >= 1; i--) {
            const tsValue = data[i][tsColIdx];
            if (!tsValue) continue;
            const ts = new Date(tsValue).getTime();
            if (now - ts > oneDay) {
                sheet.deleteRow(i + 1);
            }
        }
    });
  },

  handleBroadcast: function(ss, body) {
    let sheet = ss.getSheetByName('SystemNotification');
    if (!sheet) {
        sheet = ss.insertSheet('SystemNotification');
    }
    if (sheet.getLastRow() === 0) {
        sheet.appendRow(["ID", "Recipient", "Type", "Message", "Timestamp", "IsRead", "Action"]);
        sheet.setFrozenRows(1);
    }
    sheet.appendRow(["SYS-" + Date.now(), "all", body.type, body.message, new Date().toISOString(), "FALSE", ""]);
    return ResponseBuilder.success();
  },

  handleAcknowledgeIssue: function(ss, body) {
    let sheet = ss.getSheetByName('Acknowledgements');
    if (!sheet) {
        sheet = ss.insertSheet('Acknowledgements');
    }
    if (sheet.getLastRow() === 0) {
        sheet.appendRow(['Issue_ID', 'User', 'Role', 'Timestamp']);
        sheet.setFrozenRows(1);
    }
    sheet.appendRow([String(body.issueId), body.user, body.role, new Date().toISOString()]);
    return ResponseBuilder.success();
  },

  handleMarkNotificationRead: function(ss, body) {
    const sheet = ss.getSheetByName('SystemNotification');
    const data = sheet.getDataRange().getValues();
    for (let i = 1; i < data.length; i++) {
        if (String(data[i][0]) === String(body.id)) {
            sheet.getRange(i + 1, 6).setValue("TRUE");
            return ResponseBuilder.success();
        }
    }
    return ResponseBuilder.error("Not found");
  }
};

const SubscriptionHandlers = {
  handleExtendSubscription: function(ss, body) {
    let sheet = ss.getSheetByName('Subscription_Data');
    if (!sheet) {
      sheet = ss.insertSheet('Subscription_Data');
    }
    if (sheet.getLastRow() === 0 || sheet.getRange(1,1).getValue() === "") {
      sheet.getRange(1, 1, 1, 5).setValues([["Status", "Plan", "ExpiryDate", "ProcessedBy", "Timestamp"]]);
      sheet.setFrozenRows(1);
    }
    // SUPPORT DYNAMIC PLAN SELECTION
    sheet.appendRow(["Active", body.plan || "Enterprise", body.expiryDate, body.processedBy || "Admin", new Date()]);
    return ResponseBuilder.success({ message: "Subscription extended successfully" });
  }
};`;

const CODE_LIB = `const ResponseBuilder = {
