    let sheet = ss.getSheetByName('SystemNotification');
    if (!sheet) {
        sheet = ss.insertSheet('SystemNotification');
    }
    if (sheet.getLastRow() === 0) {
        sheet.appendRow(["ID", "Recipient", "Type", "Message", "Timestamp", "IsRead", "Action"]);
        sheet.setFrozenRows(1);
    }
    sheet.appendRow(["SYS-" + Date.now(), "all", body.type, body.message, new Date().toISOString(), "FALSE", ""]);
    return ResponseBuilder.success();
  },

  handleAcknowledgeIssue: function(ss, body) {
    let sheet = ss.getSheetByName('Acknowledgements');
    if (!sheet) {
        sheet = ss.insertSheet('Acknowledgements');
    }
    if (sheet.getLastRow() === 0) {
        sheet.appendRow(['Issue_ID', 'User', 'Role', 'Timestamp']);
        sheet.setFrozenRows(1);
    }
    sheet.appendRow([String(body.issueId), body.user, body.role, new Date().toISOString()]);
    return ResponseBuilder.success();
  },

  handleMarkNotificationRead: function(ss, body) {
    const sheet = ss.getSheetByName('SystemNotification');
    const data = sheet.getDataRange().getValues();
    for (let i = 1; i < data.length; i++) {
        if (String(data[i][0]) === String(body.id)) {
            sheet.getRange(i + 1, 6).setValue("TRUE");
            return ResponseBuilder.success();
        }
    }
    return ResponseBuilder.error("Not found");
  }
};

const SubscriptionHandlers = {
  handleExtendSubscription: function(ss, body) {
    let sheet = ss.getSheetByName('Subscription_Data');
    if (!sheet) {
      sheet = ss.insertSheet('Subscription_Data');
    }
    if (sheet.getLastRow() === 0 || sheet.getRange(1,1).getValue() === "") {
      sheet.getRange(1, 1, 1, 5).setValues([["Status", "Plan", "ExpiryDate", "ProcessedBy", "Timestamp"]]);
      sheet.setFrozenRows(1);
    }
    // SUPPORT DYNAMIC PLAN SELECTION
    sheet.appendRow(["Active", body.plan || "Enterprise", body.expiryDate, body.processedBy || "Admin", new Date()]);
    return ResponseBuilder.success({ message: "Subscription extended successfully" });
  }
};`;

const CODE_LIB = `const ResponseBuilder = {
  success: function(data = {}) { return this.build({ status: "success", ...data }); },
  error: function(message) { return this.build({ status: "error", message: message }); },
  build: function(data) { return ContentService.createTextOutput(JSON.stringify(data)).setMimeType(ContentService.MimeType.JSON); }
};`;

export const BACKEND_FILES: Record<string, string> = {
    '1_Controller.gs': CODE_CONTROLLER,
    '2_Auth.gs': CODE_AUTH,
    '3_Core.gs': CODE_CORE_OPS,
    '5_Utils.gs': CODE_LIB
};

export const BACKEND_SCRIPT_TEMPLATE = Object.values(BACKEND_FILES).join('\n\n');

import { useState, useEffect } from 'react';
import { SubscriptionDetails, User } from '../types';

export const useSubscription = (appScriptUrl: string, currentUser: User | null) => {
    const [subscription, setSubscription] = useState<SubscriptionDetails | null>(null);
    const [history, setHistory] = useState<any[]>([]);
    const [isLoading, setIsLoading] = useState(false);

    const fetchSubscription = async () => {
        if (!appScriptUrl || typeof appScriptUrl !== 'string' || !appScriptUrl.startsWith('http')) return;
        if (!currentUser) return;

        setIsLoading(true);
        try {
            const response = await fetch(`${appScriptUrl}?t=${new Date().getTime()}`);
            if (!response.ok) return;

            const json = await response.json();

            if (json['Subscription_Data']) {
                const data = json['Subscription_Data'];
                const current = data.current || data; 
                const serverHistory = data.history || [];

                // Robust date parsing: Normalize to the end of that specific day
                const rawDateStr = String(current.expiryDate || '').trim();

                // STRICTOR CHECK: If there is no date string, it is absolutely expired.
                if (!rawDateStr || rawDateStr === "undefined" || rawDateStr === "null" || rawDateStr === "") {
                    setSubscription({
                        status: 'Expired',
                        plan: 'None',
                        expiryDate: '',
                        daysRemaining: 0
                    });
                    setHistory(serverHistory);
                    return;
                }

                const dateOnly = rawDateStr.split('T')[0];
                const parts = dateOnly.split('-');

                let expiry: Date;
                if (parts.length === 3) {
                    // Set to 23:59:59 of the expiry date
                    expiry = new Date(parseInt(parts[0]), parseInt(parts[1]) - 1, parseInt(parts[2]), 23, 59, 59);
                } else {
                    expiry = new Date(rawDateStr);
                    expiry.setHours(23, 59, 59, 999);
                }

                if (isNaN(expiry.getTime())) {
                    // Invalid date parsed
                    setSubscription({
                        status: 'Expired',
                        plan: 'None',
                        expiryDate: '',
                        daysRemaining: 0
                    });
                    return;
                }

                const now = new Date();
                const diffTime = expiry.getTime() - now.getTime();
                const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

                // Overriding sheet status if time has run out or date is invalid
                const isSystemExpired = diffDays <= 0;

                setSubscription({
                    status: isSystemExpired ? 'Expired' : (current.status || 'Active'),
                    plan: current.plan || 'Standard',
                    expiryDate: dateOnly,
                    daysRemaining: Math.max(0, diffDays)
                });
                setHistory(serverHistory);
            } else {
                // Failsafe: No sheet data at all = Expired
                setSubscription({
                    status: 'Expired',
                    plan: 'None',
                    expiryDate: '',
                    daysRemaining: 0
                });
            }
        } catch (error) {
            console.error("Subscription fetch error:", error);
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        fetchSubscription();
    }, [appScriptUrl, currentUser]);

    return { subscription, history, isLoading, refreshSubscription: fetchSubscription };
};

import React, { useState, useEffect, useMemo } from 'react';
