                 <div className="px-5 py-4 border-b border-slate-50 shrink-0">
                        <div className="flex items-center gap-3">
                            <div className="w-8 h-8 rounded-lg bg-indigo-50 flex items-center justify-center text-indigo-600 shrink-0 overflow-hidden p-1">
                                {settings.companyLogo && !logoError ? (
