import { SystemSettings, User, SubscriptionDetails } from '../../types';

interface SidebarProps {
  isOpen: boolean;
  onClose: () => void;
  activeModule: string;
  onSelectModule: (m: string) => void;
  settings: SystemSettings;
  user?: User; 
  onLogout?: () => void;
  onEditProfile?: () => void; 
  onLockedItemClick?: (featureName: string) => void;
  subscription?: SubscriptionDetails | null;
  onRequestInspection?: () => void; 
}

const Sidebar: React.FC<SidebarProps> = ({ isOpen, onClose, activeModule, onSelectModule, settings, user, onLogout, onEditProfile, onLockedItemClick, subscription, onRequestInspection }) => {

    const roleStr = user?.role ? String(user.role).toLowerCase() : '';
    const isAdmin = roleStr === 'admin' || roleStr === 'superadmin';
    const isSuperAdmin = roleStr === 'superadmin';
    const isExpired = subscription?.status === 'Expired';

    const canAccessRequests = isAdmin || ['inspector', 'operations', 'maintenance', 'secretary', 'other', 'clerk'].includes(roleStr);

    const [logoError, setLogoError] = useState(false);

    useEffect(() => {
        setLogoError(false);
    }, [settings.companyLogo]);

    const handleShareApp = async () => {
        const shareData = {
            title: settings.companyName || 'SafetyCheck Pro',
            text: `Access the ${settings.companyName || 'Fleet'} Inspection Portal here:`,
            url: settings.webAppUrl || window.location.href
        };
        try {
            if (navigator.share) {
                await navigator.share(shareData);
            } else {
                await navigator.clipboard.writeText(shareData.url);
                alert("Link copied to clipboard!");
            }
        } catch (err) {
            console.error("Error sharing:", err);
        }
    };

    const NavItem = ({ id, label, icon, isLocked = false, isDanger = false, onClickCustom, showLockIcon = false }: { id: string, label: string, icon: React.ReactNode, isLocked?: boolean, isDanger?: boolean, onClickCustom?: () => void, showLockIcon?: boolean }) => {
        const isActive = activeModule === id;

        return (
            <button
                onClick={() => { 
                    if (onClickCustom) {
                        onClickCustom();
                        return;
                    }
                    if (isLocked && onLockedItemClick) {
                        onLockedItemClick(label);
                        onClose();
                    } else {
                        onSelectModule(id); 
                        onClose(); 
                    }
                }}
                className={`w-full group relative flex items-center gap-2.5 px-3 py-1 rounded-md transition-all duration-150
                    ${isActive 
                        ? (isDanger ? 'bg-red-50 text-red-700' : 'bg-slate-100 text-slate-900 shadow-sm')
                        : isLocked 
                            ? 'text-slate-300 cursor-not-allowed opacity-50' 
                            : isDanger 
                                ? 'text-red-500 hover:bg-red-50'
                                : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'
                    }
                `}
            >
                {isActive && (
                    <div className={`absolute left-0 top-1.5 bottom-1.5 w-1 rounded-r-full ${isDanger ? 'bg-red-600' : 'bg-indigo-600'}`}></div>
                )}

                <span className={`shrink-0 transition-colors ${isActive ? (isDanger ? 'text-red-500' : 'text-indigo-600') : 'text-slate-400 group-hover:text-slate-600'}`}>
                    {React.cloneElement(icon as React.ReactElement<{ className?: string }>, { className: "w-4 h-4" })}
                </span>

                <span className={`text-[13px] tracking-tight truncate flex-1 text-left
                    ${isActive ? (isDanger ? 'text-red-800 font-bold' : 'text-slate-900 font-semibold') 
                               : isLocked ? 'text-slate-300 font-normal' 
                               : 'text-slate-600 group-hover:text-slate-900 font-medium'}`}>
                    {label}
                </span>

                {(isLocked || showLockIcon) && (
                    <svg className={`w-3 h-3 ${isLocked ? 'text-slate-200' : 'text-amber-400'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z"></path></svg>
                )}
            </button>
        );
    };

    return (
