import React, { useState } from 'react';
import { User, SystemSettings, UserPreferences } from '../../types';

interface ProfileModalProps {
    user: User;
    settings: SystemSettings;
    appScriptUrl: string;
    onClose: () => void;
    showToast: (msg: string, type: 'success' | 'error' | 'info' | 'warning') => void;
    onUpdateSuccess: (newUser: User) => void;
    onLogout: () => void;
}

const ProfileModal: React.FC<ProfileModalProps> = ({ 
    user, 
    settings, 
    appScriptUrl, 
    onClose, 
    showToast, 
    onUpdateSuccess, 
    onLogout
}) => {
    const nameParts = (user.name || '').split(' ');
    const firstName = nameParts[0] || '';
    const lastName = nameParts.slice(1).join(' ') || '';

    // Password State
    const [password, setPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [isUpdatingPassword, setIsUpdatingPassword] = useState(false);

    // Preferences State
    const [prefs, setPrefs] = useState<UserPreferences>(user.preferences || {
        emailNotifications: true,
        notifyGeneral: true,
        notifyPetroleum: true,
        notifyPetroleumV2: true,
        notifyAcid: true
    });
    const [isUpdatingPrefs, setIsUpdatingPrefs] = useState(false);

    const handlePasswordChange = async () => {
        if (!password) {
            showToast("Please enter a new password.", "warning");
            return;
        }
        if (password !== confirmPassword) {
            showToast("Passwords do not match.", "error");
            return;
        }

        setIsUpdatingPassword(true);
        try {
            const response = await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify({
                    action: 'update_user',
                    originalUsername: user.username,
                    password: password
                })
            });
            const result = await response.json();

            if (result.status === 'success') {
                showToast("Security updated!", 'success');
                setPassword('');
                setConfirmPassword('');
            } else {
                showToast(result.message || "Failed to update.", 'error');
            }
        } catch (e) {
            showToast("Sync failed.", 'error');
        } finally {
            setIsUpdatingPassword(false);
        }
    };

    const handleUpdatePrefs = async (newPrefs: UserPreferences) => {
        setPrefs(newPrefs);
        setIsUpdatingPrefs(true);
        try {
            const response = await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify({
                    action: 'update_user',
                    originalUsername: user.username,
                    preferences: newPrefs
                })
            });
            const result = await response.json();
            if (result.status === 'success') {
                onUpdateSuccess({ ...user, preferences: newPrefs });
                showToast("Preferences synced.", 'success');
            }
        } catch (e) {
            showToast("Sync failed.", 'error');
        } finally {
            setIsUpdatingPrefs(false);
        }
    };

    const togglePref = (key: keyof UserPreferences) => {
        const next = { ...prefs, [key]: !prefs[key] };
        handleUpdatePrefs(next);
    };

    const handleShareApp = async () => {
        const shareData = {
            title: settings.companyName || 'SafetyCheck Pro',
            text: `Access the ${settings.companyName || 'Fleet'} Inspection Portal here:`,
            url: settings.webAppUrl || window.location.href
        };
        try {
            if (navigator.share) {
                await navigator.share(shareData);
            } else {
                await navigator.clipboard.writeText(shareData.url);
                showToast("Portal link copied to clipboard.", "info");
            }
        } catch (err) {
            console.error("Error sharing:", err);
        }
    };

    return (
        <div className="fixed inset-0 z-[100] bg-white flex flex-col animate-fadeIn overflow-y-auto">
            {/* Header */}
            <div className="sticky top-0 bg-white border-b border-gray-100 px-4 py-3 flex items-center shrink-0 z-10 shadow-sm">
                <button 
                    onClick={onClose}
                    className="p-2 text-blue-500 hover:bg-blue-50 rounded-full transition-all"
                >
                    <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M15 19l-7-7 7-7"></path></svg>
                </button>
                <h1 className="flex-1 text-center font-bold text-slate-800 text-sm uppercase tracking-widest">My Workspace</h1>
                <div className="w-10"></div>
            </div>

            <div className="max-w-2xl mx-auto w-full px-6 py-10 space-y-12 pb-24">

                {/* 1. YOUR DETAILS */}
                <section className="space-y-4">
                    <h3 className="text-lg font-bold text-slate-800 border-b border-gray-100 pb-2 uppercase tracking-tight">Identity Profile</h3>
                    <div className="space-y-3">
                        <div className="flex justify-between items-center text-sm py-1">
                            <span className="font-semibold text-slate-600">Organization</span>
                            <span className="text-slate-400 font-medium">{settings.companyName || 'Transport Pro'}</span>
                        </div>
                        <div className="flex justify-between items-center text-sm py-1">
                            <span className="font-semibold text-slate-600">First Name</span>
                            <span className="text-slate-400 font-medium">{firstName}</span>
                        </div>
                        <div className="flex justify-between items-center text-sm py-1">
                            <span className="font-semibold text-slate-600">Last Name</span>
                            <span className="text-slate-400 font-medium">{lastName}</span>
                        </div>
                        <div className="flex justify-between items-center text-sm py-1">
                            <span className="font-semibold text-slate-600">Login ID</span>
                            <span className="text-slate-400 font-medium">{user.username}</span>
                        </div>
                    </div>
                </section>

                {/* 2. SHARE APPLICATION */}
                <section className="space-y-4">
                    <h3 className="text-lg font-bold text-slate-800 border-b border-gray-100 pb-2 uppercase tracking-tight">Share Application</h3>
                    <div className="bg-slate-50 p-6 rounded-2xl border border-slate-100 flex flex-col items-center gap-4">
                        <p className="text-sm text-slate-600 text-center font-medium">Invite colleagues or save the link to your device for quick access.</p>
                        <button 
                            onClick={handleShareApp}
                            className="w-full py-4 bg-emerald-600 hover:bg-emerald-700 text-white font-bold rounded-xl shadow-lg transition-all active:scale-95 flex items-center justify-center gap-2 text-xs uppercase tracking-widest"
                        >
                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z"></path></svg>
                            Share Access Link
                        </button>
                    </div>
                </section>

                {/* 3. CHANGE PASSWORD */}
