                    <div key={i} className={`p-4 rounded-2xl shadow-sm border ${c.user === currentUser?.name ? 'bg-indigo-600 text-white ml-auto border-indigo-500' : 'bg-white text-gray-700 mr-auto border-slate-100'} max-w-[85%]`}>
                        <div className="flex justify-between items-center mb-1 gap-4">
                            <p className="text-[10px] font-black uppercase tracking-widest opacity-80">{c.user}</p>
                            <p className="text-[9px] opacity-60">{new Date(c.timestamp).toLocaleDateString()}</p>
                        </div>
                        <p className="text-sm font-medium leading-relaxed">{c.message}</p>
