                ))}
            </div>
            {!isLocked && (
                <div className="p-4 border-t bg-white flex gap-3">
                    <input className="flex-1 border border-slate-200 rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-indigo-100 outline-none transition-all" placeholder="Type your response here..." value={replyText} onChange={e => setReplyText(e.target.value)} />
                    <button onClick={handleSend} disabled={isSendingReply || !replyText.trim()} className="px-6 py-3 bg-indigo-600 hover:bg-indigo-700 text-white font-bold rounded-xl flex items-center justify-center gap-2 transition-all active:scale-95 shadow-md disabled:bg-slate-300">
                        {isSendingReply ? <svg className="animate-spin h-4 w-4 text-white" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg> : null}
                        {isSendingReply ? 'Sending' : 'Reply'}
                    </button>
                </div>
            )}
        </div>
    );
};

const SupportView: React.FC<SupportViewProps> = ({ appScriptUrl, currentUser, showToast }) => {
    const isLocked = (window as any).isSubscriptionLocked || false;
    const [activeTab, setActiveTab] = useState<'create' | 'list'>(isLocked ? 'list' : 'create');
    const [tickets, setTickets] = useState<SupportTicket[]>([]);
    const [selectedTicket, setSelectedTicket] = useState<SupportTicket | null>(null);
    const [isLoading, setIsLoading] = useState(false);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [isSendingReply, setIsSendingReply] = useState(false);
    const [formData, setFormData] = useState({ subject: '', description: '', priority: 'Medium' });

    const fetchTickets = async () => {
        if (!appScriptUrl || !currentUser) return;
        setIsLoading(true);
        try {
            const resp = await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify({ action: 'get_tickets', email: currentUser.username, role: currentUser.role }) });
            const res = await resp.json();
            if (res.status === 'success') setTickets(res.tickets);
        } finally { setIsLoading(false); }
    };

    useEffect(() => { fetchTickets(); }, []);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (isLocked) {
            showToast("System locked: Cannot create tickets.", "error");
            return;
        }
        setIsSubmitting(true);
        try {
            const payload = { action: 'submit_support_ticket', type: 'Issue', ...formData, user: currentUser?.name, email: currentUser?.username, role: currentUser?.role };
            const resp = await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify(payload) });
            const res = await resp.json();
            if (res.status === 'success') {
                showToast("Help ticket submitted successfully", "success");
                setFormData({ subject: '', description: '', priority: 'Medium' });
                setActiveTab('list');
                fetchTickets();
            }
        } catch (e) { showToast("Submission failed", "error"); } finally { setIsSubmitting(false); }
    };

    const handleReply = async (message: string) => {
        if (!selectedTicket || isLocked) return;
        setIsSendingReply(true);
        try {
            const comment = { user: currentUser?.name, role: currentUser?.role, message, timestamp: new Date().toISOString() };
            await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify({ action: 'update_ticket', ticketId: selectedTicket.ticketId, comment }), mode: 'no-cors' });
            const updated = { ...selectedTicket, comments: [...selectedTicket.comments, comment as any] };
            setSelectedTicket(updated);
            setTickets(ts => ts.map(t => t.ticketId === updated.ticketId ? updated : t));
            showToast("Response sent", "success");
        } finally { setIsSendingReply(false); }
    };

    return (
        <div className="max-w-6xl mx-auto space-y-8 animate-fadeIn pb-12 px-4 md:px-0 font-sans">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                <div>
                    <h2 className="text-3xl font-black text-slate-800 uppercase tracking-tight leading-none flex items-center gap-3">
                        <div className="p-2 bg-amber-100 text-amber-600 rounded-xl shrink-0 shadow-sm border border-amber-50">
                            <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M18.364 5.636l-3.536 3.536m0 5.656l3.536 3.536M9.172 9.172L5.636 5.636m3.536 9.192l-3.536 3.536M21 12a9 9 0 11-18 0 9 9 0 0118 0zm-5 0a4 4 0 11-8 0 4 4 0 018 0z"></path></svg>
                        </div>
                        Help & Support Center
                    </h2>
                    <p className="text-[10px] text-slate-400 font-bold uppercase tracking-[0.3em] mt-3">Technical Assistance & Issue Resolution</p>
                </div>
                {isLocked && (
                    <span className="px-4 py-2 bg-amber-50 text-amber-700 border border-amber-100 rounded-xl text-[10px] font-black uppercase tracking-[0.2em] animate-pulse">Restricted Access Mode</span>
                )}
            </div>

            <div className="flex gap-3 bg-slate-50 p-1.5 rounded-2xl w-fit border border-slate-100 shadow-inner">
                <button 
                    onClick={() => !isLocked && setActiveTab('create')} 
                    disabled={isLocked}
                    className={`px-6 py-2.5 rounded-xl font-black text-[11px] uppercase tracking-widest transition-all ${activeTab === 'create' ? 'bg-white text-indigo-600 shadow-md border border-slate-100' : 'text-slate-400'} ${isLocked ? 'opacity-30 cursor-not-allowed grayscale' : 'hover:text-indigo-500'}`}
                >
                    Report Issue
                </button>
                <button onClick={() => setActiveTab('list')} className={`px-6 py-2.5 rounded-xl font-black text-[11px] uppercase tracking-widest transition-all ${activeTab === 'list' ? 'bg-white text-indigo-600 shadow-md border border-slate-100' : 'text-slate-400'} hover:text-indigo-500`}>Ticket History</button>
            </div>

            {activeTab === 'create' ? (
                <div className="bg-white p-8 sm:p-10 rounded-[2rem] border border-slate-100 shadow-sm max-w-2xl animate-fadeIn">
                    <h3 className="text-xl font-black text-slate-800 uppercase tracking-tight mb-2">New Support Ticket</h3>
                    <p className="text-slate-400 text-xs font-medium mb-8">Describe the issue in detail and our technical team will review it.</p>
                    <form onSubmit={handleSubmit} className="space-y-6">
                        <div className="space-y-2">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Subject / Problem Title</label>
                            <input className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-bold text-slate-700 outline-none focus:ring-4 focus:ring-indigo-100 transition-all" placeholder="What needs attention?" value={formData.subject} onChange={e => setFormData({...formData, subject: e.target.value})} required />
                        </div>
                        <div className="space-y-2">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Details & Description</label>
                            <textarea className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-medium text-slate-600 h-40 outline-none focus:ring-4 focus:ring-indigo-100 transition-all resize-none" placeholder="Provide as much detail as possible..." value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} required />
                        </div>
                        <button type="submit" disabled={isSubmitting} className="w-full py-5 bg-indigo-600 hover:bg-indigo-700 text-white font-black rounded-2xl flex items-center justify-center gap-3 shadow-xl shadow-indigo-100 active:scale-95 transition-all text-xs uppercase tracking-[0.25em]">
                            {isSubmitting ? (
                                <>
                                    <svg className="animate-spin h-5 w-5 text-white" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                                    Dispatching...
                                </>
                            ) : (
                                <>
                                    Dispatch Help Request
                                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path strokeLinecap="round" strokeLinejoin="round" d="M14 5l7 7m0 0l-7 7m7-7H3"></path></svg>
                                </>
                            )}
                        </button>
                    </form>
                </div>
            ) : selectedTicket ? (
                <TicketDetail ticket={selectedTicket} currentUser={currentUser} isAdmin={currentUser?.role === 'Admin'} onClose={() => setSelectedTicket(null)} onReply={handleReply} isSendingReply={isSendingReply} isLocked={isLocked} />
            ) : (
                <TicketList tickets={tickets} isLoading={isLoading} onRefresh={fetchTickets} onSelect={setSelectedTicket} isAdmin={false} filterStatus="ALL" />
            )}
        </div>
    );
};

