                                    `}>
                                        {u.role}
                                    </span>
                                </td>
                                <td className="md:px-10 md:py-6 block md:table-cell mb-6 md:mb-0">
                                    <div className="md:hidden text-[9px] font-normal text-slate-300 uppercase tracking-[0.2em] mb-2">Login Access</div>
                                    <div className="flex items-center gap-4">
